import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef,
  type ReactNode,
} from 'react'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface AccessibilityContextValue {
  /** User prefers reduced motion (OS-level setting). */
  reducedMotion: boolean
  /** System color scheme preference. */
  prefersColorScheme: 'light' | 'dark'
  /** User has high-contrast or increased-contrast enabled. */
  highContrast: boolean
  /** Push a message into the aria-live region for screen readers. */
  announceToScreenReader: (message: string, priority?: 'polite' | 'assertive') => void
}

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

const AccessibilityContext = createContext<AccessibilityContextValue | null>(null)

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Consume the accessibility context.
 * Must be used within an `<AccessibilityProvider>`.
 */
export function useAccessibility(): AccessibilityContextValue {
  const ctx = useContext(AccessibilityContext)
  if (!ctx) {
    throw new Error('useAccessibility must be used within an AccessibilityProvider')
  }
  return ctx
}

// ---------------------------------------------------------------------------
// Media query helper
// ---------------------------------------------------------------------------

function useMediaQuery(query: string, defaultValue: boolean = false): boolean {
  const [matches, setMatches] = useState<boolean>(() => {
    if (typeof window === 'undefined') return defaultValue
    return window.matchMedia(query).matches
  })

  useEffect(() => {
    if (typeof window === 'undefined') return

    const mql = window.matchMedia(query)
    const handler = (e: MediaQueryListEvent) => setMatches(e.matches)

    // Set initial value (in case SSR default was wrong)
    setMatches(mql.matches)

    mql.addEventListener('change', handler)
    return () => mql.removeEventListener('change', handler)
  }, [query])

  return matches
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

interface AccessibilityProviderProps {
  children: ReactNode
}

/**
 * Wraps the application with accessibility preferences derived from
 * OS-level media queries. Also renders a hidden aria-live region for
 * screen reader announcements.
 */
export function AccessibilityProvider({ children }: AccessibilityProviderProps) {
  const reducedMotion = useMediaQuery('(prefers-reduced-motion: reduce)')
  const prefersDark = useMediaQuery('(prefers-color-scheme: dark)', true)
  const highContrast = useMediaQuery('(prefers-contrast: more)')

  const prefersColorScheme: 'light' | 'dark' = prefersDark ? 'dark' : 'light'

  // Announcement refs — we keep two regions (polite + assertive)
  const politeRef = useRef<HTMLDivElement>(null)
  const assertiveRef = useRef<HTMLDivElement>(null)

  const announceToScreenReader = useCallback(
    (message: string, priority: 'polite' | 'assertive' = 'polite') => {
      const target = priority === 'assertive' ? assertiveRef.current : politeRef.current
      if (!target) return

      // Clear and re-set to force re-announcement in assistive tech
      target.textContent = ''
      requestAnimationFrame(() => {
        target.textContent = message
      })
    },
    []
  )

  const value: AccessibilityContextValue = {
    reducedMotion,
    prefersColorScheme,
    highContrast,
    announceToScreenReader,
  }

  // Visually-hidden styles (same pattern as existing accessibility.ts)
  const srOnlyStyle: React.CSSProperties = {
    position: 'absolute',
    width: '1px',
    height: '1px',
    margin: '-1px',
    padding: 0,
    overflow: 'hidden',
    clip: 'rect(0, 0, 0, 0)',
    whiteSpace: 'nowrap',
    border: 0,
  }

  return (
    <AccessibilityContext.Provider value={value}>
      {children}

      {/* Aria-live regions for screen reader announcements */}
      <div
        ref={politeRef}
        role="status"
        aria-live="polite"
        aria-atomic="true"
        style={srOnlyStyle}
      />
      <div
        ref={assertiveRef}
        role="alert"
        aria-live="assertive"
        aria-atomic="true"
        style={srOnlyStyle}
      />
    </AccessibilityContext.Provider>
  )
}

import { motion } from 'framer-motion'
import { Play, Pause, SpeakerSimpleHigh, SpeakerSimpleLow, SpeakerSimpleNone, SpeakerSimpleSlash } from '@phosphor-icons/react'
import type { VolumeLevel } from '@/lib/venue-storytelling'

interface AudioVibePreviewProps {
  genre: string
  ambiance: string
  volumeLevel: VolumeLevel
  isPlaying?: boolean
  onToggle?: () => void
}

const GENRE_COLORS: Record<string, string> = {
  'Electronic': 'oklch(0.65 0.28 340)',    // purple
  'House':      'oklch(0.65 0.28 340)',
  'Jazz':       'oklch(0.72 0.16 85)',      // warm gold
  'Classical':  'oklch(0.72 0.16 85)',
  'Rock':       'oklch(0.60 0.22 25)',      // red
  'Pop':        'oklch(0.70 0.20 350)',     // pink
  'Hip-Hop':    'oklch(0.60 0.22 25)',
  'Indie':      'oklch(0.60 0.15 150)',     // teal/green
  'Folk':       'oklch(0.65 0.14 100)',     // warm green
  'Lo-fi':      'oklch(0.55 0.12 260)',     // muted blue
  'Soul':       'oklch(0.65 0.18 50)',      // warm orange
  'Ambient':    'oklch(0.55 0.10 240)',     // cool blue
  'R&B':        'oklch(0.60 0.20 320)',     // magenta
}

function getGenreColor(genre: string): string {
  return GENRE_COLORS[genre] ?? 'oklch(0.60 0.15 240)'
}

const VOLUME_ICONS: Record<VolumeLevel, typeof SpeakerSimpleHigh> = {
  quiet: SpeakerSimpleNone,
  moderate: SpeakerSimpleLow,
  loud: SpeakerSimpleHigh,
  thumping: SpeakerSimpleHigh,
}

const VOLUME_LABELS: Record<VolumeLevel, string> = {
  quiet: 'Quiet',
  moderate: 'Moderate',
  loud: 'Loud',
  thumping: 'Thumping',
}

const BAR_COUNT = 16

function WaveformBars({ isPlaying, color }: { isPlaying: boolean; color: string }) {
  return (
    <div className="flex items-end gap-[2px] h-6">
      {Array.from({ length: BAR_COUNT }, (_, i) => {
        // Base heights vary to create a waveform shape
        const baseHeight = 0.3 + Math.sin((i / BAR_COUNT) * Math.PI) * 0.5
        const minH = 3
        const maxH = 22

        return (
          <motion.div
            key={i}
            className="w-[3px] rounded-full"
            style={{ backgroundColor: color }}
            animate={
              isPlaying
                ? {
                    height: [
                      minH + baseHeight * (maxH - minH),
                      minH + (baseHeight * 0.3 + 0.7 * Math.random()) * (maxH - minH),
                      minH + baseHeight * (maxH - minH),
                    ],
                    opacity: [0.6, 1, 0.6],
                  }
                : {
                    height: minH + baseHeight * 4,
                    opacity: 0.3,
                  }
            }
            transition={
              isPlaying
                ? {
                    duration: 0.4 + Math.random() * 0.4,
                    repeat: Infinity,
                    repeatType: 'mirror' as const,
                    ease: 'easeInOut',
                    delay: i * 0.04,
                  }
                : { duration: 0.5 }
            }
          />
        )
      })}
    </div>
  )
}

export function AudioVibePreview({
  genre,
  ambiance,
  volumeLevel,
  isPlaying = false,
  onToggle,
}: AudioVibePreviewProps) {
  const color = getGenreColor(genre)
  const VolumeIcon = VOLUME_ICONS[volumeLevel]

  return (
    <div className="flex items-center gap-3 rounded-xl border border-border/50 bg-card/60 backdrop-blur-sm p-3">
      {/* Play/pause button */}
      <motion.button
        type="button"
        className="shrink-0 w-9 h-9 rounded-full flex items-center justify-center"
        style={{ backgroundColor: `${color}20` }}
        whileHover={{ scale: 1.08 }}
        whileTap={{ scale: 0.92 }}
        onClick={onToggle}
        aria-label={isPlaying ? 'Pause' : 'Play'}
      >
        {isPlaying ? (
          <Pause size={16} weight="fill" style={{ color }} />
        ) : (
          <Play size={16} weight="fill" style={{ color }} />
        )}
      </motion.button>

      {/* Waveform + labels */}
      <div className="flex-1 min-w-0 flex flex-col gap-1.5">
        <div className="flex items-center gap-2">
          <span
            className="text-[11px] font-bold uppercase tracking-wide"
            style={{ color }}
          >
            {genre}
          </span>
          <span className="text-muted-foreground/40">·</span>
          <span className="inline-flex items-center gap-1 text-[10px] text-muted-foreground">
            <VolumeIcon size={10} weight="fill" />
            {VOLUME_LABELS[volumeLevel]}
          </span>
        </div>

        <WaveformBars isPlaying={isPlaying} color={color} />

        <p className="text-[10px] text-muted-foreground truncate">{ambiance}</p>
      </div>
    </div>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { Venue } from '@/lib/types'
import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { X, MapPin } from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'
import { cn } from '@/lib/utils'
import { getCityHeatmap, type HeatmapCell } from '@/lib/live-intelligence'

interface CityHeatmapProps {
  venues: Venue[]
  userLocation: { lat: number; lng: number } | null
  onVenueClick: (venue: Venue) => void
  visible: boolean
  onClose: () => void
}

function getHeatColor(intensity: number): string {
  if (intensity >= 80) return 'rgba(239, 68, 68, 0.6)' // red - electric
  if (intensity >= 60) return 'rgba(234, 179, 8, 0.5)' // yellow - buzzing
  if (intensity >= 40) return 'rgba(34, 197, 94, 0.4)' // green - chill
  if (intensity >= 20) return 'rgba(59, 130, 246, 0.3)' // blue - slow
  return 'rgba(30, 58, 138, 0.15)' // dark blue - dead
}

function getHeatLabel(intensity: number): string {
  if (intensity >= 80) return 'Electric'
  if (intensity >= 60) return 'Buzzing'
  if (intensity >= 40) return 'Chill'
  if (intensity >= 20) return 'Slow'
  return 'Dead'
}

export function CityHeatmap({ venues, userLocation, onVenueClick, visible, onClose }: CityHeatmapProps) {
  const [cells, setCells] = useState<HeatmapCell[]>([])
  const [selectedCell, setSelectedCell] = useState<HeatmapCell | null>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const containerRef = useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = useState({ width: 300, height: 300 })
  const refreshTimerRef = useRef<ReturnType<typeof setInterval> | null>(null)

  const radiusMiles = 5

  const refreshData = useCallback(() => {
    if (!userLocation || venues.length === 0) return
    const heatmapData = getCityHeatmap(userLocation, radiusMiles, venues)
    setCells(heatmapData)
  }, [userLocation, venues])

  useEffect(() => {
    if (!visible) return
    refreshData()

    // Auto-refresh every 30 seconds
    refreshTimerRef.current = setInterval(refreshData, 30000)
    return () => {
      if (refreshTimerRef.current) clearInterval(refreshTimerRef.current)
    }
  }, [visible, refreshData])

  useEffect(() => {
    if (containerRef.current) {
      const { width, height } = containerRef.current.getBoundingClientRect()
      setDimensions({ width, height: Math.min(height, width) })
    }
  }, [visible])

  // Render heatmap on canvas
  useEffect(() => {
    if (!canvasRef.current || cells.length === 0 || !userLocation) return
    const canvas = canvasRef.current
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    const dpr = window.devicePixelRatio || 1
    canvas.width = dimensions.width * dpr
    canvas.height = dimensions.height * dpr
    ctx.scale(dpr, dpr)

    // Background
    ctx.fillStyle = 'oklch(0.14 0.01 260)'
    ctx.fillRect(0, 0, dimensions.width, dimensions.height)

    const gridSize = 10
    const cellWidth = dimensions.width / gridSize
    const cellHeight = dimensions.height / gridSize

    // Draw heat cells
    for (let i = 0; i < cells.length; i++) {
      const row = Math.floor(i / gridSize)
      const col = i % gridSize
      const cell = cells[i]

      const x = col * cellWidth
      const y = row * cellHeight

      // Draw cell with gradient
      const gradient = ctx.createRadialGradient(
        x + cellWidth / 2, y + cellHeight / 2, 0,
        x + cellWidth / 2, y + cellHeight / 2, Math.max(cellWidth, cellHeight) * 0.8
      )
      gradient.addColorStop(0, getHeatColor(cell.intensity))
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)')

      ctx.fillStyle = gradient
      ctx.fillRect(x, y, cellWidth, cellHeight)

      // Draw cell border
      if (cell.intensity > 0) {
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)'
        ctx.lineWidth = 0.5
        ctx.strokeRect(x, y, cellWidth, cellHeight)
      }
    }

    // Draw user location marker
    const centerX = dimensions.width / 2
    const centerY = dimensions.height / 2
    ctx.beginPath()
    ctx.arc(centerX, centerY, 6, 0, Math.PI * 2)
    ctx.fillStyle = 'oklch(0.75 0.18 195)'
    ctx.fill()
    ctx.strokeStyle = 'white'
    ctx.lineWidth = 2
    ctx.stroke()
  }, [cells, dimensions, userLocation])

  const handleCanvasClick = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (cells.length === 0) return
    const canvas = canvasRef.current
    if (!canvas) return

    const rect = canvas.getBoundingClientRect()
    const x = e.clientX - rect.left
    const y = e.clientY - rect.top

    const gridSize = 10
    const cellWidth = dimensions.width / gridSize
    const cellHeight = dimensions.height / gridSize

    const col = Math.floor(x / cellWidth)
    const row = Math.floor(y / cellHeight)
    const idx = row * gridSize + col

    if (idx >= 0 && idx < cells.length && cells[idx].intensity > 0) {
      setSelectedCell(cells[idx])
    } else {
      setSelectedCell(null)
    }
  }

  if (!visible) return null

  const nearbyVenuesForCell = selectedCell?.topVenueId
    ? venues.filter(v => v.id === selectedCell.topVenueId)
    : []

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="absolute inset-0 z-30 bg-background/95 backdrop-blur-md flex flex-col"
        ref={containerRef}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4">
          <div>
            <h3 className="text-lg font-bold">City Energy Map</h3>
            <p className="text-xs text-muted-foreground font-mono">
              {radiusMiles} mi radius - Updates every 30s
            </p>
          </div>
          <Button size="icon" variant="ghost" onClick={onClose}>
            <X size={20} />
          </Button>
        </div>

        {/* Legend */}
        <div className="px-4 pb-3 flex items-center gap-3">
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: 'rgba(30, 58, 138, 0.6)' }} />
            <span className="text-[10px] text-muted-foreground">Dead</span>
          </div>
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: 'rgba(34, 197, 94, 0.6)' }} />
            <span className="text-[10px] text-muted-foreground">Chill</span>
          </div>
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: 'rgba(234, 179, 8, 0.6)' }} />
            <span className="text-[10px] text-muted-foreground">Buzzing</span>
          </div>
          <div className="flex items-center gap-1.5">
            <div className="w-3 h-3 rounded-sm" style={{ backgroundColor: 'rgba(239, 68, 68, 0.7)' }} />
            <span className="text-[10px] text-muted-foreground">Electric</span>
          </div>
        </div>

        {/* Heatmap Canvas */}
        <div className="flex-1 px-4 pb-4">
          <div className="relative w-full h-full rounded-xl overflow-hidden border border-border">
            {!userLocation ? (
              <div className="w-full h-full flex items-center justify-center">
                <p className="text-sm text-muted-foreground">Location needed for heatmap</p>
              </div>
            ) : (
              <>
                <canvas
                  ref={canvasRef}
                  className="w-full h-full cursor-pointer"
                  style={{ width: dimensions.width, height: dimensions.height }}
                  onClick={handleCanvasClick}
                />

                {/* Selected cell info */}
                <AnimatePresence>
                  {selectedCell && selectedCell.intensity > 0 && (
                    <motion.div
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: 10 }}
                      className="absolute bottom-4 left-4 right-4"
                    >
                      <Card className="bg-card/95 backdrop-blur-md border-border p-3">
                        <div className="flex items-center justify-between">
                          <div>
                            <p className="text-sm font-bold">{getHeatLabel(selectedCell.intensity)} Zone</p>
                            <p className="text-xs text-muted-foreground">
                              {selectedCell.venueCount} venue{selectedCell.venueCount !== 1 ? 's' : ''} nearby
                            </p>
                          </div>
                          <div
                            className="w-10 h-10 rounded-lg flex items-center justify-center text-lg font-bold"
                            style={{ backgroundColor: getHeatColor(selectedCell.intensity) }}
                          >
                            {selectedCell.intensity}
                          </div>
                        </div>
                        {nearbyVenuesForCell.length > 0 && (
                          <div className="mt-2 pt-2 border-t border-border">
                            {nearbyVenuesForCell.map(venue => (
                              <button
                                key={venue.id}
                                onClick={() => onVenueClick(venue)}
                                className="flex items-center gap-2 w-full text-left p-1 rounded hover:bg-secondary transition-colors"
                              >
                                <MapPin size={14} weight="fill" className="text-primary" />
                                <span className="text-sm font-medium">{venue.name}</span>
                                <span className="text-xs text-muted-foreground ml-auto">
                                  Score: {venue.pulseScore}
                                </span>
                              </button>
                            ))}
                          </div>
                        )}
                      </Card>
                    </motion.div>
                  )}
                </AnimatePresence>
              </>
            )}
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  )
}

import { useState } from 'react'
import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { ChartBar, Plus, Trophy, TrendUp, TrendDown, X, Lightning, Users, Fire } from '@phosphor-icons/react'
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, LineChart, Line } from 'recharts'
import { motion, AnimatePresence } from 'framer-motion'
import type { Venue, Pulse } from '@/lib/types'
import { getCompetitorBenchmark, type BenchmarkComparison, type CompetitorBenchmarkResult } from '@/lib/venue-platform'

interface CompetitorBenchmarkProps {
  venue: Venue
  venues: Venue[]
  pulses: Pulse[]
  competitorIds: string[]
  onAddCompetitor: (venueId: string) => void
  onRemoveCompetitor: (venueId: string) => void
}

export function CompetitorBenchmark({
  venue,
  venues,
  pulses,
  competitorIds,
  onAddCompetitor,
  onRemoveCompetitor,
}: CompetitorBenchmarkProps) {
  const [searchQuery, setSearchQuery] = useState('')

  const benchmark = getCompetitorBenchmark(venue.id, competitorIds, venues, pulses)
  const allResults = [benchmark.yourVenue, ...benchmark.competitors]

  const searchResults = searchQuery.length >= 2
    ? venues.filter(v =>
      v.id !== venue.id &&
      !competitorIds.includes(v.id) &&
      v.name.toLowerCase().includes(searchQuery.toLowerCase())
    ).slice(0, 5)
    : []

  const chartData = allResults.map(r => ({
    name: r.venueName.length > 12 ? r.venueName.slice(0, 12) + '...' : r.venueName,
    'Pulse Score': r.pulseScore,
    Visitors: r.visitorCount,
    'Avg Energy': Math.round(r.avgEnergy * 33.3),
    isYours: r.venueId === venue.id,
  }))

  const trendData = allResults.map(r => ({
    name: r.venueName.length > 12 ? r.venueName.slice(0, 12) + '...' : r.venueName,
    'Trending Days': r.trendingFrequency,
    'Peak Hour': r.peakHour,
  }))

  return (
    <div className="space-y-4">
      {/* Add Competitors */}
      <Card className="p-4 bg-card/80 border-border">
        <div className="flex items-center gap-2 mb-3">
          <ChartBar size={16} weight="fill" className="text-accent" />
          <h3 className="text-sm font-bold text-foreground">Competitor Tracking</h3>
          <Badge variant="outline" className="ml-auto text-[10px]">
            {competitorIds.length}/3
          </Badge>
        </div>

        {/* Current competitors */}
        <div className="flex flex-wrap gap-2 mb-3">
          {competitorIds.map(cId => {
            const v = venues.find(v => v.id === cId)
            return (
              <Badge
                key={cId}
                variant="secondary"
                className="flex items-center gap-1 pr-1"
              >
                <span className="text-xs">{v?.name ?? cId}</span>
                <button
                  onClick={() => onRemoveCompetitor(cId)}
                  className="ml-1 hover:text-destructive transition-colors"
                >
                  <X size={12} />
                </button>
              </Badge>
            )
          })}
        </div>

        {/* Search to add */}
        {competitorIds.length < 3 && (
          <div className="relative">
            <Input
              placeholder="Search venues to compare..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="h-8 text-xs bg-background"
            />
            <AnimatePresence>
              {searchResults.length > 0 && (
                <motion.div
                  initial={{ opacity: 0, y: -4 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -4 }}
                  className="absolute top-9 left-0 right-0 bg-card border border-border rounded-md shadow-lg z-10 overflow-hidden"
                >
                  {searchResults.map(v => (
                    <button
                      key={v.id}
                      onClick={() => {
                        onAddCompetitor(v.id)
                        setSearchQuery('')
                      }}
                      className="w-full px-3 py-2 text-left text-xs hover:bg-muted/50 flex items-center justify-between transition-colors"
                    >
                      <span className="text-foreground">{v.name}</span>
                      <Plus size={14} className="text-accent" />
                    </button>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}
      </Card>

      {/* Side-by-side Metrics */}
      {competitorIds.length > 0 && (
        <>
          <Card className="p-4 bg-card/80 border-border">
            <h3 className="text-sm font-bold text-foreground mb-3">Score Comparison</h3>
            <div className="h-48">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} margin={{ top: 5, right: 5, bottom: 5, left: -15 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }} />
                  <YAxis tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }} />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px',
                      fontSize: '11px',
                    }}
                  />
                  <Legend wrapperStyle={{ fontSize: '10px' }} />
                  <Bar dataKey="Pulse Score" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="Visitors" fill="oklch(0.70 0.22 60)" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="Avg Energy" fill="oklch(0.65 0.28 340)" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>

          {/* Trending Comparison */}
          <Card className="p-4 bg-card/80 border-border">
            <h3 className="text-sm font-bold text-foreground mb-3">Weekly Trends</h3>
            <div className="h-40">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={trendData} margin={{ top: 5, right: 5, bottom: 5, left: -15 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }} />
                  <YAxis tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }} />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px',
                      fontSize: '11px',
                    }}
                  />
                  <Bar dataKey="Trending Days" fill="oklch(0.60 0.15 150)" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>

          {/* Metric Cards */}
          <div className="space-y-2">
            {allResults.map(r => (
              <MetricRow key={r.venueId} result={r} isYours={r.venueId === venue.id} />
            ))}
          </div>

          {/* Insights */}
          {benchmark.insights.length > 0 && (
            <Card className="p-4 bg-card/80 border-border">
              <div className="flex items-center gap-2 mb-3">
                <Trophy size={16} weight="fill" className="text-yellow-400" />
                <h3 className="text-sm font-bold text-foreground">Insights</h3>
              </div>
              <div className="space-y-2">
                {benchmark.insights.slice(0, 6).map((insight, i) => {
                  const isWinning = insight.includes("You're beating")
                  return (
                    <div
                      key={i}
                      className={`flex items-start gap-2 text-xs ${isWinning ? 'text-green-400' : 'text-amber-400'}`}
                    >
                      {isWinning ? <TrendUp size={14} className="shrink-0 mt-0.5" /> : <TrendDown size={14} className="shrink-0 mt-0.5" />}
                      <span>{insight}</span>
                    </div>
                  )
                })}
              </div>
            </Card>
          )}
        </>
      )}

      {competitorIds.length === 0 && (
        <Card className="p-6 bg-card/80 border-border text-center">
          <ChartBar size={32} weight="thin" className="text-muted-foreground mx-auto mb-2" />
          <p className="text-sm text-muted-foreground">Add up to 3 competitor venues to compare metrics</p>
        </Card>
      )}
    </div>
  )
}

function MetricRow({ result, isYours }: { result: CompetitorBenchmarkResult; isYours: boolean }) {
  return (
    <Card className={`p-3 border-border ${isYours ? 'bg-primary/10 border-primary/30' : 'bg-card/80'}`}>
      <div className="flex items-center justify-between mb-2">
        <span className="text-xs font-bold text-foreground truncate flex-1">
          {result.venueName}
          {isYours && <Badge variant="outline" className="ml-2 text-[9px] text-accent border-accent/50">You</Badge>}
        </span>
      </div>
      <div className="grid grid-cols-4 gap-2 text-center">
        <div>
          <Fire size={12} className="text-orange-400 mx-auto mb-0.5" />
          <p className="text-xs font-bold text-foreground">{result.pulseScore}</p>
          <p className="text-[9px] text-muted-foreground">Score</p>
        </div>
        <div>
          <Users size={12} className="text-blue-400 mx-auto mb-0.5" />
          <p className="text-xs font-bold text-foreground">{result.visitorCount}</p>
          <p className="text-[9px] text-muted-foreground">Visitors</p>
        </div>
        <div>
          <Lightning size={12} className="text-yellow-400 mx-auto mb-0.5" />
          <p className="text-xs font-bold text-foreground">{result.avgEnergy.toFixed(1)}</p>
          <p className="text-[9px] text-muted-foreground">Energy</p>
        </div>
        <div>
          <TrendUp size={12} className="text-green-400 mx-auto mb-0.5" />
          <p className="text-xs font-bold text-foreground">{result.trendingFrequency}d</p>
          <p className="text-[9px] text-muted-foreground">Trending</p>
        </div>
      </div>
    </Card>
  )
}

import { useMemo, useState } from 'react'
import { User, Venue } from '@/lib/types'
import { Crew, CrewCheckIn, createCrew, getUserCrews, getActiveCrewCheckIns, initiateCrewCheckIn, confirmCrewCheckIn, buildCrewActivityFeed } from '@/lib/crew-mode'
import { CrewPanel } from '@/components/CrewPanel'
import { CaretLeft, UsersThree, Plus } from '@phosphor-icons/react'
import { motion } from 'framer-motion'
import { toast } from 'sonner'

interface CrewPageProps {
  currentUser: User
  allUsers: User[]
  crews: Crew[]
  crewCheckIns: CrewCheckIn[]
  venues: Venue[]
  onBack: () => void
  onCrewsUpdate: (crews: Crew[]) => void
  onCheckInsUpdate: (checkIns: CrewCheckIn[]) => void
}

export function CrewPage({
  currentUser,
  allUsers,
  crews,
  crewCheckIns,
  venues,
  onBack,
  onCrewsUpdate,
  onCheckInsUpdate
}: CrewPageProps) {
  const [showCreate, setShowCreate] = useState(false)
  const [crewName, setCrewName] = useState('')
  const [selectedMembers, setSelectedMembers] = useState<string[]>([])

  const userCrews = useMemo(
    () => getUserCrews(crews, currentUser.id),
    [crews, currentUser.id]
  )

  const handleCreateCrew = () => {
    if (!crewName.trim()) {
      toast.error('Enter a crew name')
      return
    }
    if (selectedMembers.length < 1) {
      toast.error('Select at least 1 friend')
      return
    }
    const result = createCrew(crewName, currentUser.id, selectedMembers)
    if ('error' in result) {
      toast.error(result.error)
      return
    }
    onCrewsUpdate([...crews, result])
    setShowCreate(false)
    setCrewName('')
    setSelectedMembers([])
    toast.success(`Crew "${crewName}" created!`)
  }

  const handleConfirmCheckIn = (checkInId: string, energyRating: 'dead' | 'chill' | 'buzzing' | 'electric') => {
    const updated = crewCheckIns.map(ci =>
      ci.id === checkInId ? confirmCrewCheckIn(ci, currentUser.id, energyRating) : ci
    )
    onCheckInsUpdate(updated)
    toast.success('Check-in confirmed!')
  }

  const friendUsers = allUsers.filter(u => currentUser.friends.includes(u.id))

  return (
    <div className="min-h-screen bg-background pb-20">
      <div className="sticky top-0 z-30 bg-background/80 backdrop-blur-lg border-b border-border">
        <div className="flex items-center gap-3 px-4 py-3 max-w-2xl mx-auto">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-muted rounded-lg">
            <CaretLeft size={24} />
          </button>
          <div className="flex items-center gap-2">
            <UsersThree size={24} weight="fill" className="text-primary" />
            <h1 className="text-xl font-bold">Crews</h1>
          </div>
          <button
            onClick={() => setShowCreate(!showCreate)}
            className="ml-auto p-2 hover:bg-muted rounded-lg"
          >
            <Plus size={20} weight="bold" />
          </button>
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-4 space-y-4">
        {/* Create Crew Form */}
        {showCreate && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            className="bg-card rounded-xl p-4 border border-primary/30 space-y-3"
          >
            <h3 className="font-bold">New Crew</h3>
            <input
              value={crewName}
              onChange={e => setCrewName(e.target.value)}
              placeholder="Crew name..."
              className="w-full px-3 py-2 bg-muted rounded-lg text-sm border border-border focus:outline-none focus:ring-2 focus:ring-primary"
            />
            <div className="space-y-2">
              <p className="text-sm text-muted-foreground">Select friends:</p>
              <div className="flex flex-wrap gap-2">
                {friendUsers.map(u => (
                  <button
                    key={u.id}
                    onClick={() => setSelectedMembers(prev =>
                      prev.includes(u.id) ? prev.filter(id => id !== u.id) : [...prev, u.id]
                    )}
                    className={`px-3 py-1.5 rounded-full text-sm transition-all ${
                      selectedMembers.includes(u.id)
                        ? 'bg-primary text-primary-foreground'
                        : 'bg-muted text-muted-foreground'
                    }`}
                  >
                    {u.username}
                  </button>
                ))}
              </div>
            </div>
            <button
              onClick={handleCreateCrew}
              className="w-full py-2 bg-primary text-primary-foreground rounded-lg font-medium text-sm"
            >
              Create Crew
            </button>
          </motion.div>
        )}

        {/* Crew List */}
        {userCrews.map((crew, i) => {
          const members = crew.memberIds.map(id => {
            const user = allUsers.find(u => u.id === id)
            return { id, username: user?.username || 'Unknown', profilePhoto: user?.profilePhoto }
          })
          const activeCheckIn = crewCheckIns.find(ci =>
            ci.crewId === crew.id && ci.status === 'active'
          )
          const venueNames: Record<string, string> = {}
          for (const v of venues) venueNames[v.id] = v.name
          const feed = buildCrewActivityFeed(crew, crewCheckIns, venueNames)

          return (
            <motion.div
              key={crew.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
            >
              <CrewPanel
                crew={crew}
                activeCheckIn={activeCheckIn}
                activityFeed={feed}
                members={members}
                currentUserId={currentUser.id}
                onConfirmCheckIn={(energyRating) => {
                  if (activeCheckIn) {
                    handleConfirmCheckIn(activeCheckIn.id, energyRating)
                  }
                }}
              />
            </motion.div>
          )
        })}

        {userCrews.length === 0 && !showCreate && (
          <div className="text-center py-12 space-y-3">
            <UsersThree size={48} className="mx-auto text-muted-foreground/50" />
            <p className="text-muted-foreground">No crews yet</p>
            <p className="text-sm text-muted-foreground/70">Create a crew with your friends to check in together</p>
            <button
              onClick={() => setShowCreate(true)}
              className="px-4 py-2 bg-primary text-primary-foreground rounded-lg font-medium text-sm"
            >
              Create Your First Crew
            </button>
          </div>
        )}
      </div>
    </div>
  )
}

import { Venue, Pulse, PulseWithUser, User } from '@/lib/types'
import { PulseStory, getActiveStories } from '@/lib/stories'
import { VenueEvent, getEventsSoon } from '@/lib/events'
import { getPeopleYouMayKnow } from '@/lib/social-graph'
import { StoryRing } from '@/components/StoryRing'
import { FriendSuggestions } from '@/components/FriendSuggestions'
import { EventCard } from '@/components/EventCard'
import { PredictiveSurgePanel } from '@/components/PredictiveSurgePanel'
import { Separator } from '@/components/ui/separator'
import { Compass, CalendarBlank, UsersThree, Trophy, ChartBar, MapTrifold, MusicNotes, GearSix, Lightning, Ticket, Sparkle } from '@phosphor-icons/react'
import { motion } from 'framer-motion'
import ForYouFeed from '@/components/ForYouFeed'
import MoodSelector from '@/components/MoodSelector'
import type { MoodType } from '@/lib/personalization-engine'
import { useState } from 'react'

interface DiscoverTabProps {
  venues: Venue[]
  pulses: Pulse[]
  pulsesWithUsers: PulseWithUser[]
  currentUser: User
  allUsers: User[]
  stories: PulseStory[]
  events: VenueEvent[]
  userLocation?: { lat: number; lng: number } | null
  onVenueClick: (venue: Venue) => void
  onStoryClick: (stories: PulseStory[], index: number) => void
  onAddFriend: (userId: string) => void
  onNavigate: (page: 'events' | 'crews' | 'achievements' | 'insights' | 'neighborhoods' | 'playlists' | 'settings' | 'integrations' | 'challenges' | 'my-tickets' | 'night-planner') => void
}

export function DiscoverTab({
  venues,
  pulses,
  pulsesWithUsers,
  currentUser,
  allUsers,
  stories,
  events,
  onVenueClick,
  onStoryClick,
  userLocation,
  onAddFriend,
  onNavigate
}: DiscoverTabProps) {
  const [selectedMood, setSelectedMood] = useState<MoodType | null>(null)
  const activeStories = getActiveStories(stories)
  const upcomingEvents = getEventsSoon(events, 12).slice(0, 3)
  const suggestions = getPeopleYouMayKnow(currentUser, allUsers, pulses).slice(0, 5)

  return (
    <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
      <div className="flex items-center gap-2">
        <Compass size={24} weight="fill" className="text-primary" />
        <h2 className="text-xl font-bold">Discover</h2>
      </div>

      {/* Stories */}
      {activeStories.length > 0 && (
        <>
          <StoryRing
            stories={activeStories}
            currentUserId={currentUser.id}
            onStoryClick={(userId) => {
              const userStories = activeStories.filter(s => s.userId === userId)
              onStoryClick(userStories, 0)
            }}
          />
          <Separator />
        </>
      )}

      {/* Predictive Surge */}
      <PredictiveSurgePanel
        venues={venues}
        pulses={pulses}
        onVenueClick={onVenueClick}
      />

      {/* Phase 4: Mood Selector */}
      <MoodSelector
        onMoodSelect={setSelectedMood}
        selectedMood={selectedMood}
      />

      {/* Phase 4: For You Feed */}
      <ForYouFeed
        venues={venues}
        user={currentUser}
        pulses={pulses}
        userLocation={userLocation ?? null}
        onVenueClick={onVenueClick}
      />

      <Separator />

      {/* Night Planner CTA */}
      <button
        onClick={() => onNavigate('night-planner')}
        className="w-full bg-gradient-to-r from-primary/10 to-purple-500/10 rounded-xl p-4 border border-primary/20 flex items-center gap-3 hover:border-primary/40 transition-colors"
      >
        <Sparkle size={24} weight="fill" className="text-primary" />
        <div className="flex-1 text-left">
          <p className="font-medium text-sm">Plan Your Night</p>
          <p className="text-xs text-muted-foreground">AI-powered multi-stop itinerary</p>
        </div>
      </button>

      {/* Quick Actions Grid */}
      <div className="grid grid-cols-2 gap-3">
        <QuickAction
          icon={<CalendarBlank size={24} weight="fill" />}
          label="Events"
          sublabel={upcomingEvents.length > 0 ? `${upcomingEvents.length} coming up` : 'Browse events'}
          color="from-blue-500/20 to-cyan-500/20"
          borderColor="border-blue-500/20"
          onClick={() => onNavigate('events')}
        />
        <QuickAction
          icon={<UsersThree size={24} weight="fill" />}
          label="Crews"
          sublabel="Group check-ins"
          color="from-green-500/20 to-emerald-500/20"
          borderColor="border-green-500/20"
          onClick={() => onNavigate('crews')}
        />
        <QuickAction
          icon={<Trophy size={24} weight="fill" />}
          label="Achievements"
          sublabel="Track your badges"
          color="from-yellow-500/20 to-orange-500/20"
          borderColor="border-yellow-500/20"
          onClick={() => onNavigate('achievements')}
        />
        <QuickAction
          icon={<ChartBar size={24} weight="fill" />}
          label="Insights"
          sublabel="Your weekly recap"
          color="from-purple-500/20 to-pink-500/20"
          borderColor="border-purple-500/20"
          onClick={() => onNavigate('insights')}
        />
        <QuickAction
          icon={<MusicNotes size={24} weight="fill" />}
          label="Playlists"
          sublabel="Curated pulse boards"
          color="from-rose-500/20 to-red-500/20"
          borderColor="border-rose-500/20"
          onClick={() => onNavigate('playlists')}
        />
        <QuickAction
          icon={<Lightning size={24} weight="fill" />}
          label="Challenges"
          sublabel="Earn rewards"
          color="from-amber-500/20 to-yellow-500/20"
          borderColor="border-amber-500/20"
          onClick={() => onNavigate('challenges')}
        />
        <QuickAction
          icon={<Ticket size={24} weight="fill" />}
          label="My Tickets"
          sublabel="Tickets & reservations"
          color="from-indigo-500/20 to-violet-500/20"
          borderColor="border-indigo-500/20"
          onClick={() => onNavigate('my-tickets')}
        />
        <QuickAction
          icon={<GearSix size={24} weight="fill" />}
          label="Settings"
          sublabel="Language, privacy & more"
          color="from-gray-500/20 to-slate-500/20"
          borderColor="border-gray-500/20"
          onClick={() => onNavigate('settings')}
        />
      </div>

      {/* Neighborhood button */}
      <button
        onClick={() => onNavigate('neighborhoods')}
        className="w-full bg-gradient-to-r from-primary/10 to-accent/10 rounded-xl p-4 border border-primary/20 flex items-center gap-3 hover:border-primary/40 transition-colors"
      >
        <MapTrifold size={24} weight="fill" className="text-primary" />
        <div className="flex-1 text-left">
          <p className="font-medium text-sm">Neighborhood Scores</p>
          <p className="text-xs text-muted-foreground">See which areas are hottest right now</p>
        </div>
      </button>

      {/* Upcoming Events Preview */}
      {upcomingEvents.length > 0 && (
        <>
          <Separator />
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <h3 className="font-bold">Happening Soon</h3>
              <button onClick={() => onNavigate('events')} className="text-xs text-primary font-medium">
                See All
              </button>
            </div>
            {upcomingEvents.map(event => {
              const venue = venues.find(v => v.id === event.venueId)
              return (
                <EventCard
                  key={event.id}
                  event={event}
                  venueName={venue?.name || 'Unknown'}
                  currentUserId={currentUser.id}
                  onRSVP={() => {}}
                />
              )
            })}
          </div>
        </>
      )}

      {/* Friend Suggestions */}
      {suggestions.length > 0 && (
        <>
          <Separator />
          <div className="space-y-3">
            <h3 className="font-bold">People You May Know</h3>
            <FriendSuggestions
              suggestions={suggestions}
              onAddFriend={onAddFriend}
            />
          </div>
        </>
      )}
    </div>
  )
}

function QuickAction({
  icon,
  label,
  sublabel,
  color,
  borderColor,
  onClick
}: {
  icon: React.ReactNode
  label: string
  sublabel: string
  color: string
  borderColor: string
  onClick: () => void
}) {
  return (
    <motion.button
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      className={`bg-gradient-to-br ${color} rounded-xl p-4 border ${borderColor} text-left`}
    >
      <div className="text-foreground mb-2">{icon}</div>
      <p className="font-medium text-sm">{label}</p>
      <p className="text-xs text-muted-foreground">{sublabel}</p>
    </motion.button>
  )
}

import { useCallback, useRef } from 'react'
import { TrendUp, MapTrifold, User, Bell, Compass } from '@phosphor-icons/react'
import { motion, useAnimation, type Variants } from 'framer-motion'
import { cn } from '@/lib/utils'
import type { Icon as PhosphorIcon } from '@phosphor-icons/react'

export type TabId = 'trending' | 'discover' | 'map' | 'notifications' | 'profile'

interface EnhancedBottomNavProps {
  activeTab: TabId
  onTabChange: (tab: TabId) => void
  unreadNotifications?: number
}

interface TabConfig {
  id: TabId
  icon: PhosphorIcon
  label: string
  badge?: number
}

const iconBounceVariants: Variants = {
  tap: {
    scale: [0.85, 1.15, 1.0],
    transition: {
      type: 'spring',
      stiffness: 500,
      damping: 15,
      times: [0, 0.6, 1],
      duration: 0.4,
    },
  },
  idle: {
    scale: 1,
  },
}

const glowDotVariants: Variants = {
  initial: { scale: 0, opacity: 0 },
  animate: {
    scale: 1,
    opacity: 1,
    transition: {
      type: 'spring',
      stiffness: 400,
      damping: 20,
    },
  },
  exit: {
    scale: 0,
    opacity: 0,
    transition: { duration: 0.15 },
  },
}

const badgePulseVariants: Variants = {
  animate: {
    boxShadow: [
      '0 0 0 0 rgba(239, 68, 68, 0.7)',
      '0 0 0 6px rgba(239, 68, 68, 0)',
    ],
    transition: {
      duration: 1.5,
      repeat: Infinity,
      ease: 'easeOut',
    },
  },
}

function triggerHaptic() {
  if (typeof navigator !== 'undefined' && 'vibrate' in navigator) {
    try {
      navigator.vibrate(10)
    } catch {
      // Silently ignore if vibration fails
    }
  }
}

function TabButton({
  tab,
  isActive,
  onPress,
}: {
  tab: TabConfig
  isActive: boolean
  onPress: () => void
}) {
  const controls = useAnimation()
  const Icon = tab.icon
  const isMap = tab.id === 'map'

  const handlePress = useCallback(() => {
    triggerHaptic()
    controls.start('tap').then(() => controls.start('idle'))
    onPress()
  }, [controls, onPress])

  return (
    <button
      onClick={handlePress}
      className="flex flex-col items-center justify-center flex-1 h-full relative"
      aria-label={tab.label}
      aria-current={isActive ? 'page' : undefined}
    >
      <div className="relative z-10 flex flex-col items-center gap-1">
        {/* Icon container with bounce + scale + optional rotation */}
        <motion.div
          className="relative"
          variants={iconBounceVariants}
          animate={controls}
          initial="idle"
        >
          <motion.div
            animate={{
              scale: isActive ? 1.1 : 1,
              rotate: isMap && isActive ? 12 : 0,
            }}
            transition={{
              type: 'spring',
              stiffness: 350,
              damping: 20,
            }}
          >
            <Icon
              size={24}
              weight={isActive ? 'fill' : 'regular'}
              className={cn(
                'transition-colors duration-200',
                isActive ? 'text-primary' : 'text-muted-foreground'
              )}
            />
          </motion.div>

          {/* Notification badge with pulse glow */}
          {tab.badge !== undefined && tab.badge > 0 && (
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              className="absolute -top-1.5 -right-2"
            >
              <motion.div
                variants={badgePulseVariants}
                animate="animate"
                className="w-4 h-4 bg-red-500 text-white rounded-full flex items-center justify-center text-[10px] font-bold"
              >
                {tab.badge > 9 ? '9+' : tab.badge}
              </motion.div>
            </motion.div>
          )}
        </motion.div>

        {/* Label */}
        <span
          className={cn(
            'text-[10px] font-medium transition-colors duration-200',
            isActive ? 'text-primary' : 'text-muted-foreground'
          )}
        >
          {tab.label}
        </span>

        {/* Glowing dot indicator */}
        {isActive && (
          <motion.div
            variants={glowDotVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            className="absolute -bottom-1 w-1 h-1 rounded-full bg-primary"
            style={{
              boxShadow: 'hsl(var(--primary)) 0px 0px 6px 1px',
            }}
          />
        )}
      </div>
    </button>
  )
}

export function EnhancedBottomNav({
  activeTab,
  onTabChange,
  unreadNotifications = 0,
}: EnhancedBottomNavProps) {
  const tabs: TabConfig[] = [
    { id: 'trending', icon: TrendUp, label: 'Trending' },
    { id: 'discover', icon: Compass, label: 'Discover' },
    { id: 'map', icon: MapTrifold, label: 'Map' },
    {
      id: 'notifications',
      icon: Bell,
      label: 'Alerts',
      badge: unreadNotifications,
    },
    { id: 'profile', icon: User, label: 'Profile' },
  ]

  return (
    <nav
      className={cn(
