// ForYouFeed
// ---------------------------------------------------------------------------

export default function ForYouFeed({
  venues,
  user,
  pulses,
  userLocation,
  onVenueClick,
}: ForYouFeedProps) {
  const [isRefreshing, setIsRefreshing] = useState(false)

  const scoredVenues = useMemo<ScoredVenue[]>(
    () =>
      getPersonalizedVenues({
        user,
        venues,
        pulses,
        userLocation,
        currentTime: new Date(),
      }),
    [user, venues, pulses, userLocation],
  )

  const handleRefresh = useCallback(() => {
    setIsRefreshing(true)
    // Simulate refresh delay
    setTimeout(() => setIsRefreshing(false), 800)
  }, [])

  if (scoredVenues.length === 0) {
    return <EmptyState />
  }

  const [featured, ...rest] = scoredVenues

  return (
    <div className="flex flex-col gap-3">
      {/* Pull to refresh indicator */}
      <AnimatePresence>
        {isRefreshing && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 40, opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="flex items-center justify-center"
          >
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ repeat: Infinity, duration: 0.8, ease: 'linear' }}
            >
              <ArrowDown weight="bold" className="size-5 text-fuchsia-400" />
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Header */}
      <div className="flex items-center justify-between px-1">
        <div>
          <h2 className="text-lg font-bold text-white">For You</h2>
          <p className="text-xs text-zinc-500">
            {scoredVenues.length} venues curated for you
          </p>
        </div>
        <button
          type="button"
          onClick={handleRefresh}
          className="text-xs text-fuchsia-400 hover:text-fuchsia-300 transition-colors"
        >
          Refresh
        </button>
      </div>

      {/* Venue list */}
      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
        className="flex flex-col gap-3"
      >
        {/* Featured card */}
        <VenueCard
          scored={featured}
          featured
          onVenueClick={onVenueClick}
        />

        {/* Remaining cards */}
        {rest.map((sv) => (
          <VenueCard
            key={sv.venue.id}
            scored={sv}
            onVenueClick={onVenueClick}
          />
        ))}
      </motion.div>
    </div>
  )
}

"use client"

import { useState, useMemo } from "react"
import { motion } from "framer-motion"
import { Lock } from "@phosphor-icons/react"

interface Friend {
  id: string
  username: string
  avatar: string
  lat: number
  lng: number
  venueId?: string
  venueName?: string
  visibility?: "everyone" | "friends" | "limited"
}

interface FriendMapDotsProps {
  friends: Friend[]
  latLngToPixel: (lat: number, lng: number) => { x: number; y: number }
  zoom: number
}

interface Cluster {
  friends: Friend[]
  x: number
  y: number
}

const DOT_SIZE = 28
const CLUSTER_DISTANCE = 36

function getEnergyBorderColor(venueId?: string): string {
  // Provide a visual cue if the friend is at a venue
  if (venueId) return "#f59e0b" // amber for checked-in
  return "#6b7280" // gray for roaming
}

function clusterFriends(
  friends: Friend[],
  latLngToPixel: (lat: number, lng: number) => { x: number; y: number }
): Cluster[] {
  const positions = friends.map((f) => ({
    friend: f,
    pixel: latLngToPixel(f.lat, f.lng),
  }))

  const used = new Set<number>()
  const clusters: Cluster[] = []

  for (let i = 0; i < positions.length; i++) {
    if (used.has(i)) continue

    const cluster: Friend[] = [positions[i].friend]
    let cx = positions[i].pixel.x
    let cy = positions[i].pixel.y
    used.add(i)

    for (let j = i + 1; j < positions.length; j++) {
      if (used.has(j)) continue
      const dx = positions[j].pixel.x - cx
      const dy = positions[j].pixel.y - cy
      const dist = Math.sqrt(dx * dx + dy * dy)

      if (dist < CLUSTER_DISTANCE) {
        cluster.push(positions[j].friend)
        used.add(j)
        // Recalculate center
        cx = (cx * (cluster.length - 1) + positions[j].pixel.x) / cluster.length
        cy = (cy * (cluster.length - 1) + positions[j].pixel.y) / cluster.length
      }
    }

    clusters.push({ friends: cluster, x: cx, y: cy })
  }

  return clusters
}

export default function FriendMapDots({
  friends,
  latLngToPixel,
  zoom,
}: FriendMapDotsProps) {
  const [hoveredId, setHoveredId] = useState<string | null>(null)

  const clusters = useMemo(
    () => clusterFriends(friends, latLngToPixel),
    [friends, latLngToPixel, zoom]
  )

  return (
    <g className="friend-map-dots">
      {clusters.map((cluster) => {
        const primary = cluster.friends[0]
        const isCluster = cluster.friends.length > 1
        const isHovered = cluster.friends.some((f) => f.id === hoveredId)

        return (
          <g key={primary.id} transform={`translate(${cluster.x}, ${cluster.y})`}>
            {/* Breathing animation wrapper */}
            <motion.g
              animate={{
                scale: [0.95, 1.05, 0.95],
              }}
              transition={{
                duration: 3,
                repeat: Infinity,
                ease: "easeInOut",
              }}
            >
              {/* Avatar circle */}
              <clipPath id={`clip-${primary.id}`}>
                <circle cx={0} cy={0} r={DOT_SIZE / 2 - 2} />
              </clipPath>

              {/* Border circle */}
              <circle
                cx={0}
                cy={0}
                r={DOT_SIZE / 2}
                fill={getEnergyBorderColor(primary.venueId)}
                stroke="white"
                strokeWidth={1.5}
              />

              {/* Avatar image */}
              <image
                href={primary.avatar}
                x={-(DOT_SIZE / 2 - 2)}
                y={-(DOT_SIZE / 2 - 2)}
                width={DOT_SIZE - 4}
                height={DOT_SIZE - 4}
                clipPath={`url(#clip-${primary.id})`}
                style={{ pointerEvents: "none" }}
              />

              {/* Privacy indicator */}
              {primary.visibility === "limited" && (
                <g transform={`translate(${DOT_SIZE / 2 - 4}, ${-(DOT_SIZE / 2 - 4)})`}>
                  <circle cx={0} cy={0} r={6} fill="#1f2937" />
                  <foreignObject x={-5} y={-5} width={10} height={10}>
                    <Lock size={10} weight="fill" color="white" />
                  </foreignObject>
                </g>
              )}

              {/* Cluster badge */}
              {isCluster && (
                <g transform={`translate(${DOT_SIZE / 2 - 2}, ${DOT_SIZE / 2 - 2})`}>
                  <circle cx={0} cy={0} r={9} fill="#6366f1" stroke="white" strokeWidth={1} />
                  <text
                    x={0}
                    y={0}
                    textAnchor="middle"
                    dominantBaseline="central"
                    fill="white"
                    fontSize={10}
                    fontWeight="bold"
                  >
                    +{cluster.friends.length - 1}
                  </text>
                </g>
              )}
            </motion.g>

            {/* Hover/tap target (invisible, larger area) */}
            <circle
              cx={0}
              cy={0}
              r={DOT_SIZE / 2 + 6}
              fill="transparent"
              style={{ cursor: "pointer" }}
              onMouseEnter={() => setHoveredId(primary.id)}
              onMouseLeave={() => setHoveredId(null)}
              onTouchStart={() => setHoveredId(primary.id)}
              onTouchEnd={() => setHoveredId(null)}
            />

            {/* Tooltip */}
            {isHovered && (
              <g transform={`translate(0, ${-(DOT_SIZE / 2 + 12)})`}>
                <rect
                  x={-60}
                  y={-24}
                  width={120}
                  height={isCluster ? 20 + cluster.friends.length * 16 : 28}
                  rx={6}
                  fill="rgba(0,0,0,0.85)"
                  stroke="rgba(255,255,255,0.15)"
                  strokeWidth={0.5}
                />
                {isCluster ? (
                  cluster.friends.map((friend, i) => (
                    <text
                      key={friend.id}
                      x={0}
                      y={-10 + i * 16}
                      textAnchor="middle"
                      fill="white"
                      fontSize={11}
                    >
                      {friend.username}
                      {friend.venueName ? ` at ${friend.venueName}` : ""}
                    </text>
                  ))
                ) : (
                  <text
                    x={0}
                    y={-8}
                    textAnchor="middle"
                    fill="white"
                    fontSize={11}
                  >
                    {primary.username}
                    {primary.venueName ? ` at ${primary.venueName}` : ""}
                  </text>
                )}
              </g>
            )}
          </g>
        )
      })}
    </g>
  )
}

import { useState, useEffect, useRef, useMemo, useCallback } from 'react'
import { motion, AnimatePresence, type Variants } from 'framer-motion'
import {
  MagnifyingGlass,
  X,
  Clock,
  TrendUp,
  MapPin,
  Buildings,
} from '@phosphor-icons/react'
import { Venue } from '@/lib/types'
import { cn } from '@/lib/utils'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface GlobalSearchProps {
  open: boolean
  onClose: () => void
  venues: Venue[]
  onSelectVenue: (venueId: string) => void
  onSelectCity: (cityKey: string) => void
}

interface SearchResult {
  id: string
  type: 'venue' | 'city' | 'category'
  label: string
  sublabel?: string
  venueId?: string
  cityKey?: string
  /** Indices of matched characters inside `label` (for highlighting). */
  matchRanges: [number, number][]
}

type ResultSection = {
  key: string
  title: string
  icon: React.ReactNode
  results: SearchResult[]
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Lightweight fuzzy matcher.  Returns match ranges (start, end) inside `text`
 * for every contiguous run of characters that matches `query`.  The algorithm
 * works case-insensitively and greedily finds the best contiguous substrings.
 */
function fuzzyMatch(
  text: string,
  query: string,
): { score: number; ranges: [number, number][] } | null {
  const lowerText = text.toLowerCase()
  const lowerQuery = query.toLowerCase()

  // Fast-path: exact substring
  const idx = lowerText.indexOf(lowerQuery)
  if (idx !== -1) {
    return { score: 100 - idx, ranges: [[idx, idx + lowerQuery.length]] }
  }

  // Character-by-character fuzzy walk
  let qi = 0
  let score = 0
  const ranges: [number, number][] = []
  let runStart = -1

  for (let ti = 0; ti < lowerText.length && qi < lowerQuery.length; ti++) {
    if (lowerText[ti] === lowerQuery[qi]) {
      if (runStart === -1) runStart = ti
      qi++
      score += 1
      // Bonus for consecutive
      if (ranges.length > 0 && ranges[ranges.length - 1][1] === ti) {
        score += 2
      }
    } else if (runStart !== -1) {
      ranges.push([runStart, ti])
      runStart = -1
    }
  }

  if (qi < lowerQuery.length) return null // not all chars matched

  // Close last run
  if (runStart !== -1) {
    const lastMatchIdx =
      ranges.length > 0 ? ranges[ranges.length - 1][1] : runStart
    // Walk forward to find actual end of last run
    let end = runStart
    for (let ti = runStart; ti < lowerText.length; ti++) {
      if (ti - runStart < lowerQuery.length - (qi - (lowerQuery.length - (lowerQuery.length - qi)))) break
      end = ti + 1
      break
    }
    // Simpler: just push the run from runStart to current qi position
    // We know the last character matched ended at (the last ti that matched)
    // Recompute: find last ti matched
    let lastTi = 0
    let tmpQi = 0
    for (let ti = 0; ti < lowerText.length && tmpQi < lowerQuery.length; ti++) {
      if (lowerText[ti] === lowerQuery[tmpQi]) {
        lastTi = ti
        tmpQi++
      }
    }
    ranges.push([runStart, lastTi + 1])
  }

  // Merge overlapping ranges
  const merged: [number, number][] = []
  for (const r of ranges) {
    if (merged.length > 0 && r[0] <= merged[merged.length - 1][1]) {
      merged[merged.length - 1][1] = Math.max(merged[merged.length - 1][1], r[1])
    } else {
      merged.push([...r])
    }
  }

  return { score, ranges: merged }
}

/** Deduplicate an array by a key function. */
function uniqueBy<T>(arr: T[], keyFn: (item: T) => string): T[] {
  const seen = new Set<string>()
  return arr.filter((item) => {
    const k = keyFn(item)
    if (seen.has(k)) return false
    seen.add(k)
    return true
  })
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const MAX_RECENT = 5
const DEBOUNCE_MS = 150
const TRENDING_COUNT = 6

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

function HighlightedText({
  text,
  ranges,
}: {
  text: string
  ranges: [number, number][]
}) {
  if (ranges.length === 0) return <>{text}</>

  const parts: React.ReactNode[] = []
  let cursor = 0

  for (const [start, end] of ranges) {
    if (start > cursor) {
      parts.push(
        <span key={`t-${cursor}`}>{text.slice(cursor, start)}</span>,
      )
    }
    parts.push(
      <span
        key={`h-${start}`}
        className="text-accent font-bold"
      >
        {text.slice(start, end)}
      </span>,
    )
    cursor = end
  }

  if (cursor < text.length) {
    parts.push(<span key={`t-${cursor}`}>{text.slice(cursor)}</span>)
  }

  return <>{parts}</>
}

// ---------------------------------------------------------------------------
// Motion variants
// ---------------------------------------------------------------------------

const overlayVariants: Variants = {
  hidden: { opacity: 0, y: '-8%' },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.25, ease: [0.22, 1, 0.36, 1] },
  },
  exit: {
    opacity: 0,
    y: '-8%',
    transition: { duration: 0.2, ease: [0.22, 1, 0.36, 1] },
  },
}

const sectionVariants: Variants = {
  hidden: { opacity: 0, x: -24 },
  visible: (i: number) => ({
    opacity: 1,
    x: 0,
    transition: { delay: i * 0.06, duration: 0.3, ease: 'easeOut' },
  }),
}

const itemVariants: Variants = {
  hidden: { opacity: 0, y: 6 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: { delay: i * 0.03, duration: 0.2, ease: 'easeOut' },
  }),
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------

export function GlobalSearch({
  open,
  onClose,
  venues,
  onSelectVenue,
  onSelectCity,
}: GlobalSearchProps) {
  const [query, setQuery] = useState('')
  const [debouncedQuery, setDebouncedQuery] = useState('')
  const [recentSearches, setRecentSearches] = useState<
    { label: string; type: 'venue' | 'city' | 'category'; id: string }[]
  >([])
  const [activeIndex, setActiveIndex] = useState(-1)

  const inputRef = useRef<HTMLInputElement>(null)
  const listRef = useRef<HTMLDivElement>(null)

  // ---- Debounce ----
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedQuery(query), DEBOUNCE_MS)
    return () => clearTimeout(timer)
  }, [query])

  // ---- Focus input on open ----
  useEffect(() => {
    if (open) {
      // Small delay to let the animation start so the element is mounted
      const raf = requestAnimationFrame(() => inputRef.current?.focus())
      return () => cancelAnimationFrame(raf)
    }
    // Reset state on close
    setQuery('')
    setDebouncedQuery('')
    setActiveIndex(-1)
  }, [open])

  // ---- Trending venues (top by pulse score) ----
  const trendingVenues = useMemo(
    () =>
      [...venues]
        .sort((a, b) => b.pulseScore - a.pulseScore)
        .slice(0, TRENDING_COUNT),
    [venues],
  )

  // ---- Search logic ----
  const sections: ResultSection[] = useMemo(() => {
    const q = debouncedQuery.trim()
    if (!q) return []

    // --- Venues ---
    const venueResults: (SearchResult & { _score: number })[] = []
    for (const v of venues) {
      const nameMatch = fuzzyMatch(v.name, q)
      const catMatch = v.category ? fuzzyMatch(v.category, q) : null
      const cityMatch = v.city ? fuzzyMatch(v.city, q) : null

      const best = [nameMatch, catMatch, cityMatch]
        .filter(Boolean)
        .sort((a, b) => b!.score - a!.score)[0]

      if (best) {
        // Determine which field matched best for highlighting
        const matchedName = nameMatch && nameMatch.score === best.score
        venueResults.push({
          id: `venue-${v.id}`,
          type: 'venue',
          label: v.name,
          sublabel: [v.category, v.city].filter(Boolean).join(' \u00B7 '),
          venueId: v.id,
          matchRanges: matchedName ? best.ranges : [],
          _score: best.score + v.pulseScore * 0.1,
        })
      }
    }
    venueResults.sort((a, b) => b._score - a._score)

    // --- Cities ---
    const cityMap = new Map<string, { count: number; match: ReturnType<typeof fuzzyMatch> }>()
    for (const v of venues) {
      if (!v.city) continue
      const m = fuzzyMatch(v.city, q)
      if (!m) continue
      const existing = cityMap.get(v.city)
      if (!existing || m.score > existing.match!.score) {
        cityMap.set(v.city, {
          count: (existing?.count ?? 0) + 1,
          match: m,
        })
      } else {
        cityMap.set(v.city, { ...existing, count: existing.count + 1 })
      }
    }
    const cityResults: SearchResult[] = [...cityMap.entries()]
      .sort((a, b) => b[1].match!.score - a[1].match!.score)
      .slice(0, 8)
      .map(([city, data]) => ({
        id: `city-${city}`,
        type: 'city' as const,
        label: city,
        sublabel: `${data.count} venue${data.count !== 1 ? 's' : ''}`,
        cityKey: city,
        matchRanges: data.match!.ranges,
      }))

    // --- Categories ---
    const catMap = new Map<string, { count: number; match: ReturnType<typeof fuzzyMatch> }>()
    for (const v of venues) {
      if (!v.category) continue
      const m = fuzzyMatch(v.category, q)
      if (!m) continue
      const existing = catMap.get(v.category)
      if (!existing || m.score > existing.match!.score) {
        catMap.set(v.category, {
          count: (existing?.count ?? 0) + 1,
          match: m,
        })
      } else {
        catMap.set(v.category, { ...existing, count: existing.count + 1 })
      }
    }
    const catResults: SearchResult[] = [...catMap.entries()]
      .sort((a, b) => b[1].match!.score - a[1].match!.score)
      .slice(0, 6)
      .map(([cat, data]) => ({
        id: `cat-${cat}`,
        type: 'category' as const,
        label: cat,
        sublabel: `${data.count} venue${data.count !== 1 ? 's' : ''}`,
        matchRanges: data.match!.ranges,
      }))

    const result: ResultSection[] = []

    if (venueResults.length > 0) {
      result.push({
        key: 'venues',
        title: 'Venues',
        icon: <MapPin size={16} weight="fill" className="text-accent" />,
        results: venueResults.slice(0, 10),
      })
    }

    if (cityResults.length > 0) {
      result.push({
        key: 'cities',
        title: 'Cities',
        icon: <Buildings size={16} weight="fill" className="text-accent" />,
        results: cityResults,
      })
    }

    if (catResults.length > 0) {
      result.push({
        key: 'categories',
        title: 'Categories',
        icon: <TrendUp size={16} weight="fill" className="text-accent" />,
        results: catResults,
      })
    }

    return result
  }, [debouncedQuery, venues])

  // Flat list of all results for keyboard navigation
  const flatResults = useMemo(
    () => sections.flatMap((s) => s.results),
    [sections],
  )

  // Reset active index when results change
  useEffect(() => {
    setActiveIndex(-1)
  }, [debouncedQuery])

  // ---- Scroll active item into view ----
  useEffect(() => {
    if (activeIndex < 0 || !listRef.current) return
    const el = listRef.current.querySelector(`[data-result-index="${activeIndex}"]`)
    el?.scrollIntoView({ block: 'nearest', behavior: 'smooth' })
  }, [activeIndex])

  // ---- Handlers ----
  const addRecent = useCallback(
    (label: string, type: 'venue' | 'city' | 'category', id: string) => {
      setRecentSearches((prev) => {
        const next = [{ label, type, id }, ...prev.filter((r) => r.id !== id)]
        return next.slice(0, MAX_RECENT)
      })
    },
    [],
  )

  const handleSelect = useCallback(
    (result: SearchResult) => {
      addRecent(result.label, result.type, result.id)

      if (result.type === 'venue' && result.venueId) {
        onSelectVenue(result.venueId)
      } else if (result.type === 'city' && result.cityKey) {
        onSelectCity(result.cityKey)
      } else if (result.type === 'category') {
        // For categories, select the top venue in that category
        const firstMatch = venues.find(
          (v) => v.category?.toLowerCase() === result.label.toLowerCase(),
        )
        if (firstMatch) onSelectVenue(firstMatch.id)
      }

      onClose()
    },
    [addRecent, onClose, onSelectVenue, onSelectCity, venues],
  )

  const handleTrendingSelect = useCallback(
    (venue: Venue) => {
      addRecent(venue.name, 'venue', `venue-${venue.id}`)
      onSelectVenue(venue.id)
      onClose()
    },
    [addRecent, onSelectVenue, onClose],
  )

  const handleRecentSelect = useCallback(
    (recent: { label: string; type: 'venue' | 'city' | 'category'; id: string }) => {
      if (recent.type === 'venue') {
        const venueId = recent.id.replace('venue-', '')
        onSelectVenue(venueId)
      } else if (recent.type === 'city') {
        const cityKey = recent.id.replace('city-', '')
        onSelectCity(cityKey)
      }
      onClose()
    },
    [onSelectVenue, onSelectCity, onClose],
  )

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      const hasResults = flatResults.length > 0

      switch (e.key) {
        case 'ArrowDown': {
          e.preventDefault()
          if (hasResults) {
            setActiveIndex((prev) =>
              prev < flatResults.length - 1 ? prev + 1 : 0,
            )
          }
          break
        }
        case 'ArrowUp': {
          e.preventDefault()
          if (hasResults) {
            setActiveIndex((prev) =>
              prev > 0 ? prev - 1 : flatResults.length - 1,
            )
          }
          break
        }
        case 'Enter': {
          e.preventDefault()
          if (activeIndex >= 0 && flatResults[activeIndex]) {
            handleSelect(flatResults[activeIndex])
          }
          break
        }
        case 'Escape': {
          e.preventDefault()
          onClose()
          break
        }
      }
    },
    [flatResults, activeIndex, handleSelect, onClose],
  )

  const showEmpty = debouncedQuery.trim().length === 0
  const showNoResults =
    debouncedQuery.trim().length > 0 && sections.length === 0

  // Track the global index offset for each result
  let globalIndex = 0

  return (
    <AnimatePresence>
      {open && (
        <motion.div
          className="fixed inset-0 z-50 flex flex-col"
          variants={overlayVariants}
          initial="hidden"
          animate="visible"
          exit="exit"
        >
          {/* Backdrop */}
          <div
            className="absolute inset-0 bg-background/95 backdrop-blur-xl"
            onClick={onClose}
          />

          {/* Content */}
          <div className="relative z-10 flex flex-col w-full max-w-2xl mx-auto h-full">
            {/* Search header */}
            <div className="flex-shrink-0 px-4 pt-safe-top">
              <div className="flex items-center gap-3 py-4">
                <motion.div
                  className="relative flex-1"
                  initial={{ scaleX: 0.85, opacity: 0 }}
                  animate={{ scaleX: 1, opacity: 1 }}
                  transition={{ duration: 0.3, ease: [0.22, 1, 0.36, 1] }}
                  style={{ transformOrigin: 'left center' }}
                >
                  <MagnifyingGlass
                    size={22}
                    weight="bold"
                    className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground pointer-events-none"
                  />
                  <input
                    ref={inputRef}
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder="Search venues, cities, categories..."
                    autoComplete="off"
                    autoCorrect="off"
                    spellCheck={false}
                    className={cn(
                      'w-full h-13 pl-12 pr-12 rounded-2xl',
                      'bg-card/80 border border-border',
                      'text-foreground placeholder:text-muted-foreground',
                      'text-base font-medium',
                      'outline-none transition-all duration-200',
                      'focus:ring-2 focus:ring-accent/50 focus:border-accent/40',
                      'backdrop-blur-sm',
                    )}
                  />
                  {query && (
                    <button
                      onClick={() => {
                        setQuery('')
                        inputRef.current?.focus()
                      }}
                      className="absolute right-3 top-1/2 -translate-y-1/2 p-1.5 rounded-full bg-muted/60 hover:bg-muted transition-colors"
                    >
                      <X size={14} weight="bold" className="text-muted-foreground" />
                    </button>
                  )}
                </motion.div>

                <motion.button
                  onClick={onClose}
                  className="flex-shrink-0 px-3 py-2 text-sm font-semibold text-accent hover:text-accent/80 transition-colors"
                  initial={{ opacity: 0, x: 12 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1, duration: 0.2 }}
                >
                  Cancel
                </motion.button>
              </div>
            </div>

            {/* Scrollable results area */}
            <div
              ref={listRef}
              className="flex-1 overflow-y-auto px-4 pb-8 overscroll-contain"
            >
              {/* ---- Empty state: recent + trending ---- */}
              {showEmpty && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.1, duration: 0.25 }}
                >
                  {/* Recent searches */}
                  {recentSearches.length > 0 && (
                    <motion.div
                      className="mb-6"
                      variants={sectionVariants}
                      initial="hidden"
                      animate="visible"
                      custom={0}
                    >
                      <div className="flex items-center gap-2 mb-3">
                        <Clock
                          size={16}
                          weight="fill"
                          className="text-muted-foreground"
                        />
                        <h3 className="text-xs font-bold uppercase tracking-widest text-muted-foreground">
                          Recent Searches
                        </h3>
                      </div>
                      <div className="space-y-1">
                        {recentSearches.map((recent, i) => (
                          <motion.button
                            key={recent.id}
                            variants={itemVariants}
                            initial="hidden"
                            animate="visible"
                            custom={i}
                            onClick={() => handleRecentSelect(recent)}
                            className={cn(
                              'w-full flex items-center gap-3 px-3 py-2.5 rounded-xl',
                              'text-left transition-colors',
                              'hover:bg-card/80',
                            )}
                          >
                            <Clock
                              size={18}
                              weight="regular"
                              className="text-muted-foreground flex-shrink-0"
                            />
                            <span className="text-sm font-medium text-foreground truncate">
                              {recent.label}
                            </span>
                            <span className="text-xs text-muted-foreground capitalize ml-auto flex-shrink-0">
                              {recent.type}
                            </span>
                          </motion.button>
                        ))}
                      </div>
                    </motion.div>
                  )}

                  {/* Trending */}
                  <motion.div
                    variants={sectionVariants}
                    initial="hidden"
                    animate="visible"
                    custom={recentSearches.length > 0 ? 1 : 0}
                  >
                    <div className="flex items-center gap-2 mb-3">
                      <TrendUp
                        size={16}
                        weight="fill"
                        className="text-accent"
                      />
                      <h3 className="text-xs font-bold uppercase tracking-widest text-muted-foreground">
                        Trending Now
                      </h3>
                    </div>
                    <div className="space-y-1">
                      {trendingVenues.map((venue, i) => (
                        <motion.button
                          key={venue.id}
                          variants={itemVariants}
                          initial="hidden"
                          animate="visible"
                          custom={i}
                          onClick={() => handleTrendingSelect(venue)}
                          className={cn(
                            'w-full flex items-center gap-3 px-3 py-2.5 rounded-xl',
                            'text-left transition-colors',
                            'hover:bg-card/80',
                          )}
                        >
                          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-primary/20 to-accent/20 flex items-center justify-center flex-shrink-0">
                            <TrendUp
                              size={16}
                              weight="fill"
                              className="text-accent"
                            />
                          </div>
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-semibold text-foreground truncate">
                              {venue.name}
                            </p>
                            <p className="text-xs text-muted-foreground truncate">
                              {[venue.category, venue.city]
                                .filter(Boolean)
                                .join(' \u00B7 ')}
                            </p>
                          </div>
                          <div className="flex-shrink-0 text-xs font-bold text-accent tabular-nums">
                            {venue.pulseScore}
                          </div>
                        </motion.button>
                      ))}
                    </div>
                  </motion.div>
                </motion.div>
              )}

              {/* ---- Search results ---- */}
              {!showEmpty && sections.length > 0 && (
                <div className="space-y-5">
                  {sections.map((section, sectionIdx) => {
                    const sectionStartIndex = globalIndex
                    const sectionElement = (
                      <motion.div
                        key={section.key}
                        variants={sectionVariants}
                        initial="hidden"
                        animate="visible"
                        custom={sectionIdx}
                      >
                        <div className="flex items-center gap-2 mb-2">
                          {section.icon}
                          <h3 className="text-xs font-bold uppercase tracking-widest text-muted-foreground">
                            {section.title}
                          </h3>
                          <span className="text-xs text-muted-foreground/60 ml-1">
                            {section.results.length}
                          </span>
                        </div>
                        <div className="space-y-0.5">
                          {section.results.map((result, i) => {
                            const resultGlobalIndex = sectionStartIndex + i
                            const isActive = resultGlobalIndex === activeIndex

                            return (
                              <motion.button
                                key={result.id}
                                data-result-index={resultGlobalIndex}
                                variants={itemVariants}
                                initial="hidden"
                                animate="visible"
                                custom={i}
                                onClick={() => handleSelect(result)}
                                onMouseEnter={() =>
                                  setActiveIndex(resultGlobalIndex)
                                }
                                className={cn(
                                  'w-full flex items-center gap-3 px-3 py-2.5 rounded-xl',
                                  'text-left transition-colors duration-100',
                                  isActive
                                    ? 'bg-accent/10 ring-1 ring-accent/20'
                                    : 'hover:bg-card/80',
                                )}
                              >
                                <div
                                  className={cn(
                                    'w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0',
                                    result.type === 'venue' &&
                                      'bg-gradient-to-br from-primary/20 to-accent/20',
                                    result.type === 'city' &&
                                      'bg-gradient-to-br from-blue-500/20 to-cyan-500/20',
                                    result.type === 'category' &&
                                      'bg-gradient-to-br from-purple-500/20 to-pink-500/20',
                                  )}
                                >
                                  {result.type === 'venue' && (
                                    <MapPin
                                      size={16}
                                      weight="fill"
                                      className="text-accent"
                                    />
                                  )}
                                  {result.type === 'city' && (
                                    <Buildings
                                      size={16}
                                      weight="fill"
                                      className="text-blue-400"
                                    />
                                  )}
                                  {result.type === 'category' && (
                                    <TrendUp
                                      size={16}
                                      weight="fill"
                                      className="text-purple-400"
                                    />
                                  )}
                                </div>
                                <div className="flex-1 min-w-0">
                                  <p className="text-sm font-semibold text-foreground truncate">
                                    <HighlightedText
                                      text={result.label}
                                      ranges={result.matchRanges}
                                    />
                                  </p>
                                  {result.sublabel && (
                                    <p className="text-xs text-muted-foreground truncate">
                                      {result.sublabel}
                                    </p>
                                  )}
                                </div>
                                {result.type === 'venue' && (
                                  <div className="flex-shrink-0">
                                    <span className="text-xs text-muted-foreground font-mono">
                                      Venue
                                    </span>
                                  </div>
                                )}
                              </motion.button>
                            )
                          })}
                        </div>
                      </motion.div>
                    )

                    globalIndex += section.results.length
                    return sectionElement
                  })}
                </div>
              )}

              {/* ---- No results ---- */}
              {showNoResults && (
                <motion.div
                  className="flex flex-col items-center justify-center py-16 text-center"
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ duration: 0.25 }}
                >
                  <div className="w-16 h-16 rounded-2xl bg-card/80 flex items-center justify-center mb-4">
                    <MagnifyingGlass
                      size={32}
                      weight="duotone"
                      className="text-muted-foreground"
                    />
                  </div>
                  <p className="text-base font-semibold text-foreground mb-1">
                    No results for &ldquo;{debouncedQuery}&rdquo;
                  </p>
                  <p className="text-sm text-muted-foreground max-w-xs">
                    Try a different spelling, or search for a city or category
                    like &ldquo;rooftop&rdquo; or &ldquo;Brooklyn&rdquo;
                  </p>
                </motion.div>
              )}
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

import { useState, useMemo } from 'react'
import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import {
  Users, MagnifyingGlass, Star, UserCircle, CalendarBlank,
  CurrencyDollar, Tag, NotePencil, X, CaretDown, CaretUp,
  Crown, Warning, UserPlus, Heart,
} from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'
import type { Pulse } from '@/lib/types'
import {
  buildGuestProfiles,
  getRegulars,
  getVIPGuests,
  getChurningGuests,
  getNewGuests,
  addGuestTag,
  addGuestNote,
  type GuestProfile,
} from '@/lib/venue-platform'

interface GuestCRMProps {
  venueId: string
  pulses: Pulse[]
  users: { id: string; username: string }[]
}

type GuestSegment = 'all' | 'vip' | 'regular' | 'new' | 'at_risk'

const SEGMENT_CONFIG: Record<GuestSegment, { label: string; color: string; icon: typeof Users }> = {
  all: { label: 'All', color: 'text-foreground', icon: Users },
  vip: { label: 'VIP', color: 'text-yellow-400', icon: Crown },
  regular: { label: 'Regular', color: 'text-blue-400', icon: Heart },
  new: { label: 'New', color: 'text-green-400', icon: UserPlus },
  at_risk: { label: 'At Risk', color: 'text-red-400', icon: Warning },
}

export function GuestCRM({ venueId, pulses, users }: GuestCRMProps) {
  const [search, setSearch] = useState('')
  const [activeSegment, setActiveSegment] = useState<GuestSegment>('all')
  const [selectedGuest, setSelectedGuest] = useState<GuestProfile | null>(null)
  const [guestProfiles, setGuestProfiles] = useState<GuestProfile[]>(() =>
    buildGuestProfiles(venueId, pulses, users)
  )
  const [newTag, setNewTag] = useState('')
  const [editingNotes, setEditingNotes] = useState(false)
  const [noteText, setNoteText] = useState('')

  const segments = useMemo(() => {
    const vips = getVIPGuests(guestProfiles)
    const regulars = getRegulars(guestProfiles)
    const newGuests = getNewGuests(guestProfiles)
    const atRisk = getChurningGuests(guestProfiles, 30)
    return {
      all: guestProfiles,
      vip: vips,
      regular: regulars,
      new: newGuests,
      at_risk: atRisk,
    }
  }, [guestProfiles])

  const filteredGuests = useMemo(() => {
    let list = segments[activeSegment]
    if (search) {
      const q = search.toLowerCase()
      list = list.filter(g =>
        g.username.toLowerCase().includes(q) ||
        g.tags.some(t => t.toLowerCase().includes(q))
      )
    }
    return list
  }, [segments, activeSegment, search])

  const handleAddTag = (guest: GuestProfile) => {
    if (!newTag.trim()) return
    const updated = addGuestTag(guest, newTag.trim())
    setGuestProfiles(prev =>
      prev.map(g => g.userId === guest.userId ? updated : g)
    )
    setSelectedGuest(updated)
    setNewTag('')
  }

  const handleSaveNote = (guest: GuestProfile) => {
    const updated = addGuestNote(guest, noteText)
    setGuestProfiles(prev =>
      prev.map(g => g.userId === guest.userId ? updated : g)
    )
    setSelectedGuest(updated)
    setEditingNotes(false)
  }

  const formatDate = (dateStr: string) => {
    if (!dateStr) return 'N/A'
    const d = new Date(dateStr)
    return `${d.getMonth() + 1}/${d.getDate()}/${d.getFullYear()}`
  }

  const formatCurrency = (amount: number) => `$${amount.toLocaleString()}`

  // Guest detail modal
  if (selectedGuest) {
    return (
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="space-y-4"
      >
        <button
          onClick={() => { setSelectedGuest(null); setEditingNotes(false) }}
          className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
        >
          <CaretDown size={12} className="rotate-90" />
          Back to guests
        </button>

        {/* Guest Header */}
        <Card className="p-4 bg-card/80 border-border">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-12 h-12 rounded-full bg-primary/20 flex items-center justify-center">
              <UserCircle size={28} className="text-primary" />
            </div>
            <div className="flex-1">
              <h3 className="text-sm font-bold text-foreground">{selectedGuest.username}</h3>
              <div className="flex items-center gap-2 mt-0.5">
                {selectedGuest.isVIP && (
                  <Badge className="bg-yellow-500/20 text-yellow-400 text-[9px]">VIP</Badge>
                )}
                <span className="text-[10px] text-muted-foreground">
                  {selectedGuest.visits.length} visits
                </span>
              </div>
            </div>
          </div>

          {/* Key Metrics */}
          <div className="grid grid-cols-3 gap-2">
            <div className="text-center p-2 bg-background/50 rounded-md">
              <CurrencyDollar size={14} className="text-green-400 mx-auto mb-0.5" />
              <p className="text-sm font-bold text-foreground">{formatCurrency(selectedGuest.totalSpend)}</p>
              <p className="text-[9px] text-muted-foreground">Total Spend</p>
            </div>
            <div className="text-center p-2 bg-background/50 rounded-md">
              <CurrencyDollar size={14} className="text-blue-400 mx-auto mb-0.5" />
              <p className="text-sm font-bold text-foreground">{formatCurrency(selectedGuest.averageSpend)}</p>
              <p className="text-[9px] text-muted-foreground">Avg Spend</p>
            </div>
            <div className="text-center p-2 bg-background/50 rounded-md">
              <CalendarBlank size={14} className="text-accent mx-auto mb-0.5" />
              <p className="text-sm font-bold text-foreground">{selectedGuest.visits.length}</p>
              <p className="text-[9px] text-muted-foreground">Visits</p>
            </div>
          </div>
        </Card>

        {/* Visit Details */}
        <Card className="p-4 bg-card/80 border-border">
          <h4 className="text-xs font-bold text-foreground mb-2">Visit Info</h4>
          <div className="space-y-1.5 text-xs">
            <div className="flex justify-between">
              <span className="text-muted-foreground">First Visit</span>
              <span className="text-foreground">{formatDate(selectedGuest.firstVisit)}</span>
            </div>
            <div className="flex justify-between">
              <span className="text-muted-foreground">Last Visit</span>
              <span className="text-foreground">{formatDate(selectedGuest.lastVisit)}</span>
            </div>
            <div className="flex justify-between">
              <span className="text-muted-foreground">Favorite Nights</span>
              <span className="text-foreground">{selectedGuest.favoriteNights.join(', ') || 'N/A'}</span>
            </div>
          </div>
        </Card>

        {/* Tags */}
        <Card className="p-4 bg-card/80 border-border">
          <div className="flex items-center gap-2 mb-2">
            <Tag size={14} className="text-accent" />
            <h4 className="text-xs font-bold text-foreground">Tags</h4>
          </div>
          <div className="flex flex-wrap gap-1.5 mb-2">
            {selectedGuest.tags.map(tag => (
              <Badge key={tag} variant="secondary" className="text-[10px]">{tag}</Badge>
            ))}
          </div>
          <div className="flex gap-2">
            <Input
              placeholder="Add tag..."
              value={newTag}
              onChange={(e) => setNewTag(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAddTag(selectedGuest)}
              className="h-7 text-xs bg-background flex-1"
            />
            <button
              onClick={() => handleAddTag(selectedGuest)}
              className="text-xs text-accent hover:underline shrink-0"
            >
              Add
            </button>
          </div>
        </Card>

        {/* Notes */}
        <Card className="p-4 bg-card/80 border-border">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2">
              <NotePencil size={14} className="text-accent" />
              <h4 className="text-xs font-bold text-foreground">Notes</h4>
            </div>
            {!editingNotes && (
              <button
                onClick={() => { setEditingNotes(true); setNoteText(selectedGuest.notes) }}
                className="text-[10px] text-accent hover:underline"
              >
                Edit
              </button>
            )}
          </div>
          {editingNotes ? (
            <div className="space-y-2">
              <textarea
                value={noteText}
                onChange={(e) => setNoteText(e.target.value)}
                className="w-full h-20 p-2 text-xs bg-background border border-border rounded-md resize-none text-foreground focus:outline-none focus:ring-1 focus:ring-primary"
                placeholder="Add notes about this guest..."
              />
              <div className="flex gap-2 justify-end">
                <button
                  onClick={() => setEditingNotes(false)}
                  className="text-xs text-muted-foreground hover:text-foreground"
                >
                  Cancel
                </button>
                <button
                  onClick={() => handleSaveNote(selectedGuest)}
                  className="text-xs text-accent hover:underline"
                >
                  Save
                </button>
              </div>
            </div>
          ) : (
            <p className="text-xs text-muted-foreground">
              {selectedGuest.notes || 'No notes yet'}
            </p>
          )}
        </Card>

        {/* Recent Visits */}
        <Card className="p-4 bg-card/80 border-border">
          <h4 className="text-xs font-bold text-foreground mb-2">Recent Visits</h4>
          <div className="space-y-1">
            {selectedGuest.visits.slice(-10).reverse().map((visit, i) => (
              <div key={i} className="flex items-center justify-between text-xs py-1 border-b border-border/50 last:border-0">
                <span className="text-muted-foreground">{formatDate(visit.date)}</span>
                <Badge variant="outline" className="text-[9px]">{visit.energyRating}</Badge>
              </div>
            ))}
          </div>
        </Card>
      </motion.div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Segment Tabs */}
      <div className="flex gap-1.5 overflow-x-auto pb-1">
        {(Object.entries(SEGMENT_CONFIG) as [GuestSegment, typeof SEGMENT_CONFIG['all']][]).map(([key, config]) => {
          const Icon = config.icon
          const count = segments[key].length
          return (
            <button
              key={key}
              onClick={() => setActiveSegment(key)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors shrink-0 ${
                activeSegment === key
                  ? 'bg-primary text-primary-foreground'
                  : 'bg-muted/50 text-muted-foreground hover:bg-muted'
              }`}
            >
              <Icon size={12} />
              {config.label}
              <span className={`${activeSegment === key ? 'text-primary-foreground/70' : 'text-muted-foreground/50'}`}>
                {count}
              </span>
            </button>
          )
        })}
      </div>

      {/* Search */}
      <div className="relative">
        <MagnifyingGlass size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground" />
        <Input
          placeholder="Search guests or tags..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="h-8 text-xs bg-card pl-8"
        />
      </div>

      {/* Guest List */}
      <div className="space-y-2">
        <AnimatePresence mode="popLayout">
          {filteredGuests.map((guest, i) => (
            <motion.div
              key={guest.userId}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              transition={{ delay: i * 0.03 }}
            >
              <Card
                className="p-3 bg-card/80 border-border hover:border-primary/30 transition-colors cursor-pointer"
                onClick={() => setSelectedGuest(guest)}
              >
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-full bg-primary/20 flex items-center justify-center shrink-0">
                    <UserCircle size={22} className="text-primary" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-bold text-foreground truncate">{guest.username}</span>
                      {guest.isVIP && (
                        <Crown size={12} className="text-yellow-400 shrink-0" />
                      )}
                    </div>
                    <div className="flex items-center gap-2 mt-0.5">
                      <span className="text-[10px] text-muted-foreground">{guest.visits.length} visits</span>
                      <span className="text-[10px] text-muted-foreground">{formatCurrency(guest.totalSpend)} spent</span>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <p className="text-[10px] text-muted-foreground">Last visit</p>
                    <p className="text-xs text-foreground">{formatDate(guest.lastVisit)}</p>
                  </div>
                </div>
                {guest.tags.length > 0 && (
                  <div className="flex flex-wrap gap-1 mt-2">
                    {guest.tags.map(tag => (
                      <Badge key={tag} variant="outline" className="text-[9px] px-1.5 py-0">{tag}</Badge>
                    ))}
                  </div>
                )}
              </Card>
            </motion.div>
          ))}
        </AnimatePresence>

        {filteredGuests.length === 0 && (
          <Card className="p-6 bg-card/80 border-border text-center">
            <Users size={32} weight="thin" className="text-muted-foreground mx-auto mb-2" />
            <p className="text-sm text-muted-foreground">
              {search ? 'No guests match your search' : 'No guests in this segment yet'}
            </p>
          </Card>
        )}
      </div>
    </div>
  )
}

import { useEffect, useRef, useState, useMemo } from 'react'
import { Venue } from '@/lib/types'
import { PulseScore } from '@/components/PulseScore'
import { MapFilters, MapFiltersState } from '@/components/MapFilters'
import { MapSearch } from '@/components/MapSearch'
import { GPSIndicator } from '@/components/GPSIndicator'
import {
  MapPin, NavigationArrow, Plus, Minus, CaretDown, CaretUp,
  BeerBottle, MusicNotes, ForkKnife, Coffee, Martini, Confetti,
  Users, Fire, Lightning
} from '@phosphor-icons/react'
import { Button } from '@/components/ui/button'
import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'
import { motion, AnimatePresence } from 'framer-motion'
import { formatDistance } from '@/lib/units'
import { useUnitPreference } from '@/hooks/use-unit-preference'
import { triggerHapticFeedback } from '@/lib/haptics'
import {
  buildVenueRenderPoints,
  clampCenter,
  clampZoom,
  clusterVenueRenderPoints,
  getFittedViewport,
  getHeadingDelta,
  getPreviewVenuePoints,
  type VenueRenderPoint
} from '@/lib/interactive-map'

interface InteractiveMapProps {
  venues: Venue[]
  userLocation: { lat: number; lng: number } | null
  onVenueClick: (venue: Venue) => void
  isTracking?: boolean
  locationAccuracy?: number
  locationHeading?: number | null
}

const ZOOM_STEP = 1.35
const MAP_SCALE = 500000

export function InteractiveMap({
  venues,
  userLocation,
  onVenueClick,
  isTracking = false,
  locationAccuracy,
  locationHeading
}: InteractiveMapProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 })
  const [zoom, setZoom] = useState(1)
  const [center, setCenter] = useState<{ lat: number; lng: number } | null>(null)
  const [hoveredVenue, setHoveredVenue] = useState<Venue | null>(null)
  const [isDragging, setIsDragging] = useState(false)
  const [dragStart, setDragStart] = useState<{ x: number; y: number } | null>(null)
  const [followUser, setFollowUser] = useState(true)
  const containerRef = useRef<HTMLDivElement>(null)
  const offscreenCanvasRef = useRef<HTMLCanvasElement | null>(null) // Optimization: Reuse canvas
  const [filters, setFilters] = useState<MapFiltersState>({
    energyLevels: [],
    categories: [],
    maxDistance: Infinity
  })
  const [nearMeActive, setNearMeActive] = useState(false)
  const [showLegend, setShowLegend] = useState(false)
  const [showFullHeatmap, setShowFullHeatmap] = useState(false)
  const [comparedVenueIds, setComparedVenueIds] = useState<string[]>([])
  const [showOnboardingTips, setShowOnboardingTips] = useState(false)
  const [tipIndex, setTipIndex] = useState(0)
  const [lastTouchDistance, setLastTouchDistance] = useState<number | null>(null)
  const [expandedClusterId, setExpandedClusterId] = useState<string | null>(null)
  const [accessibilityMode, setAccessibilityMode] = useState(false)
  const [isCameraMoving, setIsCameraMoving] = useState(false)
  const onboardingStorageKey = 'pulse-map-onboarding-v1'
  const { unitSystem } = useUnitPreference()
  const loadingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const cameraSettleTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const venueSelectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const hoverClearTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const inertialFrameRef = useRef<number | null>(null)
  const panVelocityRef = useRef({ lat: 0, lng: 0 })
  const lastPanFrameRef = useRef<{ x: number; y: number; ts: number } | null>(null)
  const lastTapRef = useRef<{ x: number; y: number; ts: number } | null>(null)
  const movedDuringTouchRef = useRef(false)

  const stopInertia = () => {
    if (inertialFrameRef.current !== null) {
      cancelAnimationFrame(inertialFrameRef.current)
      inertialFrameRef.current = null
    }
    panVelocityRef.current = { lat: 0, lng: 0 }
  }

  useEffect(() => {
    return () => {
      if (inertialFrameRef.current !== null) {
        cancelAnimationFrame(inertialFrameRef.current)
        inertialFrameRef.current = null
      }
      panVelocityRef.current = { lat: 0, lng: 0 }
      if (cameraSettleTimeoutRef.current) clearTimeout(cameraSettleTimeoutRef.current)
      if (venueSelectTimeoutRef.current) clearTimeout(venueSelectTimeoutRef.current)
      if (hoverClearTimeoutRef.current) clearTimeout(hoverClearTimeoutRef.current)
    }
  }, [])

  useEffect(() => {
    // If no location after 3s, default to first venue or SF
    loadingTimeoutRef.current = window.setTimeout(() => {
      if (!center && !userLocation && venues.length > 0) {
        setCenter({ lat: venues[0].location.lat, lng: venues[0].location.lng })
        setFollowUser(false)
      }
    }, 3000)

    return () => {
      if (loadingTimeoutRef.current) clearTimeout(loadingTimeoutRef.current)
    }
  }, [center, userLocation, venues])

  useEffect(() => {
    if (userLocation && followUser) {
      setCenter(userLocation)
      if (loadingTimeoutRef.current) clearTimeout(loadingTimeoutRef.current)
    }
  }, [userLocation, followUser])

  useEffect(() => {
    if (userLocation && !center) {
      setCenter(userLocation)
    }
  }, [userLocation, center])

  useEffect(() => {
    if (typeof window === 'undefined') return
    const seen = window.localStorage.getItem(onboardingStorageKey)
    if (!seen) {
      setShowOnboardingTips(true)
      setTipIndex(0)
    }
  }, [onboardingStorageKey])

  useEffect(() => {
    setIsCameraMoving(true)
    if (cameraSettleTimeoutRef.current) clearTimeout(cameraSettleTimeoutRef.current)
    cameraSettleTimeoutRef.current = window.setTimeout(() => {
      setIsCameraMoving(false)
    }, isDragging ? 260 : 140)
  }, [center, zoom, isDragging])

  const calculateDistance = (
    lat1: number,
    lon1: number,
    lat2: number,
    lon2: number
  ): number => {
    const R = 3958.8
    const φ1 = (lat1 * Math.PI) / 180
    const φ2 = (lat2 * Math.PI) / 180
    const Δφ = ((lat2 - lat1) * Math.PI) / 180
    const Δλ = ((lon2 - lon1) * Math.PI) / 180

    const a =
      Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
      Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2)
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

    return R * c
  }

  const calculateBearing = (
    lat1: number,
    lon1: number,
    lat2: number,
    lon2: number
  ): number => {
    const φ1 = (lat1 * Math.PI) / 180
    const φ2 = (lat2 * Math.PI) / 180
    const λ1 = (lon1 * Math.PI) / 180
    const λ2 = (lon2 * Math.PI) / 180

    const y = Math.sin(λ2 - λ1) * Math.cos(φ2)
    const x = Math.cos(φ1) * Math.sin(φ2) - Math.sin(φ1) * Math.cos(φ2) * Math.cos(λ2 - λ1)
    const θ = Math.atan2(y, x)
    return ((θ * 180) / Math.PI + 360) % 360
  }

  const getEnergyLevelFromScore = (score: number): string => {
    if (score >= 80) return 'electric'
    if (score >= 60) return 'buzzing'
    if (score >= 30) return 'chill'
    return 'dead'
  }

  const getCategoryIcon = (category?: string) => {
    switch (category?.toLowerCase()) {
      case 'bar': return BeerBottle
      case 'club': return MusicNotes
      case 'nightclub': return MusicNotes
      case 'restaurant': return ForkKnife
      case 'food': return ForkKnife
      case 'cafe': return Coffee
      case 'lounge': return Martini
      case 'event': return Confetti
      default: return MapPin
    }
  }

  const getEnergyColor = (score: number) => {
    if (score >= 80) return 'oklch(0.65 0.28 320)'
    if (score >= 60) return 'oklch(0.65 0.25 25)'
    if (score >= 30) return 'oklch(0.65 0.18 240)'
    return 'oklch(0.40 0.05 260)'
  }

  const filteredVenues = useMemo(() => {
    const filtered = venues.filter((venue) => {
      if (filters.energyLevels.length > 0) {
        const energyLevel = getEnergyLevelFromScore(venue.pulseScore)
        if (!filters.energyLevels.includes(energyLevel as any)) {
          return false
        }
      }

      if (filters.categories.length > 0 && venue.category) {
        if (!filters.categories.includes(venue.category)) {
          return false
        }
      }

      if (filters.maxDistance !== Infinity && userLocation) {
        const distance = calculateDistance(
          userLocation.lat,
          userLocation.lng,
          venue.location.lat,
          venue.location.lng
        )
        if (distance > filters.maxDistance) {
          return false
        }
      }
      // Near Me filter (0.5 mile radius)
      if (nearMeActive && userLocation) {
        const distance = calculateDistance(
          userLocation.lat,
          userLocation.lng,
          venue.location.lat,
          venue.location.lng
        )
        if (distance > 0.5) {
          return false
        }
      }

      return true
    })

    // Progressive disclosure: show top 5 surging venues by default
    if (!showFullHeatmap && !nearMeActive && filters.energyLevels.length === 0 && filters.categories.length === 0) {
      // Only nearby venues (within 50mi of center or user) sorted by pulseScore
      const nearby = userLocation
        ? filtered
          .filter(v => calculateDistance(userLocation.lat, userLocation.lng, v.location.lat, v.location.lng) < 50)
          .sort((a, b) => b.pulseScore - a.pulseScore)
        : filtered.sort((a, b) => b.pulseScore - a.pulseScore)
      return nearby.slice(0, 5)
    }

    return filtered
  }, [venues, filters, userLocation, nearMeActive, showFullHeatmap])

  const availableCategories = Array.from(
    new Set(venues.map((v) => v.category).filter((c): c is string => !!c))
  ).sort()

  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { width, height } = containerRef.current.getBoundingClientRect()
        setDimensions({ width, height })
      }
    }

    updateDimensions()
    window.addEventListener('resize', updateDimensions)
    return () => window.removeEventListener('resize', updateDimensions)
  }, [])

  useEffect(() => {
    if (!canvasRef.current || !center) return

    const canvas = canvasRef.current
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    canvas.width = dimensions.width * window.devicePixelRatio
    canvas.height = dimensions.height * window.devicePixelRatio
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio)

    drawHeatmap(ctx, filteredVenues, center, zoom, dimensions)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filteredVenues, center, zoom, dimensions])

  const latLngToPixel = (
    lat: number,
    lng: number,
    mapCenter: { lat: number; lng: number },
    mapZoom: number,
    dims: { width: number; height: number }
  ) => {
    const scale = MAP_SCALE * mapZoom
    const x = dims.width / 2 + (lng - mapCenter.lng) * scale
    const y = dims.height / 2 - (lat - mapCenter.lat) * scale
    return { x, y }
  }

  const pixelToLatLng = (
    x: number,
    y: number,
    mapCenter: { lat: number; lng: number },
    mapZoom: number,
    dims: { width: number; height: number }
  ) => {
    const scale = MAP_SCALE * mapZoom
    return {
      lng: mapCenter.lng + (x - dims.width / 2) / scale,
      lat: mapCenter.lat - (y - dims.height / 2) / scale
    }
  }

  const zoomAroundPoint = (
    nextZoom: number,
    pointX: number,
    pointY: number
  ) => {
    if (!center) return
    const clampedZoom = clampZoom(nextZoom)
    if (clampedZoom === zoom) return
    const anchor = pixelToLatLng(pointX, pointY, center, zoom, dimensions)
    const scale = MAP_SCALE * clampedZoom
    const nextCenter = clampCenter({
      lng: anchor.lng - (pointX - dimensions.width / 2) / scale,
      lat: anchor.lat + (pointY - dimensions.height / 2) / scale
    })
    setCenter(nextCenter)
    setZoom(clampedZoom)
  }

  const panByPixels = (dx: number, dy: number, mapZoom: number) => {
    const scale = MAP_SCALE * mapZoom
    setCenter((prev) => {
      if (!prev) return prev
      return clampCenter({
        lng: prev.lng - dx / scale,
        lat: prev.lat + dy / scale
      })
    })
  }

  const startInertia = () => {
    if (!center) return
    const MIN_VELOCITY = 0.0000008
    const FRICTION_PER_FRAME = 0.9
    let lastTime = performance.now()

    const step = (now: number) => {
      const dt = Math.max(8, now - lastTime)
      lastTime = now
      const decay = Math.pow(FRICTION_PER_FRAME, dt / 16)

      panVelocityRef.current = {
        lat: panVelocityRef.current.lat * decay,
        lng: panVelocityRef.current.lng * decay
      }

      setCenter((prev) => {
        if (!prev) return prev
        return clampCenter({
          lat: prev.lat + panVelocityRef.current.lat * dt,
          lng: prev.lng + panVelocityRef.current.lng * dt
        })
      })

      const speed = Math.hypot(panVelocityRef.current.lat, panVelocityRef.current.lng)
      if (speed < MIN_VELOCITY) {
        stopInertia()
        return
      }
      inertialFrameRef.current = requestAnimationFrame(step)
    }

    stopInertia()
    inertialFrameRef.current = requestAnimationFrame(step)
  }

  const drawHeatmap = (
    ctx: CanvasRenderingContext2D,
    venueList: Venue[],
    mapCenter: { lat: number; lng: number },
    mapZoom: number,
    dims: { width: number; height: number }
  ) => {
    ctx.clearRect(0, 0, dims.width, dims.height)

    // Clean dark background with subtle vignette
    const bgGradient = ctx.createRadialGradient(
      dims.width / 2, dims.height / 2, 0,
      dims.width / 2, dims.height / 2, Math.max(dims.width, dims.height) * 0.7
    )
    bgGradient.addColorStop(0, 'oklch(0.18 0.01 260)')
    bgGradient.addColorStop(1, 'oklch(0.12 0 0)')
    ctx.fillStyle = bgGradient
    ctx.fillRect(0, 0, dims.width, dims.height)

    // Subtle dot grid pattern instead of lines
    ctx.fillStyle = 'oklch(0.25 0 0 / 0.3)'
    const dotSpacing = 40 * mapZoom
    const dotSize = 1.5
    for (let x = dotSpacing; x < dims.width; x += dotSpacing) {
      for (let y = dotSpacing; y < dims.height; y += dotSpacing) {
        ctx.beginPath()
        ctx.arc(x, y, dotSize, 0, Math.PI * 2)
        ctx.fill()
      }
    }

    if (!offscreenCanvasRef.current) {
      offscreenCanvasRef.current = document.createElement('canvas')
    }
    const heatmapCanvas = offscreenCanvasRef.current

    // Resize only if needed to avoid flicker/perf hit
    if (heatmapCanvas.width !== dims.width || heatmapCanvas.height !== dims.height) {
      heatmapCanvas.width = dims.width
      heatmapCanvas.height = dims.height
    } else {
      // Clear previous draw
      const offCtx = heatmapCanvas.getContext('2d')
      offCtx?.clearRect(0, 0, dims.width, dims.height)
    }

    const heatmapCtx = heatmapCanvas.getContext('2d')
    if (!heatmapCtx) return

    venueList.forEach((venue) => {
      if (venue.pulseScore <= 0) return

      const pos = latLngToPixel(venue.location.lat, venue.location.lng, mapCenter, mapZoom, dims)
      const intensity = Math.min(venue.pulseScore / 100, 1)
      const radius = Math.max(40 * mapZoom * (0.5 + intensity * 0.5), 20)

      const gradient = heatmapCtx.createRadialGradient(pos.x, pos.y, 0, pos.x, pos.y, radius)

      if (venue.pulseScore >= 80) {
        gradient.addColorStop(0, `rgba(217, 70, 239, ${intensity * 1.0})`) // Neon Fuchsia - boosted
        gradient.addColorStop(0.5, `rgba(217, 70, 239, ${intensity * 0.6})`)
      } else if (venue.pulseScore >= 60) {
        gradient.addColorStop(0, `rgba(244, 63, 94, ${intensity * 0.9})`) // Neon Rose - boosted
        gradient.addColorStop(0.5, `rgba(244, 63, 94, ${intensity * 0.5})`)
      } else if (venue.pulseScore >= 30) {
        gradient.addColorStop(0, `rgba(14, 165, 233, ${intensity * 0.8})`) // Neon Sky - boosted
        gradient.addColorStop(0.5, `rgba(14, 165, 233, ${intensity * 0.4})`)
      } else {
        gradient.addColorStop(0, `rgba(99, 102, 241, ${intensity * 0.6})`) // Indigo - boosted
        gradient.addColorStop(0.5, `rgba(99, 102, 241, ${intensity * 0.3})`)
      }
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)')

      heatmapCtx.fillStyle = gradient
      heatmapCtx.fillRect(pos.x - radius, pos.y - radius, radius * 2, radius * 2)
    })

    ctx.globalCompositeOperation = 'screen'
    ctx.drawImage(heatmapCanvas, 0, 0)
    ctx.globalCompositeOperation = 'source-over'
  }

  const handleMouseDown = (e: React.MouseEvent) => {
    stopInertia()
    setHoveredVenue(null)
    setExpandedClusterId(null)
    setIsDragging(true)
    setDragStart({ x: e.clientX, y: e.clientY })
    lastPanFrameRef.current = { x: e.clientX, y: e.clientY, ts: performance.now() }
    setFollowUser(false)
  }

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !dragStart || !center) return

    const dx = e.clientX - dragStart.x
    const dy = e.clientY - dragStart.y

    const now = performance.now()
    if (lastPanFrameRef.current) {
      const dt = Math.max(1, now - lastPanFrameRef.current.ts)
      const scale = MAP_SCALE * zoom
      panVelocityRef.current = {
        lng: (-dx / scale) / dt,
        lat: (dy / scale) / dt
      }
    }

    panByPixels(dx, dy, zoom)
    setDragStart({ x: e.clientX, y: e.clientY })
    lastPanFrameRef.current = { x: e.clientX, y: e.clientY, ts: now }
  }

  const handleMouseUp = () => {
    setIsDragging(false)
    setDragStart(null)
    lastPanFrameRef.current = null
    startInertia()
  }

  const handleZoomIn = () => {
    triggerHapticFeedback('light')
    setExpandedClusterId(null)
    setZoom((z) => clampZoom(z * ZOOM_STEP))
    setFollowUser(false)
  }

  const handleZoomOut = () => {
    triggerHapticFeedback('light')
    setExpandedClusterId(null)
    setZoom((z) => clampZoom(z / ZOOM_STEP))
    setFollowUser(false)
  }

  const handleCenterOnUser = () => {
    if (userLocation) {
      triggerHapticFeedback('medium')
      setExpandedClusterId(null)
      setCenter(userLocation)
      setZoom(1)
      setFollowUser(true)
    }
  }

  const handleToggleFullHeatmap = () => {
    triggerHapticFeedback('light')
    setShowFullHeatmap(prev => !prev)
  }

  const handleWheelZoom = (e: React.WheelEvent<HTMLCanvasElement>) => {
    e.preventDefault()
    if (!center) return
    stopInertia()
    setExpandedClusterId(null)
    const rect = e.currentTarget.getBoundingClientRect()
    const pointX = e.clientX - rect.left
    const pointY = e.clientY - rect.top
    const delta = e.deltaY < 0 ? ZOOM_STEP : 1 / ZOOM_STEP
    zoomAroundPoint(zoom * delta, pointX, pointY)
    setFollowUser(false)
  }

  const handleDoubleClick = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!center) return
    stopInertia()
    setExpandedClusterId(null)
    const rect = e.currentTarget.getBoundingClientRect()
    const pointX = e.clientX - rect.left
    const pointY = e.clientY - rect.top
    triggerHapticFeedback('light')
    zoomAroundPoint(zoom * ZOOM_STEP, pointX, pointY)
    setFollowUser(false)
  }

  // Touch event handlers for mobile
  const getTouchDistance = (touches: React.TouchList) => {
    if (touches.length < 2) return null
    const dx = touches[0].clientX - touches[1].clientX
    const dy = touches[0].clientY - touches[1].clientY
    return Math.sqrt(dx * dx + dy * dy)
  }

  const handleTouchStart = (e: React.TouchEvent) => {
    stopInertia()
    setExpandedClusterId(null)
    if (e.touches.length === 2) {
      setLastTouchDistance(getTouchDistance(e.touches))
    } else if (e.touches.length === 1) {
      const now = performance.now()
      const tap = { x: e.touches[0].clientX, y: e.touches[0].clientY, ts: now }
      if (lastTapRef.current) {
        const dt = now - lastTapRef.current.ts
        const dx = tap.x - lastTapRef.current.x
        const dy = tap.y - lastTapRef.current.y
        const dist = Math.hypot(dx, dy)
        if (dt < 280 && dist < 24 && center && canvasRef.current) {
          const rect = canvasRef.current.getBoundingClientRect()
          triggerHapticFeedback('light')
          zoomAroundPoint(zoom * ZOOM_STEP, tap.x - rect.left, tap.y - rect.top)
          setFollowUser(false)
          lastTapRef.current = null
          return
        }
      }
      lastTapRef.current = tap
      movedDuringTouchRef.current = false
      setHoveredVenue(null)
      setIsDragging(true)
      setDragStart({ x: e.touches[0].clientX, y: e.touches[0].clientY })
      lastPanFrameRef.current = { x: e.touches[0].clientX, y: e.touches[0].clientY, ts: now }
      setFollowUser(false)
    }
  }

  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2 && lastTouchDistance !== null) {
      // Pinch to zoom
      const newDistance = getTouchDistance(e.touches)
      if (newDistance !== null) {
        const scale = newDistance / lastTouchDistance
        setZoom(z => clampZoom(z * scale))
        setLastTouchDistance(newDistance)
        setFollowUser(false)
      }
    } else if (e.touches.length === 1 && isDragging && dragStart && center) {
      // Touch pan
      const dx = e.touches[0].clientX - dragStart.x
      const dy = e.touches[0].clientY - dragStart.y
      movedDuringTouchRef.current = true
      const now = performance.now()
      if (lastPanFrameRef.current) {
        const dt = Math.max(1, now - lastPanFrameRef.current.ts)
        const scale = MAP_SCALE * zoom
        panVelocityRef.current = {
          lng: (-dx / scale) / dt,
          lat: (dy / scale) / dt
        }
      }
      panByPixels(dx, dy, zoom)
      setDragStart({ x: e.touches[0].clientX, y: e.touches[0].clientY })
      lastPanFrameRef.current = { x: e.touches[0].clientX, y: e.touches[0].clientY, ts: now }
    }
  }

  const handleTouchEnd = () => {
    setIsDragging(false)
    setDragStart(null)
    setLastTouchDistance(null)
    lastPanFrameRef.current = null
    if (movedDuringTouchRef.current) {
      startInertia()
    }
    movedDuringTouchRef.current = false
  }

  // Keyboard navigation
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!center) return
    const panAmount = 0.0005 / zoom

    switch (e.key) {
      case 'ArrowUp':
        setCenter({ ...center, lat: center.lat + panAmount })
        setFollowUser(false)
        break
      case 'ArrowDown':
        setCenter({ ...center, lat: center.lat - panAmount })
        setFollowUser(false)
        break
      case 'ArrowLeft':
        setCenter({ ...center, lng: center.lng - panAmount })
        setFollowUser(false)
        break
      case 'ArrowRight':
        setCenter({ ...center, lng: center.lng + panAmount })
        setFollowUser(false)
        break
      case '+':
      case '=':
        handleZoomIn()
        break
      case '-':
        handleZoomOut()
        break
    }
  }

  const handleVenueSelect = (venue: Venue) => {
    stopInertia()
    if (venueSelectTimeoutRef.current) clearTimeout(venueSelectTimeoutRef.current)
    if (hoverClearTimeoutRef.current) clearTimeout(hoverClearTimeoutRef.current)
    triggerHapticFeedback('medium')
    setExpandedClusterId(null)
    if (center) {
      setCenter({
        lat: (center.lat + venue.location.lat) / 2,
        lng: (center.lng + venue.location.lng) / 2
      })
      setZoom((z) => clampZoom(Math.max(0.9, Math.min(1.4, z))))
      venueSelectTimeoutRef.current = window.setTimeout(() => {
        setCenter({ lat: venue.location.lat, lng: venue.location.lng })
        setZoom((z) => clampZoom(Math.max(2.1, z * 1.1)))
      }, 170)
    } else {
      setCenter({ lat: venue.location.lat, lng: venue.location.lng })
      setZoom(2.1)
    }
    setFollowUser(false)
    window.setTimeout(() => {
      setHoveredVenue(venue)
      hoverClearTimeoutRef.current = window.setTimeout(() => {
        setHoveredVenue(null)
      }, 2500)
    }, 220)
  }

  const getVenuePixelPosition = (venue: Venue) => {
    if (!center) return null
    return latLngToPixel(venue.location.lat, venue.location.lng, center, zoom, dimensions)
  }

  const handleFitToVenues = () => {
    const viewport = getFittedViewport(filteredVenues, dimensions)
    if (!viewport) return
    stopInertia()
    triggerHapticFeedback('medium')
    setCenter(viewport.center)
    setZoom(viewport.zoom)
    setFollowUser(false)
  }

  const venueRenderPoints = useMemo<VenueRenderPoint[]>(() => {
    if (!center) return []
    return buildVenueRenderPoints({
      venues: filteredVenues,
      center,
      zoom,
      dimensions,
      userLocation
    })
  }, [center, filteredVenues, zoom, dimensions, userLocation])

  const shouldClusterMarkers = zoom < 1.05 && !isDragging

  const clusteredMapData = useMemo(() => {
    return clusterVenueRenderPoints(venueRenderPoints, zoom, shouldClusterMarkers)
  }, [shouldClusterMarkers, venueRenderPoints, zoom])

  useEffect(() => {
    if (!expandedClusterId) return
    const stillExists = clusteredMapData.clusters.some((cluster) => cluster.id === expandedClusterId)
    if (!stillExists || !shouldClusterMarkers) {
      setExpandedClusterId(null)
    }
  }, [expandedClusterId, clusteredMapData.clusters, shouldClusterMarkers])

  const expandedCluster = useMemo(() => (
    clusteredMapData.clusters.find((cluster) => cluster.id === expandedClusterId) ?? null
  ), [clusteredMapData.clusters, expandedClusterId])

  const expandedClusterNodes = useMemo(() => {
    if (!expandedCluster) return [] as Array<VenueRenderPoint & { sx: number; sy: number }>
    const total = expandedCluster.venues.length
    const radius = Math.min(110, Math.max(48, 34 + total * 5))
    return expandedCluster.venues.map((point, index) => {
      const angle = (Math.PI * 2 * index) / total - Math.PI / 2
      return {
        ...point,
        sx: expandedCluster.x + radius * Math.cos(angle),
        sy: expandedCluster.y + radius * Math.sin(angle)
      }
    })
  }, [expandedCluster])

  const labelVenueIds = useMemo(() => {
    const sorted = [...clusteredMapData.singles].sort((a, b) => {
      const pulseWeight = b.venue.pulseScore - a.venue.pulseScore
      if (Math.abs(pulseWeight) > 10) return pulseWeight

      if (a.distance !== undefined && b.distance !== undefined) {
        return a.distance - b.distance
      }

      return a.venue.name.localeCompare(b.venue.name)
    })

    const maxLabels = (isDragging || isCameraMoving)
      ? 0
      : zoom < 0.85
        ? 2
        : zoom < 1.1
          ? 4
          : zoom < 1.5
            ? (accessibilityMode ? 10 : 8)
            : (accessibilityMode ? 18 : 14)

    const ids = new Set(sorted.slice(0, maxLabels).map((point) => point.venue.id))
    if (hoveredVenue) ids.add(hoveredVenue.id)
    return ids
  }, [clusteredMapData.singles, isDragging, isCameraMoving, zoom, hoveredVenue, accessibilityMode])

  const activeFilterCount = filters.energyLevels.length + filters.categories.length + (filters.maxDistance !== Infinity ? 1 : 0)

  const previewVenues = useMemo(() => {
    if (!center) return [] as VenueRenderPoint[]
    return getPreviewVenuePoints({
      points: venueRenderPoints,
      center,
      userLocation,
      locationHeading
    })
  }, [center, venueRenderPoints, locationHeading, userLocation])

  const comparedVenues = useMemo(() => {
    const map = new Map(previewVenues.map((point) => [point.venue.id, point]))
    return comparedVenueIds
      .map((id) => map.get(id))
      .filter((point): point is VenueRenderPoint => !!point)
  }, [comparedVenueIds, previewVenues])

  const bestNextVenue = previewVenues[0] ?? null

  const statusChips = [
    followUser && userLocation ? 'Following You' : null,
    isCameraMoving ? 'Moving' : 'Settled',
    locationHeading !== null && locationHeading !== undefined ? `Heading ${Math.round(locationHeading)}°` : null,
    activeFilterCount > 0 ? `${activeFilterCount} Filters` : 'All Venues',
    clusteredMapData.clusters.length > 0 ? `${clusteredMapData.clusters.length} Clusters` : null,
    comparedVenueIds.length > 0 ? `${comparedVenueIds.length} Comparing` : null,
    accessibilityMode ? 'Accessibility Mode' : null
  ].filter(Boolean) as string[]

  useEffect(() => {
    if (comparedVenueIds.length === 0) return
    const validIds = new Set(previewVenues.map((point) => point.venue.id))
    setComparedVenueIds((prev) => prev.filter((id) => validIds.has(id)))
  }, [previewVenues, comparedVenueIds.length])

  const toggleCompareVenue = (venueId: string) => {
    triggerHapticFeedback('light')
    setComparedVenueIds((prev) => {
      if (prev.includes(venueId)) return prev.filter((id) => id !== venueId)
      if (prev.length >= 3) return [...prev.slice(1), venueId]
      return [...prev, venueId]
    })
  }

  const onboardingTips = [
    'Pinch or scroll to zoom. Double tap to zoom quickly.',
    'Tap clusters to expand nearby venues or zoom deeper.',
    'Use the bottom cards to compare hotspots and jump fast.',
    'Turn on A11y mode for larger markers and calmer motion.'
  ]

  const completeOnboarding = () => {
    if (typeof window !== 'undefined') {
      window.localStorage.setItem(onboardingStorageKey, 'seen')
    }
    setShowOnboardingTips(false)
    setTipIndex(0)
  }

  const handleSmartRoute = () => {
    if (!bestNextVenue) return
    triggerHapticFeedback('medium')
    handleVenueSelect(bestNextVenue.venue)
  }

  if (!center) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-secondary rounded-xl">
        <p className="text-muted-foreground">Loading map...</p>
      </div>
    )
  }

  return (
    <div
      ref={containerRef}
      className="relative w-full h-full rounded-xl overflow-hidden focus:outline-none focus:ring-2 focus:ring-accent"
      tabIndex={0}
      onKeyDown={handleKeyDown}
    >
      <canvas
        ref={canvasRef}
        className={cn(
          'absolute inset-0 w-full h-full touch-none',
          isDragging ? 'cursor-grabbing' : 'cursor-grab'
        )}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onWheel={handleWheelZoom}
        onDoubleClick={handleDoubleClick}
      />

      <svg className="absolute inset-0 w-full h-full pointer-events-none">
        {clusteredMapData.clusters.map((cluster) => {
          const clusterSize = Math.min(42, 20 + cluster.venues.length * 1.8)
          const clusterColor = getEnergyColor(cluster.maxPulseScore)
          const isExpanded = expandedClusterId === cluster.id
          return (
            <g key={cluster.id} className="pointer-events-none">
              <circle
                cx={cluster.x}
                cy={cluster.y}
                r={clusterSize * 1.35}
                fill={clusterColor}
                opacity={isExpanded ? 0.1 : 0.22}
              />
              <circle
                cx={cluster.x}
                cy={cluster.y}
                r={clusterSize}
                fill={clusterColor}
                stroke="oklch(0.98 0 0 / 0.85)"
                strokeWidth={2}
                filter={`drop-shadow(0 0 8px ${clusterColor})`}
                opacity={isExpanded ? 0.4 : 1}
              />
              <text
                x={cluster.x}
                y={cluster.y + 4}
                textAnchor="middle"
                fill="white"
                fontSize={Math.max(10, Math.min(15, clusterSize * 0.45))}
                fontWeight="700"
              >
                {cluster.venues.length}
              </text>
            </g>
          )
        })}

        {expandedCluster && expandedClusterNodes.map((node) => (
          <g key={`expanded-${node.venue.id}`}>
            <line
              x1={expandedCluster.x}
              y1={expandedCluster.y}
              x2={node.sx}
              y2={node.sy}
              stroke="oklch(0.92 0 0 / 0.35)"
              strokeWidth={1.5}
            />
            <circle
              cx={node.sx}
              cy={node.sy}
              r={Math.max(11, (accessibilityMode ? 14 : 12) * zoom * 0.5)}
              fill={getEnergyColor(node.venue.pulseScore)}
              stroke="white"
              strokeWidth={1.5}
            />
          </g>
        ))}

        {clusteredMapData.singles.map(({ venue, x, y }) => {
          const baseSize = accessibilityMode ? 24 : 18
          const scale = venue.pulseScore > 0 ? 1 + (venue.pulseScore / 100) : 1
          const markerSize = baseSize * zoom * scale * 0.6
          const isHighlighted = hoveredVenue?.id === venue.id
          const isHighEnergy = venue.pulseScore >= 80
          const hasRecentActivity = venue.lastActivity
            ? (Date.now() - new Date(venue.lastActivity).getTime()) < 10 * 60 * 1000
            : venue.pulseScore >= 50

          const Icon = getCategoryIcon(venue.category)
          const iconSize = markerSize * 1.2

          return (
            <g key={venue.id} className="pointer-events-none">
              {isHighEnergy && !isCameraMoving && !accessibilityMode && (
                <>
                  <circle
                    cx={x}
                    cy={y}
                    r={markerSize * 2.5}
                    fill={getEnergyColor(venue.pulseScore)}
                    opacity={0.15}
                    className="animate-pulse-glow"
                    style={{ animationDuration: '3s' }}
                  />
                  <circle
                    cx={x}
                    cy={y}
                    r={markerSize * 1.8}
                    fill={getEnergyColor(venue.pulseScore)}
                    opacity={0.25}
                    className="animate-pulse"
                    style={{ animationDuration: '2s' }}
                  />
                </>
              )}

              <circle
                cx={x}
                cy={y}
                r={markerSize}
                fill={venue.pulseScore > 0 ? getEnergyColor(venue.pulseScore) : 'oklch(0.25 0.05 260)'}
                stroke={isHighlighted ? 'white' : 'oklch(0.15 0 0)'}
                strokeWidth={isHighlighted ? 3 : 1.5}
                className="transition-all duration-300"
                filter={venue.pulseScore >= 30 ? `drop-shadow(0 0 ${venue.pulseScore >= 80 ? '8px' : '4px'} ${venue.pulseScore >= 80 ? 'rgba(217, 70, 239, 0.6)' : venue.pulseScore >= 60 ? 'rgba(244, 63, 94, 0.5)' : 'rgba(14, 165, 233, 0.4)'})` : undefined}
              />

              <foreignObject
                x={x - iconSize / 2}
                y={y - iconSize / 2}
                width={iconSize}
                height={iconSize}
                className="pointer-events-none"
              >
                <div className="w-full h-full flex items-center justify-center text-white">
                  <Icon
                    weight="fill"
                    className={cn(
                      "w-full h-full drop-shadow-md",
                      venue.pulseScore === 0 && "text-white/50"
                    )}
                  />
                </div>
              </foreignObject>

              {hasRecentActivity && !isCameraMoving && !accessibilityMode && (
                <circle
                  cx={x}
                  cy={y}
                  r={markerSize * 1.5}
                  fill="none"
                  stroke={getEnergyColor(venue.pulseScore)}
                  strokeWidth={2}
                  opacity={0}
                  className="animate-ping"
                  style={{ animationDuration: '1.5s' }}
                />
              )}
            </g>
          )
        })}

        {userLocation && (() => {
          const userPos = latLngToPixel(userLocation.lat, userLocation.lng, center, zoom, dimensions)
          const accuracyRadiusInMeters = locationAccuracy || 50
          const metersToPixels = (meters: number) => {
            const scale = MAP_SCALE * zoom
            const metersPerDegree = 111320
            return (meters / metersPerDegree) * scale
          }
          const accuracyRadius = metersToPixels(accuracyRadiusInMeters)

          return (
            <g>
              {locationAccuracy && (
                <circle
                  cx={userPos.x}
                  cy={userPos.y}
                  r={accuracyRadius}
                  fill="oklch(0.75 0.18 195)"
                  opacity={0.15}
                  stroke="oklch(0.75 0.18 195)"
                  strokeWidth={1}
                  strokeOpacity={0.3}
                />
              )}
              <circle
                cx={userPos.x}
                cy={userPos.y}
                r={12 * zoom}
                fill="oklch(0.75 0.18 195)"
                opacity={0.3}
                className={accessibilityMode ? undefined : "animate-pulse"}
              />
              <circle
                cx={userPos.x}
                cy={userPos.y}
                r={(accessibilityMode ? 8 : 6) * zoom}
                fill="oklch(0.75 0.18 195)"
                stroke="oklch(0.98 0 0)"
                strokeWidth={2 * zoom}
              />
              {locationHeading !== null && locationHeading !== undefined && !Number.isNaN(locationHeading) && (
                <g
                  transform={`translate(${userPos.x}, ${userPos.y}) rotate(${locationHeading})`}
                >
                  <path
                    d="M0 -16 L4 -6 L0 -8 L-4 -6 Z"
                    fill="oklch(0.92 0.11 210)"
                    opacity={0.9}
                  />
                </g>
              )}
            </g>
          )
        })()}
      </svg>

      {/* Empty State Message */}
      {venueRenderPoints.length === 0 && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="absolute inset-0 flex items-center justify-center pointer-events-none"
        >
          <Card className="bg-card/95 backdrop-blur-md border-border p-6 text-center max-w-xs shadow-2xl">
            <MapPin size={32} weight="fill" className="mx-auto text-muted-foreground mb-3" />
            <h3 className="font-bold text-foreground mb-1">No Venues in View</h3>
            <p className="text-sm text-muted-foreground mb-3">
              Zoom out or pan to discover nearby spots
            </p>
            <Button
              size="sm"
              variant="outline"
              className="pointer-events-auto"
              onClick={handleCenterOnUser}
            >
              <NavigationArrow size={14} weight="fill" className="mr-1.5" />
              Center on Me
            </Button>
          </Card>
        </motion.div>
      )}

      {clusteredMapData.clusters.map((cluster) => (
        <div
          key={`cluster-hit-${cluster.id}`}
          className="absolute pointer-events-none"
          style={{
            left: cluster.x,
            top: cluster.y,
            transform: 'translate(-50%, -50%)'
          }}
        >
          <button
            className="pointer-events-auto relative z-20 cursor-pointer rounded-full"
            aria-label={`Zoom into cluster of ${cluster.venues.length} venues`}
            onClick={() => {
              triggerHapticFeedback('medium')
              if (cluster.venues.length <= 10 && zoom >= 0.85 && expandedClusterId !== cluster.id) {
                setExpandedClusterId(cluster.id)
                setHoveredVenue(null)
                return
              }
              setExpandedClusterId(null)
              zoomAroundPoint(zoom * ZOOM_STEP, cluster.x, cluster.y)
              setFollowUser(false)
              setHoveredVenue(null)
            }}
          >
            <div className="w-14 h-14" />
          </button>
          {!isCameraMoving && (
            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 whitespace-nowrap pointer-events-none z-10">
              <div className="bg-card/95 backdrop-blur-sm border border-border rounded-lg px-2 py-1 shadow-lg">
                <p className="text-[10px] font-semibold text-foreground">
                  {cluster.venues.length} venues
                </p>
              </div>
            </div>
          )}
        </div>
      ))}

      {expandedClusterNodes.map((node) => (
        <div
          key={`expanded-hit-${node.venue.id}`}
          className="absolute pointer-events-none"
          style={{
            left: node.sx,
            top: node.sy,
            transform: 'translate(-50%, -50%)'
          }}
        >
          <button
            className="pointer-events-auto relative z-30 cursor-pointer rounded-full"
            aria-label={`Open ${node.venue.name}`}
            onClick={() => {
              triggerHapticFeedback('medium')
              setExpandedClusterId(null)
              onVenueClick(node.venue)
            }}
          >
            <div className="w-11 h-11" />
          </button>
        </div>
      ))}

      {clusteredMapData.singles.map(({ venue, x, y, distance }) => {
        const showLabel = labelVenueIds.has(venue.id) || venue.pulseScore >= 75
        const isHovered = hoveredVenue?.id === venue.id

        return (
          <div
            key={venue.id}
            className="absolute pointer-events-none"
            style={{
              left: x,
              top: y,
              transform: 'translate(-50%, -50%)'
            }}
          >
            <button
              className="pointer-events-auto relative z-20 cursor-pointer hover:scale-110 transition-transform"
              onMouseEnter={() => setHoveredVenue(venue)}
              onMouseLeave={() => setHoveredVenue(null)}
              onClick={() => {
                triggerHapticFeedback('medium')
                onVenueClick(venue)
              }}
            >
              <div className="w-10 h-10" />
            </button>
            <AnimatePresence>
              {showLabel && (
                <motion.div
                  initial={{ opacity: 0, scale: 0.8, y: 5 }}
                  animate={{ opacity: 1, scale: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.8, y: 5 }}
                  transition={{ duration: 0.2, ease: "easeOut" }}
                  className="absolute top-full mt-3 left-1/2 -translate-x-1/2 whitespace-nowrap pointer-events-none z-10"
                >
                  {isHovered && (
                    <motion.div
                      initial={{ scaleY: 0 }}
                      animate={{ scaleY: 1 }}
                      className="absolute bottom-full left-1/2 -translate-x-1/2 w-0.5 h-3 bg-gradient-to-t from-border to-transparent mb-0.5 origin-bottom"
                    />
                  )}
                  <div className={cn(
                    "bg-card/95 backdrop-blur-sm border border-border rounded-lg px-2.5 py-1.5 shadow-lg transition-all",
                    isHovered && "bg-card border-accent shadow-2xl scale-110",
                    venue.pulseScore >= 70 && "border-accent/50"
                  )}>
                    <p className="text-xs font-bold">{venue.name}</p>
                    <div className="flex items-center gap-2">
                      {venue.category && (
                        <p className="text-[10px] text-muted-foreground uppercase font-mono">
                          {venue.category}
                        </p>
                      )}
                      {distance !== undefined && (
                        <>
                          {venue.category && (
                            <span className="text-[10px] text-muted-foreground">•</span>
                          )}
                          <p className="text-[10px] text-accent font-mono font-bold">
                            {formatDistance(distance, unitSystem)}
                          </p>
                        </>
                      )}
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )
      })}

      <AnimatePresence>
        {hoveredVenue && !isDragging && !isCameraMoving && (() => {
          const pos = getVenuePixelPosition(hoveredVenue)
          if (!pos) return null

          const distance = userLocation
            ? calculateDistance(
              userLocation.lat,
              userLocation.lng,
              hoveredVenue.location.lat,
              hoveredVenue.location.lng
            )
            : undefined

          const tooltipWidth = 240
          const tooltipHeight = 100
          const padding = 16

          let left = pos.x
          let top = pos.y - tooltipHeight - 20

          if (left - tooltipWidth / 2 < padding) {
            left = tooltipWidth / 2 + padding
          } else if (left + tooltipWidth / 2 > dimensions.width - padding) {
            left = dimensions.width - tooltipWidth / 2 - padding
          }

          if (top < padding) {
            top = pos.y + 30
          }

          return (
            <motion.div
              initial={{ opacity: 0, y: 10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 10, scale: 0.95 }}
              transition={{ duration: 0.15 }}
              className="absolute pointer-events-none z-50"
              style={{
                left,
                top,
                width: tooltipWidth,
                transform: 'translateX(-50%)'
              }}
            >
              <Card className="bg-card/98 backdrop-blur-md border-border shadow-2xl relative overflow-hidden">
                {/* Header Decoration */}
                <div
                  className={cn(
                    "absolute top-0 left-0 right-0 h-1",
                    hoveredVenue.pulseScore >= 80 ? "bg-gradient-to-r from-fuchsia-500 to-cyan-500" :
                      hoveredVenue.pulseScore >= 60 ? "bg-rose-500" :
                        hoveredVenue.pulseScore >= 30 ? "bg-sky-500" : "bg-slate-700"
                  )}
                />

                <div className="p-3 pt-4 space-y-2">
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 mb-1">
                        <h3 className="font-bold text-sm truncate">{hoveredVenue.name}</h3>
                        {hoveredVenue.pulseScore >= 80 && (
                          <Fire size={14} weight="fill" className="text-orange-500 animate-pulse" />
                        )}
                      </div>

                      <div className="flex items-center gap-2 mt-0.5">
                        <Badge variant="outline" className="h-5 px-1.5 text-[10px] uppercase font-mono border-accent/30 text-accent bg-accent/5">
                          {hoveredVenue.category || 'Venue'}
                        </Badge>
                        {distance !== undefined && (
                          <span className="text-[10px] text-muted-foreground font-mono">
                            {formatDistance(distance, unitSystem)}
                          </span>
                        )}
                      </div>
                    </div>
                    <PulseScore score={hoveredVenue.pulseScore} size="sm" showLabel={false} />
                  </div>

                  {hoveredVenue.location.address && (
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <MapPin size={12} weight="fill" />
                      <p className="text-[10px] line-clamp-1">
                        {hoveredVenue.location.address}
                      </p>
                    </div>
                  )}

                  {/* Social Signals / Stats simulated */}
                  <div className="flex items-center justify-between pt-2 border-t border-border/50">
                    <div className="flex items-center gap-3">
                      <div className="flex items-center gap-1 text-[10px] text-muted-foreground">
                        <Users size={12} />
                        <span className="font-medium">{Math.floor(hoveredVenue.pulseScore * 1.5 + 5)} here</span>
                      </div>
                      <div className="flex items-center gap-1 text-[10px] text-muted-foreground">
                        <Lightning size={12} className={hoveredVenue.pulseScore > 50 ? "text-yellow-500" : ""} />
                        <span className="font-medium">{hoveredVenue.pulseScore > 80 ? "Trending" : hoveredVenue.pulseScore > 50 ? "Active" : "Quiet"}</span>
                      </div>
                    </div>
                    <span className="text-[10px] text-primary font-bold cursor-pointer hover:underline">View</span>
                  </div>
                </div>
                {/* Pointer arrow */}
                <div
                  className="absolute left-1/2 -translate-x-1/2 -bottom-2 w-0 h-0 border-l-8 border-r-8 border-t-8 border-l-transparent border-r-transparent border-t-card/98"
                  style={{ filter: 'drop-shadow(0 2px 2px rgba(0,0,0,0.3))' }}
                />
              </Card>
            </motion.div>
          )
        })()}
      </AnimatePresence>

      <div className="absolute top-4 left-4 right-4 z-10 flex flex-col gap-2">
        <div className="flex items-start gap-2">
          <div className="flex-1 max-w-md">
            <MapSearch
              venues={venues}
              onVenueSelect={handleVenueSelect}
              userLocation={userLocation}
            />
          </div>
        </div>

        <div className="flex gap-1.5 flex-wrap max-w-lg">
          {statusChips.map((chip) => (
            <Badge
              key={chip}
              variant="secondary"
              className="bg-card/90 backdrop-blur-sm border border-border/70 text-[10px] font-semibold"
            >
              {chip}
            </Badge>
          ))}
        </div>

        {showOnboardingTips && (
          <Card className="max-w-md bg-card/95 backdrop-blur-sm border border-border shadow-lg p-3">
            <p className="text-[11px] font-semibold text-primary mb-1.5">
              Map tips {tipIndex + 1}/{onboardingTips.length}
            </p>
            <p className="text-xs text-foreground">
              {onboardingTips[tipIndex]}
            </p>
            <div className="mt-2.5 flex gap-2 justify-end">
              <Button
                size="sm"
                variant="ghost"
                className="h-7 text-[11px]"
                onClick={completeOnboarding}
              >
                Skip
              </Button>
              <Button
                size="sm"
                className="h-7 text-[11px]"
                onClick={() => {
                  if (tipIndex >= onboardingTips.length - 1) {
                    completeOnboarding()
                  } else {
                    setTipIndex((prev) => prev + 1)
                  }
                }}
              >
                {tipIndex >= onboardingTips.length - 1 ? 'Done' : 'Next'}
              </Button>
            </div>
          </Card>
        )}

        {/* Quick Filter Chips */}
        <div className="flex gap-1.5 flex-wrap max-w-md">
          <button
            onClick={() => {
              triggerHapticFeedback('light')
              if (filters.categories.includes('bar')) {
                setFilters(f => ({ ...f, categories: f.categories.filter(c => c !== 'bar') }))
              } else {
                setFilters(f => ({ ...f, categories: [...f.categories, 'bar'] }))
              }
            }}
            className={cn(
              "px-3.5 min-h-11 rounded-full text-xs font-medium transition-all touch-manipulation active:scale-[0.98]",
              "border backdrop-blur-sm shadow-sm",
              filters.categories.includes('bar')
                ? "bg-accent text-accent-foreground border-accent"
                : "bg-card/90 text-foreground border-border hover:bg-secondary"
            )}
          >
            <BeerBottle size={14} weight="fill" className="inline mr-1" />
            Bars
          </button>
          <button
            onClick={() => {
              triggerHapticFeedback('light')
              const hasClub = filters.categories.includes('club') || filters.categories.includes('nightclub')
              if (hasClub) {
                setFilters(f => ({ ...f, categories: f.categories.filter(c => c !== 'club' && c !== 'nightclub') }))
              } else {
                setFilters(f => ({ ...f, categories: [...f.categories, 'club', 'nightclub'] }))
              }
            }}
            className={cn(
              "px-3.5 min-h-11 rounded-full text-xs font-medium transition-all touch-manipulation active:scale-[0.98]",
              "border backdrop-blur-sm shadow-sm",
              filters.categories.includes('club') || filters.categories.includes('nightclub')
                ? "bg-accent text-accent-foreground border-accent"
                : "bg-card/90 text-foreground border-border hover:bg-secondary"
            )}
          >
            <MusicNotes size={14} weight="fill" className="inline mr-1" />
            Clubs
          </button>
          <button
            onClick={() => {
              triggerHapticFeedback('light')
              setNearMeActive(!nearMeActive)
            }}
            className={cn(
              "px-3.5 min-h-11 rounded-full text-xs font-medium transition-all touch-manipulation active:scale-[0.98]",
              "border backdrop-blur-sm shadow-sm",
              nearMeActive
                ? "bg-primary text-primary-foreground border-primary"
                : "bg-card/90 text-foreground border-border hover:bg-secondary"
            )}
          >
            <MapPin size={14} weight="fill" className="inline mr-1" />
            Near Me
          </button>
          <button
            onClick={() => {
              triggerHapticFeedback('light')
              const hasHot = filters.energyLevels.includes('electric') || filters.energyLevels.includes('buzzing')
              if (hasHot) {
                setFilters(f => ({ ...f, energyLevels: f.energyLevels.filter(e => e !== 'electric' && e !== 'buzzing') }))
              } else {
                setFilters(f => ({ ...f, energyLevels: [...f.energyLevels, 'electric', 'buzzing'] }))
              }
            }}
            className={cn(
              "px-3.5 min-h-11 rounded-full text-xs font-medium transition-all touch-manipulation active:scale-[0.98]",
              "border backdrop-blur-sm shadow-sm",
              filters.energyLevels.includes('electric') || filters.energyLevels.includes('buzzing')
                ? "bg-orange-500 text-white border-orange-500"
                : "bg-card/90 text-foreground border-border hover:bg-secondary"
            )}
          >
            <Fire size={14} weight="fill" className="inline mr-1" />
            Hot
          </button>
          <button
            onClick={() => {
              triggerHapticFeedback('light')
              setShowFullHeatmap(!showFullHeatmap)
            }}
            className={cn(
              "px-3.5 min-h-11 rounded-full text-xs font-medium transition-all touch-manipulation active:scale-[0.98]",
              "border backdrop-blur-sm shadow-sm",
              showFullHeatmap
                ? "bg-accent text-accent-foreground border-accent"
                : "bg-card/90 text-foreground border-border hover:bg-secondary"
            )}
          >
            {showFullHeatmap ? 'Top 5' : 'Full Map'}
          </button>
        </div>
      </div>

      {/* Consolidated Right Controls */}
      <div className="absolute top-4 right-4 flex flex-col gap-2 z-10">
        <Button
          size="sm"
          variant={accessibilityMode ? "default" : "secondary"}
          className="self-end h-10 px-3 bg-card/95 backdrop-blur-sm border border-border shadow-lg"
          onClick={() => {
            triggerHapticFeedback('light')
            setAccessibilityMode((prev) => !prev)
          }}
        >
          A11y
        </Button>
        <Button
          size="sm"
          variant="secondary"
          className="self-end h-10 px-3 bg-card/95 backdrop-blur-sm border border-border shadow-lg"
          onClick={handleFitToVenues}
        >
          <MapPin size={14} weight="fill" className="mr-1.5" />
          Fit view
        </Button>
        {!followUser && userLocation && (
          <Button
            size="sm"
            variant="secondary"
            className="self-end h-10 px-3 bg-card/95 backdrop-blur-sm border border-border shadow-lg"
            onClick={handleCenterOnUser}
          >
            <NavigationArrow size={14} weight="fill" className="mr-1.5" />
            Re-center
          </Button>
        )}
        {/* Venue Count Badge */}
        <Card className="bg-card/95 backdrop-blur-sm border-border px-3 py-2 shadow-lg">
          <div className="flex items-center gap-2">
            <MapPin size={16} weight="fill" className="text-primary" />
            <div className="text-xs">
              <span className="font-bold text-foreground">{filteredVenues.length}</span>
              <span className="text-muted-foreground ml-1">
                {filteredVenues.length === 1 ? 'venue' : 'venues'}
              </span>
            </div>
          </div>
        </Card>

        <MapFilters
          filters={filters}
          onChange={setFilters}
          availableCategories={availableCategories}
        />

        {/* Unified Control Group */}
        <Card className="bg-card/95 backdrop-blur-sm border-border p-1.5 shadow-lg">
          <div className="flex flex-col gap-1">
            <div className="flex gap-1">
              <Button
                size="icon"
                variant="ghost"
                className="h-11 w-11 hover:bg-secondary touch-manipulation"
                onClick={handleZoomIn}
                title="Zoom in (+)"
                aria-label="Zoom in"
              >
                <Plus size={18} weight="bold" />
              </Button>
              <Button
                size="icon"
                variant="ghost"
                className="h-11 w-11 hover:bg-secondary touch-manipulation"
                onClick={handleZoomOut}
                title="Zoom out (-)"
                aria-label="Zoom out"
              >
                <Minus size={18} weight="bold" />
              </Button>
            </div>
            <div className="h-px bg-border" />
            <div className="flex gap-1">
              <Button
                size="icon"
                variant="ghost"
                className={cn(
                  "h-11 w-11 touch-manipulation",
                  followUser && "bg-accent text-accent-foreground"
                )}
                onClick={handleCenterOnUser}
                title="Center on me"
                aria-label="Center map on my location"
              >
                <NavigationArrow size={18} weight="fill" />
              </Button>
              <Button
                size="icon"
                variant="ghost"
                className={cn(
                  "h-11 w-11 touch-manipulation",
                  nearMeActive && "bg-accent text-accent-foreground"
                )}
                onClick={() => {
                  triggerHapticFeedback('light')
                  setNearMeActive(!nearMeActive)
                }}
                title="Near me (0.5 mi)"
                aria-label="Toggle near me venues"
              >
                <MapPin size={18} weight="fill" />
              </Button>
            </div>
          </div>
        </Card>

        {/* Zoom Level Indicator */}
        <div className="text-[10px] font-mono text-muted-foreground text-center bg-card/80 backdrop-blur-sm rounded px-2 py-1">
          {zoom.toFixed(1)}x
        </div>
        <div className="text-[10px] font-mono text-muted-foreground/80 text-center bg-card/70 backdrop-blur-sm rounded px-2 py-1">
          Drag to pan · scroll to zoom
        </div>
      </div>

      {previewVenues.length > 0 && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-20 w-[min(94%,720px)] pointer-events-none">
          {bestNextVenue && (
            <Card className="pointer-events-auto mb-2 p-2.5 bg-card/95 backdrop-blur-sm border border-border shadow-lg">
              <div className="flex items-center justify-between gap-2">
                <div>
                  <p className="text-[11px] font-semibold text-foreground">Smart Route</p>
                  <p className="text-[10px] text-muted-foreground">
                    Best next stop: {bestNextVenue.venue.name}
                  </p>
                </div>
                <Button
                  size="sm"
                  className="h-7 text-[11px]"
                  onClick={handleSmartRoute}
                >
                  Take Me
                </Button>
              </div>
            </Card>
          )}
          <AnimatePresence>
            {comparedVenues.length > 0 && (
              <motion.div
                layout
                initial={{ opacity: 0, y: 14, scale: 0.98 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: 14, scale: 0.98 }}
                transition={{ duration: 0.2 }}
              >
                <Card className="pointer-events-auto mb-2 p-2.5 bg-card/95 backdrop-blur-sm border border-border shadow-lg">
                  <div className="flex items-center justify-between gap-2">
                    <p className="text-[11px] font-semibold text-foreground">
                      Compare ({comparedVenues.length}/3)
                    </p>
                    <Button
                      size="sm"
                      variant="ghost"
                      className="h-7 text-[11px]"
                      onClick={() => setComparedVenueIds([])}
                    >
                      Clear
                    </Button>
                  </div>
                  <div className="mt-2 grid grid-cols-1 sm:grid-cols-3 gap-2">
                    {comparedVenues.map((point) => (
                      <motion.button
                        layout
                        key={`compare-${point.venue.id}`}
                        className="text-left rounded-md border border-border/70 bg-background/40 px-2 py-1.5 hover:bg-background/60 transition-colors"
                        onClick={() => onVenueClick(point.venue)}
                      >
                        <p className="text-[11px] font-semibold truncate">{point.venue.name}</p>
                        <p className="text-[10px] text-muted-foreground uppercase truncate">
                          {point.venue.category || 'Venue'}
                        </p>
                        <div className="flex items-center justify-between mt-1">
                          <PulseScore score={point.venue.pulseScore} size="xs" showLabel={false} />
                          {point.distance !== undefined && (
                            <span className="text-[10px] text-accent font-mono">
                              {formatDistance(point.distance, unitSystem)}
                            </span>
                          )}
                        </div>
                      </motion.button>
                    ))}
                  </div>
                </Card>
              </motion.div>
            )}
          </AnimatePresence>
          <div className="flex gap-2 overflow-x-auto pb-1 px-1">
            {previewVenues.map((point) => {
              const isCompared = comparedVenueIds.includes(point.venue.id)
              const headingDelta = (locationHeading !== null && locationHeading !== undefined && userLocation)
                ? getHeadingDelta(calculateBearing(
                  userLocation.lat,
                  userLocation.lng,
                  point.venue.location.lat,
                  point.venue.location.lng
                ), locationHeading)
                : null
              const isAhead = headingDelta !== null && headingDelta < 30

              return (
                <motion.div layout key={`preview-wrap-${point.venue.id}`}>
                  <Card
                    className={cn(
                      "pointer-events-auto min-w-[180px] p-2.5 bg-card/95 backdrop-blur-sm border border-border shadow-lg",
                      hoveredVenue?.id === point.venue.id && "border-accent/70 shadow-accent/30",
                      isCompared && "border-primary/70 shadow-primary/20"
                    )}
                  >
                    <button
                      className="w-full text-left"
                      onClick={() => handleVenueSelect(point.venue)}
                    >
                      <div className="flex items-start justify-between gap-2">
                        <div className="min-w-0">
                          <p className="text-xs font-bold truncate">{point.venue.name}</p>
                          <p className="text-[10px] text-muted-foreground uppercase truncate">
                            {point.venue.category || 'Venue'}
                          </p>
                          {isAhead && (
                            <Badge variant="secondary" className="mt-1 text-[9px] h-4 px-1.5 bg-primary/15 text-primary border-primary/25">
                              Ahead
                            </Badge>
                          )}
                          {point.distance !== undefined && (
                            <p className="text-[10px] text-accent font-mono mt-0.5">
                              {formatDistance(point.distance, unitSystem)}
                            </p>
                          )}
                        </div>
                        <PulseScore score={point.venue.pulseScore} size="xs" showLabel={false} />
                      </div>
                    </button>
                    <Button
                      size="sm"
                      variant="ghost"
                      className="mt-1 h-7 w-full text-[11px]"
                      onClick={() => {
                        triggerHapticFeedback('medium')
                        onVenueClick(point.venue)
                      }}
                    >
                      Open
                    </Button>
                    <Button
                      size="sm"
                      variant={isCompared ? "default" : "ghost"}
                      className="mt-1 h-7 w-full text-[11px]"
                      onClick={() => toggleCompareVenue(point.venue.id)}
                    >
                      {isCompared ? 'Compared' : 'Compare'}
                    </Button>
                  </Card>
                </motion.div>
              )
            })}
          </div>
        </div>
      )}

      {/* Bottom Left Controls */}
      <div className="absolute bottom-4 left-4 z-10 flex flex-col gap-2">
        <GPSIndicator isTracking={isTracking} accuracy={locationAccuracy} />

        {(filters.energyLevels.length > 0 ||
          filters.categories.length > 0 ||
          filters.maxDistance !== Infinity) && (
            <Card className="bg-card/95 backdrop-blur-sm border-border px-3 py-2">
              <p className="text-xs text-muted-foreground">
                Showing <span className="font-bold text-foreground">{filteredVenues.length}</span> of{' '}
                {venues.length} venues
              </p>
            </Card>
          )}

        {/* Collapsible Legend */}
        <Card className="bg-card/95 backdrop-blur-sm border-border overflow-hidden">
          <button
            onClick={() => setShowLegend(!showLegend)}
            className="w-full px-3 py-2 flex items-center justify-between hover:bg-secondary/50 transition-colors"
          >
            <span className="text-xs font-bold text-foreground">Energy Levels</span>
            {showLegend ? (
              <CaretUp size={14} className="text-muted-foreground" />
            ) : (
              <CaretDown size={14} className="text-muted-foreground" />
            )}
          </button>
          <AnimatePresence>
            {showLegend && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.2 }}
                className="overflow-hidden"
              >
                <div className="px-3 pb-3 grid grid-cols-2 gap-2">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-[oklch(0.35_0.05_240)] border border-border" />
                    <span className="text-xs text-muted-foreground">Dead</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-[oklch(0.60_0.15_150)] border border-foreground/20" />
                    <span className="text-xs text-muted-foreground">Chill</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-[oklch(0.70_0.22_60)] border border-foreground/20 shadow-sm" />
                    <span className="text-xs text-muted-foreground">Buzzing</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-[oklch(0.65_0.28_340)] border border-foreground/20 shadow-sm animate-pulse-glow" />
                    <span className="text-xs text-muted-foreground">Electric</span>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </Card>
      </div>

      {/* Progressive Disclosure Toggle */}
      {!nearMeActive && filters.energyLevels.length === 0 && filters.categories.length === 0 && (
        <div className="absolute bottom-28 left-1/2 -translate-x-1/2 z-10">
          <Button
            variant="secondary"
            size="sm"
            onClick={handleToggleFullHeatmap}
            className="bg-card/90 backdrop-blur-md shadow-lg border border-border/50 text-xs font-semibold px-4 py-1.5 rounded-full hover:bg-card/100 transition-colors"
          >
            {showFullHeatmap ? "Show Top Surges Only" : "Show Full Heatmap"}
          </Button>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useMemo } from 'react'
import type { Venue, Pulse, User, EnergyRating } from '@/lib/types'
import { ENERGY_CONFIG } from '@/lib/types'
import type { NightPlan, SwapSuggestion } from '@/lib/night-planner'
import { getCurrentStopIndex, adaptPlan, swapStop } from '@/lib/night-planner'
import { CaretLeft, MapPin, Clock, Lightning, ArrowRight, Warning, CheckCircle, Car, PersonSimpleWalk } from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'
import { toast } from 'sonner'

interface LivePlanTrackerProps {
  plan: NightPlan
  venues: Venue[]
  pulses: Pulse[]
  currentUser: User
  onBack: () => void
  onVenueClick: (venue: Venue) => void
}

export function LivePlanTracker({
  plan: initialPlan,
  venues,
  pulses,
  currentUser,
  onBack,
  onVenueClick,
}: LivePlanTrackerProps) {
  const [plan, setPlan] = useState(initialPlan)
  const [now, setNow] = useState(new Date().toISOString())
  const [swapSuggestions, setSwapSuggestions] = useState<SwapSuggestion[]>([])
  const [dismissedSwaps, setDismissedSwaps] = useState<Set<number>>(new Set())

  // Update current time every 30 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setNow(new Date().toISOString())
    }, 30000)
    return () => clearInterval(interval)
  }, [])

  const currentStopIndex = useMemo(
    () => getCurrentStopIndex(plan, now),
    [plan, now]
  )

  const currentStop = currentStopIndex >= 0 ? plan.stops[currentStopIndex] : null
  const nextStop = currentStopIndex < plan.stops.length - 1 ? plan.stops[currentStopIndex + 1] : null

  // Build live energy scores from venue data
  const liveEnergyScores = useMemo(() => {
    const scores: Record<string, { energy: EnergyRating; score: number }> = {}
    const ENERGY_LABELS: EnergyRating[] = ['dead', 'chill', 'buzzing', 'electric']

    for (const venue of venues) {
      const energy = ENERGY_LABELS[Math.min(3, Math.round(venue.pulseScore / 33))]
      scores[venue.id] = { energy, score: venue.pulseScore }
    }
    return scores
  }, [venues])

  // Check for adaptation opportunities every minute
  useEffect(() => {
    const result = adaptPlan(plan, now, liveEnergyScores, venues, pulses, currentUser)
    setPlan(result.plan)

    const newSuggestions = result.swapSuggestions.filter(s => !dismissedSwaps.has(s.stopIndex))
    setSwapSuggestions(newSuggestions)
  }, [now, liveEnergyScores]) // eslint-disable-line react-hooks/exhaustive-deps

  const handleAcceptSwap = (suggestion: SwapSuggestion) => {
    const updated = swapStop(plan, suggestion.stopIndex, suggestion.suggestedVenue, pulses)
    setPlan(updated)
    setSwapSuggestions(prev => prev.filter(s => s.stopIndex !== suggestion.stopIndex))
    toast.success(`Swapped to ${suggestion.suggestedVenue.name}!`)
  }

  const handleDismissSwap = (stopIndex: number) => {
    setDismissedSwaps(prev => new Set([...prev, stopIndex]))
    setSwapSuggestions(prev => prev.filter(s => s.stopIndex !== stopIndex))
  }

  // Calculate countdown to next stop departure
  const getCountdown = (): string | null => {
    if (!currentStop) return null
    const departureMs = new Date(currentStop.departureTime).getTime()
    const nowMs = new Date(now).getTime()
    const remaining = departureMs - nowMs
    if (remaining <= 0) return null

    const minutes = Math.floor(remaining / 60000)
    const hours = Math.floor(minutes / 60)
    const mins = minutes % 60

    if (hours > 0) return `${hours}h ${mins}m`
    return `${mins}m`
  }

  const countdown = getCountdown()

  const formatTime = (iso: string): string => {
    return new Date(iso).toLocaleTimeString('en-US', {
      hour: 'numeric',
      minute: '2-digit',
    })
  }

  // Determine plan status message
  const getStatusMessage = (): { text: string; type: 'good' | 'warning' | 'info' } => {
    if (currentStopIndex === -1) {
      return { text: 'Your night starts soon', type: 'info' }
    }
    if (!currentStop) {
      return { text: 'Night complete!', type: 'good' }
    }

    const liveData = liveEnergyScores[currentStop.venueId]
    if (liveData) {
      const ENERGY_VALUES: Record<EnergyRating, number> = { dead: 0, chill: 1, buzzing: 2, electric: 3 }
      if (ENERGY_VALUES[liveData.energy] >= 2) {
        return { text: 'Plan is on track', type: 'good' }
      }
      if (ENERGY_VALUES[liveData.energy] <= 0) {
        return { text: 'Consider switching spots', type: 'warning' }
      }
    }
    return { text: 'Plan is on track', type: 'good' }
  }

  const status = getStatusMessage()

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="sticky top-0 z-20 bg-background/95 backdrop-blur-md border-b border-border">
        <div className="max-w-2xl mx-auto px-4 py-3 flex items-center gap-3">
          <button onClick={onBack} className="p-1">
            <CaretLeft size={24} weight="bold" />
          </button>
          <div className="flex-1">
            <h1 className="font-bold text-lg">Live Plan</h1>
            <p className="text-xs text-muted-foreground">
              {plan.stops.length} stops &middot; {plan.groupSize} people
            </p>
          </div>
          {countdown && (
            <div className="bg-primary/10 border border-primary/20 rounded-lg px-3 py-1.5">
              <p className="text-xs text-muted-foreground">Next move in</p>
              <p className="text-sm font-bold text-primary">{countdown}</p>
            </div>
          )}
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-4 space-y-4">
        {/* Status Banner */}
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className={`rounded-xl p-3 flex items-center gap-3 ${
            status.type === 'good'
              ? 'bg-green-500/10 border border-green-500/20'
              : status.type === 'warning'
              ? 'bg-amber-500/10 border border-amber-500/20'
              : 'bg-blue-500/10 border border-blue-500/20'
          }`}
        >
          {status.type === 'good' && <CheckCircle size={20} weight="fill" className="text-green-500" />}
          {status.type === 'warning' && <Warning size={20} weight="fill" className="text-amber-500" />}
          {status.type === 'info' && <Clock size={20} weight="fill" className="text-blue-500" />}
          <span className="text-sm font-medium">{status.text}</span>
        </motion.div>

        {/* Swap Suggestions */}
        <AnimatePresence>
          {swapSuggestions.map(suggestion => (
            <motion.div
              key={suggestion.stopIndex}
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-4 space-y-3"
            >
              <div className="flex items-start gap-2">
                <Warning size={18} weight="fill" className="text-amber-500 mt-0.5" />
                <div className="flex-1">
                  <p className="text-sm font-medium">{suggestion.reason}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <motion.button
                  whileTap={{ scale: 0.97 }}
                  onClick={() => handleAcceptSwap(suggestion)}
                  className="flex-1 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-medium"
                >
                  Switch to {suggestion.suggestedVenue.name}
                </motion.button>
                <motion.button
                  whileTap={{ scale: 0.97 }}
                  onClick={() => handleDismissSwap(suggestion.stopIndex)}
                  className="px-4 py-2 rounded-lg bg-card border border-border text-sm"
                >
                  Keep
                </motion.button>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {/* Current Stop (highlighted) */}
        {currentStop && (
          <div className="space-y-2">
            <h3 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Now</h3>
            <TrackerStopCard
              stop={currentStop}
              isCurrent={true}
              isCompleted={false}
              liveEnergy={liveEnergyScores[currentStop.venueId]}
              formatTime={formatTime}
              onVenueClick={() => {
                const venue = venues.find(v => v.id === currentStop.venueId)
                if (venue) onVenueClick(venue)
              }}
            />
          </div>
        )}

        {/* Next Stop Preview */}
        {nextStop && (
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              {nextStop.transitMode === 'walk' ? (
                <PersonSimpleWalk size={14} />
              ) : (
                <Car size={14} />
              )}
              <span>{nextStop.transitDuration} min {nextStop.transitMode === 'walk' ? 'walk' : 'ride'}</span>
              {nextStop.transitDeepLink && nextStop.transitMode !== 'walk' && (
                <a
                  href={nextStop.transitDeepLink}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-primary font-medium hover:underline ml-1"
                >
                  Open Uber
                </a>
              )}
            </div>
            <h3 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Up Next</h3>
            <TrackerStopCard
              stop={nextStop}
              isCurrent={false}
              isCompleted={false}
              liveEnergy={liveEnergyScores[nextStop.venueId]}
              formatTime={formatTime}
              onVenueClick={() => {
                const venue = venues.find(v => v.id === nextStop.venueId)
                if (venue) onVenueClick(venue)
              }}
            />
          </div>
        )}

        {/* Full Timeline */}
        <div className="space-y-2 pt-2">
          <h3 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Full Timeline</h3>
          <div className="space-y-1">
            {plan.stops.map((stop, i) => {
              const isCompleted = i < currentStopIndex
              const isCurrent = i === currentStopIndex

              return (
                <div
                  key={`${stop.venueId}-${i}`}
                  className={`flex items-center gap-3 py-2 px-3 rounded-lg transition-colors ${
                    isCurrent ? 'bg-primary/10' : isCompleted ? 'opacity-50' : ''
                  }`}
                >
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${
                    isCurrent
                      ? 'bg-primary text-primary-foreground'
                      : isCompleted
                      ? 'bg-green-500/20 text-green-500'
                      : 'bg-muted text-muted-foreground'
                  }`}>
                    {isCompleted ? '✓' : i + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className={`text-sm font-medium truncate ${isCurrent ? 'text-primary' : ''}`}>
                      {stop.venueName}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {formatTime(stop.arrivalTime)} - {formatTime(stop.departureTime)}
                    </p>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <EnergyDot energy={liveEnergyScores[stop.venueId]?.energy ?? stop.energyPrediction} />
                  </div>
                </div>
              )
            })}
          </div>
        </div>
      </div>
    </div>
  )
}

function TrackerStopCard({
  stop,
  isCurrent,
  isCompleted,
  liveEnergy,
  formatTime,
  onVenueClick,
}: {
  stop: import('@/lib/night-planner').PlanStop
  isCurrent: boolean
  isCompleted: boolean
  liveEnergy?: { energy: EnergyRating; score: number }
  formatTime: (iso: string) => string
  onVenueClick: () => void
}) {
  const energy = liveEnergy?.energy ?? stop.energyPrediction
  const energyConfig = ENERGY_CONFIG[energy]

  const purposeLabels: Record<string, string> = {
    dinner: 'Dinner',
    drinks: 'Drinks',
    dancing: 'Dancing',
    latenight: 'Late Night',
  }

  return (
    <motion.div
      layout
      className={`rounded-xl p-4 border transition-colors ${
        isCurrent
          ? 'bg-primary/5 border-primary/30 shadow-lg shadow-primary/10'
          : 'bg-card border-border'
      }`}
    >
      <div className="flex items-start justify-between mb-3">
        <div>
          <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            {purposeLabels[stop.purpose] ?? stop.purpose}
          </span>
          <button onClick={onVenueClick} className="block">
            <h3 className="font-bold text-lg hover:text-primary transition-colors">{stop.venueName}</h3>
          </button>
        </div>
        {isCurrent && (
          <div className="bg-primary/20 rounded-full px-2.5 py-1 flex items-center gap-1">
            <Lightning size={12} weight="fill" className="text-primary" />
            <span className="text-xs font-bold text-primary">HERE</span>
          </div>
        )}
      </div>

      <div className="flex items-center gap-4 text-sm text-muted-foreground mb-3">
        <span className="flex items-center gap-1">
          <Clock size={14} />
          {formatTime(stop.arrivalTime)} - {formatTime(stop.departureTime)}
        </span>
        <span className="flex items-center gap-1">
          <MapPin size={14} />
          ~${stop.estimatedSpend}
        </span>
      </div>

      {/* Live Energy Indicator */}
      <div className="flex items-center gap-2">
        <span className="text-xs text-muted-foreground">
          {liveEnergy ? 'Live Vibe:' : 'Predicted:'}
        </span>
        <div
          className="px-2.5 py-1 rounded-full text-xs font-medium"
          style={{
            backgroundColor: `${energyConfig.color}22`,
            color: energyConfig.color,
          }}
        >
          {energyConfig.emoji} {energyConfig.label}
        </div>
        {liveEnergy && (
          <span className="text-xs text-muted-foreground">
            Score: {liveEnergy.score}
          </span>
        )}
      </div>
    </motion.div>
  )
}

function EnergyDot({ energy }: { energy: EnergyRating }) {
  const config = ENERGY_CONFIG[energy]
  return (
    <div
      className="w-2.5 h-2.5 rounded-full"
      style={{ backgroundColor: config.color }}
      title={config.label}
    />
  )
}

import { Venue } from '@/lib/types'
import { PulseScore } from '@/components/PulseScore'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { formatDistance } from '@/lib/units'
import { useUnitPreference } from '@/hooks/use-unit-preference'
import { getEnergyLabel } from '@/lib/pulse-engine'
import { motion, AnimatePresence, useDragControls, PanInfo } from 'framer-motion'
import { useState, useRef } from 'react'
import {
  MapPin, NavigationArrow, Users, Lightning, Fire,
  X, ArrowRight, Clock, CaretUp, CaretDown,
  BeerBottle, MusicNotes, ForkKnife, Coffee, Martini, Confetti
} from '@phosphor-icons/react'

interface MapVenueSheetProps {
  venue: Venue | null
  venues: Venue[]
  userLocation: { lat: number; lng: number } | null
  onClose: () => void
  onVenueClick: (venue: Venue) => void
  onViewDetails: (venue: Venue) => void
  calculateDistance: (lat1: number, lon1: number, lat2: number, lon2: number) => number
}

const getCategoryIcon = (category?: string) => {
  switch (category?.toLowerCase()) {
    case 'bar': return BeerBottle
    case 'club': case 'nightclub': return MusicNotes
    case 'restaurant': case 'food': return ForkKnife
    case 'cafe': return Coffee
    case 'lounge': return Martini
    case 'event': return Confetti
    default: return MapPin
  }
}

function VenuePreviewCard({
  venue,
  distance,
  onViewDetails,
  unitSystem,
}: {
  venue: Venue
  distance?: number
  onViewDetails: () => void
  unitSystem: 'imperial' | 'metric'
}) {
  const Icon = getCategoryIcon(venue.category)
  const energyLabel = getEnergyLabel(venue.pulseScore)
  const isHot = venue.pulseScore >= 70

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 20 }}
      className="relative"
    >
      {/* Energy accent bar */}
      <div
        className={cn(
          "absolute top-0 left-0 right-0 h-0.5 rounded-t-xl",
          venue.pulseScore >= 80 ? "bg-gradient-to-r from-fuchsia-500 via-rose-500 to-amber-500" :
          venue.pulseScore >= 60 ? "bg-gradient-to-r from-rose-500 to-orange-400" :
          venue.pulseScore >= 30 ? "bg-gradient-to-r from-sky-500 to-blue-400" :
          "bg-muted"
        )}
      />

      <div className="p-4 pt-3">
        <div className="flex items-start gap-3">
          {/* Category icon */}
          <div className={cn(
            "w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0",
            venue.pulseScore >= 80 ? "bg-fuchsia-500/15 text-fuchsia-400" :
            venue.pulseScore >= 60 ? "bg-rose-500/15 text-rose-400" :
            venue.pulseScore >= 30 ? "bg-sky-500/15 text-sky-400" :
            "bg-muted text-muted-foreground"
          )}>
            <Icon size={24} weight="fill" />
          </div>

          {/* Venue info */}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
              <h3 className="font-bold text-base truncate">{venue.name}</h3>
              {isHot && <Fire size={16} weight="fill" className="text-orange-500 flex-shrink-0" />}
            </div>
            <div className="flex items-center gap-2 mt-0.5">
              {venue.category && (
                <Badge variant="outline" className="h-5 px-1.5 text-[10px] uppercase font-mono border-border/50 text-muted-foreground">
                  {venue.category}
                </Badge>
              )}
              {distance !== undefined && (
                <span className="text-xs text-muted-foreground font-mono">
                  {formatDistance(distance, unitSystem)}
                </span>
              )}
            </div>
          </div>

          {/* Pulse score */}
          <div className="flex-shrink-0">
            <PulseScore score={venue.pulseScore} size="sm" showLabel={false} />
          </div>
        </div>

        {/* Stats row */}
        <div className="flex items-center gap-4 mt-3 pt-3 border-t border-border/30">
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
            <Users size={14} />
            <span className="font-medium">{Math.floor(venue.pulseScore * 1.5 + 5)} here</span>
          </div>
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
            <Lightning size={14} className={venue.pulseScore > 50 ? "text-yellow-500" : ""} />
            <span className="font-medium">{energyLabel}</span>
          </div>
          {venue.lastPulseAt && (
            <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <Clock size={14} />
              <span className="font-medium">Active</span>
            </div>
          )}
          <div className="flex-1" />
          <Button
            size="sm"
            variant="default"
            className="h-8 px-4 text-xs font-bold gap-1.5"
            onClick={onViewDetails}
          >
            View
            <ArrowRight size={14} weight="bold" />
          </Button>
        </div>
      </div>
    </motion.div>
  )
}

type SheetSnap = 'closed' | 'peek' | 'half' | 'full'

export function MapVenueSheet({
  venue,
  venues,
  userLocation,
  onClose,
  onVenueClick,
  onViewDetails,
  calculateDistance: calcDist,
}: MapVenueSheetProps) {
  const { unitSystem } = useUnitPreference()
  const [snap, setSnap] = useState<SheetSnap>('peek')
  const dragControls = useDragControls()
  const sheetRef = useRef<HTMLDivElement>(null)

  // Get nearby venues sorted by distance then score
  const nearbyVenues = userLocation
    ? venues
        .map(v => ({
          venue: v,
          distance: calcDist(userLocation.lat, userLocation.lng, v.location.lat, v.location.lng)
        }))
        .filter(v => v.distance < 50)
        .sort((a, b) => b.venue.pulseScore - a.venue.pulseScore)
        .slice(0, 15)
    : venues
        .sort((a, b) => b.pulseScore - a.pulseScore)
        .slice(0, 15)
        .map(v => ({ venue: v, distance: undefined as number | undefined }))

  const snapToHeight: Record<SheetSnap, string> = {
    closed: '0px',
    peek: '180px',
    half: '50vh',
    full: '85vh',
  }

  const handleDragEnd = (_: unknown, info: PanInfo) => {
    const velocity = info.velocity.y
    const offset = info.offset.y

    if (velocity > 500 || offset > 100) {
      // Dragging down
      if (snap === 'full') setSnap('half')
      else if (snap === 'half') setSnap('peek')
      else setSnap('closed')
    } else if (velocity < -500 || offset < -100) {
      // Dragging up
      if (snap === 'peek') setSnap('half')
      else if (snap === 'half') setSnap('full')
    }
  }

  const selectedDistance = venue && userLocation
    ? calcDist(userLocation.lat, userLocation.lng, venue.location.lat, venue.location.lng)
    : undefined

  return (
    <AnimatePresence>
      {(venue || snap !== 'closed') && (
        <motion.div
          ref={sheetRef}
          initial={{ height: '0px' }}
          animate={{ height: snapToHeight[venue ? snap : 'closed'] }}
          exit={{ height: '0px' }}
          transition={{ type: 'spring', stiffness: 400, damping: 40 }}
          className="absolute bottom-0 left-0 right-0 z-30 bg-card/98 backdrop-blur-xl border-t border-border/50 rounded-t-2xl overflow-hidden"
          style={{ maxHeight: '85vh' }}
        >
          {/* Drag handle */}
          <motion.div
            className="flex justify-center pt-2 pb-1 cursor-grab active:cursor-grabbing touch-none"
            drag="y"
            dragConstraints={{ top: 0, bottom: 0 }}
            dragElastic={0}
            onDragEnd={handleDragEnd}
          >
            <div className="w-10 h-1 rounded-full bg-muted-foreground/30" />
          </motion.div>

          {/* Sheet header with toggle */}
          <div className="flex items-center justify-between px-4 pb-2">
            <button
              onClick={() => {
                if (snap === 'peek') setSnap('half')
                else if (snap === 'half') setSnap('full')
                else setSnap('half')
              }}
              className="flex items-center gap-1.5 text-xs font-bold text-muted-foreground hover:text-foreground transition-colors"
            >
              {snap === 'full' ? (
                <CaretDown size={14} weight="bold" />
              ) : (
                <CaretUp size={14} weight="bold" />
              )}
              {venue ? 'Selected Venue' : `${nearbyVenues.length} Nearby`}
            </button>
            {venue && (
              <button
                onClick={onClose}
                className="p-1 rounded-lg hover:bg-secondary transition-colors"
              >
                <X size={16} className="text-muted-foreground" />
              </button>
            )}
          </div>

          {/* Content */}
          <div className="overflow-y-auto" style={{ maxHeight: 'calc(85vh - 48px)' }}>
            {/* Selected venue preview */}
            {venue && (
              <div className="border-b border-border/30">
                <VenuePreviewCard
                  venue={venue}
                  distance={selectedDistance}
                  onViewDetails={() => onViewDetails(venue)}
                  unitSystem={unitSystem}
                />
              </div>
            )}

            {/* Nearby venues list (shown when expanded) */}
            {snap !== 'peek' && (
              <div className="px-4 py-3">
                <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-3">
                  {venue ? 'More Nearby' : 'Nearby Venues'}
                </h4>
                <div className="space-y-1">
                  {nearbyVenues
                    .filter(v => v.venue.id !== venue?.id)
                    .map(({ venue: v, distance }, i) => {
                      const VIcon = getCategoryIcon(v.category)
                      return (
                        <motion.button
                          key={v.id}
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          transition={{ delay: i * 0.03 }}
                          onClick={() => onVenueClick(v)}
                          className="w-full flex items-center gap-3 p-3 rounded-xl hover:bg-secondary/50 transition-colors text-left"
                        >
                          <div className={cn(
                            "w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0",
                            v.pulseScore >= 80 ? "bg-fuchsia-500/10 text-fuchsia-400" :
                            v.pulseScore >= 60 ? "bg-rose-500/10 text-rose-400" :
                            v.pulseScore >= 30 ? "bg-sky-500/10 text-sky-400" :
                            "bg-muted text-muted-foreground"
                          )}>
                            <VIcon size={18} weight="fill" />
                          </div>
                          <div className="flex-1 min-w-0">
                            <p className="font-semibold text-sm truncate">{v.name}</p>
                            <div className="flex items-center gap-2 mt-0.5">
                              {v.category && (
                                <span className="text-[10px] text-muted-foreground uppercase font-mono">
                                  {v.category}
                                </span>
                              )}
                              {distance !== undefined && (
                                <span className="text-[10px] text-muted-foreground font-mono">
                                  {formatDistance(distance, unitSystem)}
                                </span>
                              )}
                            </div>
                          </div>
                          <PulseScore score={v.pulseScore} size="xs" showLabel={false} />
                        </motion.button>
                      )
                    })}
                </div>
              </div>
            )}
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

import { useState, useMemo } from 'react'
import { Venue } from '@/lib/types'
import { VenueEvent } from '@/lib/events'
import {
  Ticket,
  TICKET_TYPE_CONFIG,
  getUpcomingTickets,
  getPastTickets,
  getRefundEligibility,
  requestRefund,
  applyRefund,
  initiateTransfer,
} from '@/lib/ticketing'
import {
  TableReservation,
  TABLE_LOCATION_CONFIG,
  getUpcomingReservations,
  getPastReservations,
  cancelReservation,
} from '@/lib/table-booking'
import { formatPrice } from '@/lib/payment-processing'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Card } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import {
  Ticket as TicketIcon,
  CaretLeft,
  QrCode,
  ArrowsLeftRight,
  ArrowCounterClockwise,
  CalendarBlank,
  MapPin,
  Clock,
  X,
} from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'
import { cn } from '@/lib/utils'

interface MyTicketsPageProps {
  currentUserId: string
  tickets: Ticket[]
  reservations: TableReservation[]
  events: VenueEvent[]
  venues: Venue[]
  onBack: () => void
  onTicketsUpdate: (tickets: Ticket[]) => void
  onReservationsUpdate: (reservations: TableReservation[]) => void
}

type TabFilter = 'upcoming' | 'past'

export function MyTicketsPage({
  currentUserId,
  tickets,
  reservations,
  events,
  venues,
  onBack,
  onTicketsUpdate,
  onReservationsUpdate,
}: MyTicketsPageProps) {
  const [tab, setTab] = useState<TabFilter>('upcoming')
  const [expandedTicketId, setExpandedTicketId] = useState<string | null>(null)
  const [showTransferDialog, setShowTransferDialog] = useState<string | null>(null)
  const [transferToUser, setTransferToUser] = useState('')

  const eventMap = useMemo(() => {
    const map = new Map<string, VenueEvent>()
    for (const e of events) map.set(e.id, e)
    return map
  }, [events])

  const venueMap = useMemo(() => {
    const map = new Map<string, Venue>()
    for (const v of venues) map.set(v.id, v)
    return map
  }, [venues])

  const eventsForTickets = useMemo(
    () => events.map(e => ({ id: e.id, startTime: e.startTime })),
    [events]
  )

  const upcomingTickets = useMemo(
    () => getUpcomingTickets(tickets, currentUserId, eventsForTickets),
    [tickets, currentUserId, eventsForTickets]
  )

  const pastTickets = useMemo(
    () => getPastTickets(tickets, currentUserId, eventsForTickets),
    [tickets, currentUserId, eventsForTickets]
  )

  const upcomingReservations = useMemo(
    () => getUpcomingReservations(reservations, currentUserId),
    [reservations, currentUserId]
  )

  const pastReservations = useMemo(
    () => getPastReservations(reservations, currentUserId),
    [reservations, currentUserId]
  )

  const currentTickets = tab === 'upcoming' ? upcomingTickets : pastTickets
  const currentReservations = tab === 'upcoming' ? upcomingReservations : pastReservations

  const handleRefund = (ticket: Ticket) => {
    const event = eventMap.get(ticket.eventId)
    if (!event) return

    const refundReq = requestRefund(ticket, event.startTime, 'User requested refund')
    if (refundReq.status === 'approved') {
      const updatedTickets = tickets.map(t =>
        t.id === ticket.id ? applyRefund(t) : t
      )
      onTicketsUpdate(updatedTickets)
    }
  }

  const handleTransfer = (ticket: Ticket) => {
    if (!transferToUser.trim()) return

    const result = initiateTransfer(ticket, transferToUser.trim(), ticket.price)
    if (result.success && result.ticket) {
      const updatedTickets = tickets.map(t =>
        t.id === ticket.id ? result.ticket! : t
      )
      onTicketsUpdate(updatedTickets)
      setShowTransferDialog(null)
      setTransferToUser('')
    }
  }

  const handleCancelReservation = (reservation: TableReservation) => {
    const updated = reservations.map(r =>
      r.id === reservation.id ? cancelReservation(r) : r
    )
    onReservationsUpdate(updated)
  }

  return (
    <div className="min-h-screen bg-background pb-20">
      {/* Header */}
      <div className="sticky top-0 z-30 bg-background/80 backdrop-blur-lg border-b border-border">
        <div className="flex items-center gap-3 px-4 py-3 max-w-2xl mx-auto">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-muted rounded-lg">
            <CaretLeft size={24} />
          </button>
          <div className="flex items-center gap-2">
            <TicketIcon size={24} weight="fill" className="text-primary" />
            <h1 className="text-xl font-bold">My Tickets</h1>
          </div>
        </div>

        {/* Tab Filter */}
        <div className="flex gap-2 px-4 pb-3 max-w-2xl mx-auto">
          {(['upcoming', 'past'] as const).map(f => (
            <button
              key={f}
              onClick={() => setTab(f)}
              className={cn(
                "px-4 py-1.5 rounded-full text-sm font-medium transition-all",
                tab === f
                  ? "bg-primary text-primary-foreground"
                  : "bg-card text-muted-foreground border border-border"
              )}
            >
              {f === 'upcoming' ? 'Upcoming' : 'Past'}
            </button>
          ))}
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-4 space-y-6">
        {/* Tickets Section */}
        {currentTickets.length > 0 && (
          <div className="space-y-3">
            <h2 className="font-bold text-sm uppercase tracking-wide text-muted-foreground">
              Tickets ({currentTickets.length})
            </h2>
            {currentTickets.map((ticket, i) => {
              const event = eventMap.get(ticket.eventId)
              const venue = venueMap.get(ticket.venueId)
              const config = TICKET_TYPE_CONFIG[ticket.type]
              const isExpanded = expandedTicketId === ticket.id
              const refundInfo = event ? getRefundEligibility(event.startTime) : null

              return (
                <motion.div
                  key={ticket.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.05 }}
                >
                  <Card
                    className={cn(
                      "overflow-hidden border transition-all",
                      isExpanded ? "border-primary" : "border-border"
                    )}
                  >
                    <button
                      onClick={() => setExpandedTicketId(isExpanded ? null : ticket.id)}
                      className="w-full text-left p-4"
                    >
                      <div className="flex items-start justify-between">
                        <div className="space-y-1 flex-1">
                          <div className="flex items-center gap-2">
                            <span className="text-lg">{config.emoji}</span>
                            <span className="font-bold">{event?.title || 'Event'}</span>
                          </div>
                          <p className="text-sm text-muted-foreground">
                            {venue?.name || 'Venue'}
                          </p>
                          {event && (
                            <div className="flex items-center gap-3 text-xs text-muted-foreground">
                              <span className="flex items-center gap-1">
                                <CalendarBlank size={12} />
                                {new Date(event.startTime).toLocaleDateString('en-US', {
                                  weekday: 'short',
                                  month: 'short',
                                  day: 'numeric',
                                })}
                              </span>
                              <span className="flex items-center gap-1">
                                <Clock size={12} />
                                {new Date(event.startTime).toLocaleTimeString('en-US', {
                                  hour: 'numeric',
                                  minute: '2-digit',
                                })}
                              </span>
                            </div>
                          )}
                        </div>
                        <div className="text-right shrink-0 ml-3">
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-xs",
                              ticket.status === 'purchased' && "border-green-500/30 text-green-400",
                              ticket.status === 'used' && "border-muted-foreground/30 text-muted-foreground",
                              ticket.status === 'refunded' && "border-red-500/30 text-red-400"
                            )}
                          >
                            {config.label}
                          </Badge>
                          <p className="font-bold mt-1">{formatPrice(ticket.price)}</p>
                        </div>
                      </div>
                    </button>

                    <AnimatePresence>
                      {isExpanded && (
                        <motion.div
                          initial={{ height: 0 }}
                          animate={{ height: 'auto' }}
                          exit={{ height: 0 }}
                          className="overflow-hidden"
                        >
                          <Separator />
                          <div className="p-4 space-y-4">
                            {/* QR Code placeholder */}
                            <div className="flex flex-col items-center py-4">
                              <div className="w-40 h-40 bg-white rounded-xl flex items-center justify-center">
                                <QrCode size={120} className="text-black" />
                              </div>
                              <p className="text-xs text-muted-foreground mt-2 font-mono">
                                {ticket.qrCode.slice(0, 20)}...
                              </p>
                            </div>

                            {/* Actions */}
                            {tab === 'upcoming' && ticket.status === 'purchased' && (
                              <div className="flex gap-2">
                                {ticket.transferable && ticket.transferHistory.length === 0 && (
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    className="flex-1"
                                    onClick={(e) => {
                                      e.stopPropagation()
                                      setShowTransferDialog(ticket.id)
                                    }}
                                  >
                                    <ArrowsLeftRight size={16} className="mr-2" />
                                    Transfer
                                  </Button>
                                )}
                                {refundInfo && refundInfo.eligible && (
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    className="flex-1"
                                    onClick={(e) => {
                                      e.stopPropagation()
                                      handleRefund(ticket)
                                    }}
                                  >
                                    <ArrowCounterClockwise size={16} className="mr-2" />
                                    Refund ({refundInfo.percentage}%)
                                  </Button>
                                )}
                              </div>
                            )}

                            {ticket.transferHistory.length > 0 && (
                              <p className="text-xs text-muted-foreground">
                                Transferred from {ticket.transferHistory[0].fromUserId}
                              </p>
                            )}
                          </div>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </Card>

                  {/* Transfer Dialog Inline */}
                  <AnimatePresence>
                    {showTransferDialog === ticket.id && (
                      <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        className="overflow-hidden"
                      >
                        <Card className="mt-2 p-4 border-primary/30 space-y-3">
                          <div className="flex items-center justify-between">
                            <h4 className="font-bold text-sm">Transfer Ticket</h4>
                            <button
                              onClick={() => {
                                setShowTransferDialog(null)
                                setTransferToUser('')
                              }}
                              className="p-1 hover:bg-secondary rounded"
                            >
                              <X size={16} />
                            </button>
                          </div>
                          <p className="text-xs text-muted-foreground">
                            Max transfer price: {formatPrice(ticket.originalPrice * 1.1)} (110% of original)
                          </p>
                          <input
                            type="text"
                            placeholder="Enter recipient user ID"
                            value={transferToUser}
                            onChange={(e) => setTransferToUser(e.target.value)}
                            className="w-full bg-secondary rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/30"
                          />
                          <Button
                            size="sm"
                            onClick={() => handleTransfer(ticket)}
                            disabled={!transferToUser.trim()}
                          >
                            Confirm Transfer
                          </Button>
                        </Card>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>
              )
            })}
          </div>
        )}

        {/* Table Reservations Section */}
        {currentReservations.length > 0 && (
          <>
            {currentTickets.length > 0 && <Separator />}
            <div className="space-y-3">
              <h2 className="font-bold text-sm uppercase tracking-wide text-muted-foreground">
                Table Reservations ({currentReservations.length})
              </h2>
              {currentReservations.map((reservation, i) => {
                const venue = venueMap.get(reservation.venueId)

                return (
                  <motion.div
                    key={reservation.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                  >
                    <Card className="p-4 border-border space-y-3">
                      <div className="flex items-start justify-between">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="font-bold">{venue?.name || 'Venue'}</span>
                            <Badge variant="outline" className="text-[10px]">
                              Table {reservation.tableNumber}
                            </Badge>
                          </div>
                          <div className="flex items-center gap-3 text-xs text-muted-foreground">
                            <span className="flex items-center gap-1">
                              <CalendarBlank size={12} />
                              {new Date(reservation.date).toLocaleDateString('en-US', {
                                weekday: 'short',
                                month: 'short',
                                day: 'numeric',
                              })}
                            </span>
                            <span className="flex items-center gap-1">
                              <Clock size={12} />
                              {reservation.timeSlot.label}
                            </span>
                          </div>
                          <div className="flex items-center gap-3 text-xs text-muted-foreground">
                            <span className="flex items-center gap-1">
                              <MapPin size={12} />
                              {reservation.partySize} guests
                            </span>
                          </div>
                        </div>
                        <div className="text-right shrink-0 ml-3">
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-xs",
                              reservation.status === 'confirmed' && "border-green-500/30 text-green-400",
                              reservation.status === 'completed' && "border-muted-foreground/30 text-muted-foreground",
                              reservation.status === 'cancelled' && "border-red-500/30 text-red-400"
                            )}
                          >
                            {reservation.status}
                          </Badge>
                          <p className="text-xs text-muted-foreground mt-1">Min spend</p>
                          <p className="font-bold">{formatPrice(reservation.minimumSpend)}</p>
                        </div>
                      </div>

                      {/* QR Code for upcoming */}
                      {tab === 'upcoming' && reservation.status === 'confirmed' && (
                        <div className="flex items-center justify-between pt-2 border-t border-border">
                          <div className="flex items-center gap-2">
                            <QrCode size={20} className="text-primary" />
                            <span className="text-xs text-muted-foreground font-mono">
                              {reservation.qrCode.slice(0, 16)}...
                            </span>
                          </div>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleCancelReservation(reservation)}
                          >
                            Cancel
                          </Button>
                        </div>
                      )}

                      {reservation.specialRequests && (
                        <p className="text-xs text-muted-foreground italic">
                          Note: {reservation.specialRequests}
                        </p>
                      )}
                    </Card>
                  </motion.div>
                )
              })}
            </div>
          </>
        )}

        {/* Empty State */}
        {currentTickets.length === 0 && currentReservations.length === 0 && (
          <div className="text-center py-12 space-y-3">
            <TicketIcon size={48} className="mx-auto text-muted-foreground/50" />
            <p className="text-muted-foreground">
              {tab === 'upcoming' ? 'No upcoming tickets or reservations' : 'No past tickets or reservations'}
            </p>
            <p className="text-sm text-muted-foreground/70">
              {tab === 'upcoming'
                ? 'Get tickets for events or reserve tables at your favorite venues'
                : 'Your ticket and reservation history will appear here'}
            </p>
          </div>
        )}
      </div>
    </div>
  )
}

import { useEffect, useMemo } from 'react'
import { Venue, Pulse } from '@/lib/types'
import { Neighborhood, NeighborhoodScore, getNeighborhoodLeaderboard, getHottestNeighborhood, assignVenueToNeighborhood } from '@/lib/neighborhood-scores'
import { CaretLeft, MapTrifold, Crown, TrendUp } from '@phosphor-icons/react'
import { motion } from 'framer-motion'
import { trackEvent } from '@/lib/analytics'

interface NeighborhoodViewProps {
  venues: Venue[]
  pulses: Pulse[]
  onBack: () => void
  onVenueClick: (venue: Venue) => void
}

function buildNeighborhoods(venues: Venue[]): Neighborhood[] {
  // Group venues by city and create neighborhoods
  const cityVenues: Record<string, Venue[]> = {}
  for (const v of venues) {
    const city = v.city || 'Unknown'
    if (!cityVenues[city]) cityVenues[city] = []
    cityVenues[city].push(v)
  }

  return Object.entries(cityVenues).map(([city, vList]) => {
    const lats = vList.map(v => v.location.lat)
    const lngs = vList.map(v => v.location.lng)
    return {
      id: `n-${city.toLowerCase().replace(/\s/g, '-')}`,
      name: city,
      city,
      bounds: {
        north: Math.max(...lats) + 0.01,
        south: Math.min(...lats) - 0.01,
        east: Math.max(...lngs) + 0.01,
        west: Math.min(...lngs) - 0.01,
      },
      venueIds: vList.map(v => v.id),
    }
  })
}

export function NeighborhoodView({ venues, pulses, onBack, onVenueClick }: NeighborhoodViewProps) {
  const neighborhoods = useMemo(() => buildNeighborhoods(venues), [venues])

  const leaderboard = useMemo(
    () => getNeighborhoodLeaderboard(neighborhoods, venues, pulses),
    [neighborhoods, venues, pulses]
  )

  const hottest = useMemo(
    () => getHottestNeighborhood(neighborhoods, venues, pulses),
    [neighborhoods, venues, pulses]
  )

  const hottestVenues = useMemo(() => {
    if (!hottest) return []
    const n = neighborhoods.find(n => n.id === hottest.neighborhoodId)
    if (!n) return []
    return venues.filter(v => n.venueIds.includes(v.id)).sort((a, b) => b.pulseScore - a.pulseScore).slice(0, 5)
  }, [hottest, neighborhoods, venues])

  useEffect(() => {
    trackEvent({
      type: 'neighborhood_view',
      timestamp: Date.now(),
      neighborhoodCount: neighborhoods.length,
    })
  }, [neighborhoods.length])

  const handleVenueClick = (venue: Venue) => {
    const neighborhood = assignVenueToNeighborhood(venue, neighborhoods)
    if (neighborhood) {
      trackEvent({
        type: 'neighborhood_venue_click',
        timestamp: Date.now(),
        neighborhoodId: neighborhood.id,
        venueId: venue.id,
      })
    }
    onVenueClick(venue)
  }

  return (
    <div className="min-h-screen bg-background pb-20">
      <div className="sticky top-0 z-30 bg-background/80 backdrop-blur-lg border-b border-border">
        <div className="flex items-center gap-3 px-4 py-3 max-w-2xl mx-auto">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-muted rounded-lg">
            <CaretLeft size={24} />
          </button>
          <div className="flex items-center gap-2">
            <MapTrifold size={24} weight="fill" className="text-primary" />
            <h1 className="text-xl font-bold">Neighborhoods</h1>
          </div>
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
        {hottest && hottest.score > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-gradient-to-r from-orange-500/20 to-red-500/20 rounded-2xl p-6 border border-orange-500/30"
          >
            <div className="flex items-center gap-2 mb-2">
              <Crown size={20} weight="fill" className="text-orange-400" />
              <span className="text-sm font-medium text-orange-400">Hottest Right Now</span>
            </div>
            <h2 className="text-2xl font-bold">{hottest.name}</h2>
            <p className="text-sm text-muted-foreground">{hottest.city}</p>
            <div className="flex items-center gap-4 mt-3">
              <div>
                <p className="text-lg font-bold text-orange-400">{Math.round(hottest.score)}</p>
                <p className="text-xs text-muted-foreground">Energy Score</p>
              </div>
              <div>
                <p className="text-lg font-bold">{hottest.activeVenueCount}</p>
                <p className="text-xs text-muted-foreground">Active Venues</p>
              </div>
              <div>
                <p className="text-lg font-bold">{hottest.totalVenues}</p>
                <p className="text-xs text-muted-foreground">Total Venues</p>
              </div>
            </div>
          </motion.div>
        )}

        <div className="space-y-3">
          <h2 className="text-lg font-bold">Neighborhood Leaderboard</h2>
          {leaderboard.map((ns, i) => (
            <motion.div
              key={ns.neighborhoodId}
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: i * 0.05 }}
              className="bg-card rounded-xl p-4 border border-border flex items-center gap-4"
            >
              <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${
                i === 0 ? 'bg-orange-500/20 text-orange-400' :
                i === 1 ? 'bg-gray-400/20 text-gray-400' :
                i === 2 ? 'bg-amber-700/20 text-amber-600' :
                'bg-muted text-muted-foreground'
              }`}>
                {i + 1}
              </div>
              <div className="flex-1">
                <p className="font-medium">{ns.name}</p>
                <p className="text-xs text-muted-foreground">{ns.city} · {ns.activeVenueCount} active</p>
              </div>
              <div className="text-right">
                <p className="font-bold text-primary">{Math.round(ns.score)}</p>
                {ns.hottest && (
                  <span className="text-[10px] text-orange-400 font-medium flex items-center gap-0.5 justify-end">
                    <TrendUp size={10} /> HOT
                  </span>
                )}
              </div>
            </motion.div>
          ))}
        </div>

        {hottestVenues.length > 0 && hottest && (
          <div className="space-y-3">
            <h2 className="text-lg font-bold">Top in {hottest.name}</h2>
            {hottestVenues.map((venue, i) => (
              <button
                key={venue.id}
                onClick={() => {
                  if (hottest) {
                    trackEvent({
                      type: 'neighborhood_hottest_click',
                      timestamp: Date.now(),
                      neighborhoodId: hottest.neighborhoodId,
                      city: hottest.city,
                    })
                  }
                  handleVenueClick(venue)
                }}
                className="w-full bg-card rounded-xl p-3 border border-border flex items-center gap-3 hover:border-primary/50 transition-colors text-left"
              >
                <span className="text-sm font-bold text-muted-foreground w-6">{i + 1}</span>
                <div className="flex-1">
                  <p className="font-medium text-sm">{venue.name}</p>
                  <p className="text-xs text-muted-foreground">{venue.category}</p>
                </div>
                <div className="text-right">
                  <p className="font-bold text-sm text-primary">{Math.round(venue.pulseScore)}</p>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

import { useState, useMemo } from 'react'
import type { Venue, Pulse, User, EnergyRating } from '@/lib/types'
import { ENERGY_CONFIG } from '@/lib/types'
import type { Crew } from '@/lib/crew-mode'
import { getUserCrews } from '@/lib/crew-mode'
import {
  generateNightPlan,
  getTotalEstimatedSpend,
  PLANNER_VIBES,
  VENUE_TYPES,
} from '@/lib/night-planner'
import type { NightPlan, PlanStop, PlanPreferences } from '@/lib/night-planner'
import { LivePlanTracker } from '@/components/LivePlanTracker'
import { CaretLeft, UsersThree, Sparkle, CurrencyDollar, Clock, ArrowsClockwise, LockSimple, ShareNetwork, MapPin, Car, PersonSimpleWalk } from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'
import { Slider } from '@/components/ui/slider'
import { Separator } from '@/components/ui/separator'
import { toast } from 'sonner'

type PlannerStep = 'who' | 'vibe' | 'budget' | 'plan'

interface NightPlannerPageProps {
  currentUser: User
  allUsers: User[]
  venues: Venue[]
  pulses: Pulse[]
  crews: Crew[]
  userLocation?: { lat: number; lng: number } | null
  onBack: () => void
  onVenueClick: (venue: Venue) => void
}

export function NightPlannerPage({
  currentUser,
  allUsers,
  venues,
  pulses,
  crews,
  userLocation,
  onBack,
  onVenueClick,
}: NightPlannerPageProps) {
  const [step, setStep] = useState<PlannerStep>('who')
  const [groupSize, setGroupSize] = useState(2)
  const [selectedCrewId, setSelectedCrewId] = useState<string | null>(null)
  const [selectedVibes, setSelectedVibes] = useState<string[]>([])
  const [selectedVenueTypes, setSelectedVenueTypes] = useState<string[]>([])
  const [budget, setBudget] = useState(100)
  const [startHour, setStartHour] = useState(20)
  const [endHour, setEndHour] = useState(2)
  const [generatedPlan, setGeneratedPlan] = useState<NightPlan | null>(null)
  const [lockedStops, setLockedStops] = useState<Set<number>>(new Set())
  const [showTracker, setShowTracker] = useState(false)

  const userCrews = useMemo(
    () => getUserCrews(crews, currentUser.id),
    [crews, currentUser.id]
  )

  const handleVibeToggle = (vibeId: string) => {
    setSelectedVibes(prev =>
      prev.includes(vibeId) ? prev.filter(v => v !== vibeId) : [...prev, vibeId]
    )
  }

  const handleVenueTypeToggle = (typeId: string) => {
    setSelectedVenueTypes(prev =>
      prev.includes(typeId) ? prev.filter(t => t !== typeId) : [...prev, typeId]
    )
  }

  const handleCrewSelect = (crewId: string) => {
    if (selectedCrewId === crewId) {
      setSelectedCrewId(null)
      setGroupSize(2)
    } else {
      const crew = crews.find(c => c.id === crewId)
      if (crew) {
        setSelectedCrewId(crewId)
        setGroupSize(crew.memberIds.length)
      }
    }
  }

  const buildStartTime = (): string => {
    const now = new Date()
    const date = new Date(now)
    date.setHours(startHour, 0, 0, 0)
    if (startHour < 12 && now.getHours() >= 12) {
      // If start is AM and current is PM, it's tomorrow
      date.setDate(date.getDate() + 1)
    }
    return date.toISOString()
  }

  const buildEndTime = (): string => {
    const start = new Date(buildStartTime())
    const end = new Date(start)
    end.setHours(endHour, 0, 0, 0)
    if (endHour <= startHour) {
      // End is next day
      end.setDate(end.getDate() + 1)
    }
    return end.toISOString()
  }

  const handleGenerate = () => {
    const location = userLocation ?? { lat: 40.7128, lng: -74.006 }

    const preferences: PlanPreferences = {
      vibes: selectedVibes,
      musicGenres: [],
      venueTypes: selectedVenueTypes,
      avoidCategories: [],
    }

    const locked = generatedPlan
      ? generatedPlan.stops.filter((_, i) => lockedStops.has(i))
      : undefined

    const plan = generateNightPlan(
      {
        groupSize,
        budget,
        preferences,
        location,
        startTime: buildStartTime(),
        endTime: buildEndTime(),
        userId: currentUser.id,
        crewId: selectedCrewId ?? undefined,
        lockedStops: locked,
      },
      venues,
      pulses,
      currentUser
    )

    setGeneratedPlan(plan)
    setStep('plan')
  }

  const handleShuffle = () => {
    // Keep locked stops, regenerate others
    handleGenerate()
    toast.success('Plan shuffled!')
  }

  const handleToggleLock = (index: number) => {
    setLockedStops(prev => {
      const next = new Set(prev)
      if (next.has(index)) {
        next.delete(index)
      } else {
        next.add(index)
      }
      return next
    })
  }

  const handleSharePlan = () => {
    toast.success('Plan shared with your crew!')
  }

  const handleActivatePlan = () => {
    if (generatedPlan) {
      setGeneratedPlan({ ...generatedPlan, status: 'active' })
      setShowTracker(true)
    }
  }

  const formatHour = (h: number): string => {
    if (h === 0 || h === 24) return '12 AM'
    if (h === 12) return '12 PM'
    if (h > 12) return `${h - 12} PM`
    return `${h} AM`
  }

  const formatTime = (iso: string): string => {
    return new Date(iso).toLocaleTimeString('en-US', {
      hour: 'numeric',
      minute: '2-digit',
    })
  }

  if (showTracker && generatedPlan) {
    return (
      <LivePlanTracker
        plan={generatedPlan}
        venues={venues}
        pulses={pulses}
        currentUser={currentUser}
        onBack={() => setShowTracker(false)}
        onVenueClick={onVenueClick}
      />
    )
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="sticky top-0 z-20 bg-background/95 backdrop-blur-md border-b border-border">
        <div className="max-w-2xl mx-auto px-4 py-3 flex items-center gap-3">
          <button onClick={step === 'who' ? onBack : () => {
            const steps: PlannerStep[] = ['who', 'vibe', 'budget', 'plan']
            const idx = steps.indexOf(step)
            if (idx > 0) setStep(steps[idx - 1])
          }} className="p-1">
            <CaretLeft size={24} weight="bold" />
          </button>
          <div className="flex-1">
            <h1 className="font-bold text-lg flex items-center gap-2">
              <Sparkle size={22} weight="fill" className="text-primary" />
              Night Planner
            </h1>
          </div>
          {/* Step indicator */}
          <div className="flex gap-1.5">
            {(['who', 'vibe', 'budget', 'plan'] as PlannerStep[]).map((s, i) => (
              <div
                key={s}
                className={`w-2 h-2 rounded-full transition-colors ${
                  s === step ? 'bg-primary' : i < ['who', 'vibe', 'budget', 'plan'].indexOf(step) ? 'bg-primary/50' : 'bg-muted'
                }`}
              />
            ))}
          </div>
        </div>
      </div>

      <div className="max-w-2xl mx-auto px-4 py-6">
        <AnimatePresence mode="wait">
          {step === 'who' && (
            <motion.div
              key="who"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="space-y-6"
            >
              <div>
                <h2 className="text-2xl font-bold mb-1">Who's Coming?</h2>
                <p className="text-muted-foreground text-sm">Select your crew or set group size</p>
              </div>

              {/* Crew Selection */}
              {userCrews.length > 0 && (
                <div className="space-y-3">
                  <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Your Crews</h3>
                  <div className="space-y-2">
                    {userCrews.map(crew => (
                      <motion.button
                        key={crew.id}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => handleCrewSelect(crew.id)}
                        className={`w-full p-4 rounded-xl border text-left transition-colors ${
                          selectedCrewId === crew.id
                            ? 'bg-primary/10 border-primary/50'
                            : 'bg-card border-border hover:border-primary/30'
                        }`}
                      >
                        <div className="flex items-center gap-3">
                          <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                            selectedCrewId === crew.id ? 'bg-primary/20' : 'bg-muted'
                          }`}>
                            <UsersThree size={20} weight="fill" className={selectedCrewId === crew.id ? 'text-primary' : 'text-muted-foreground'} />
                          </div>
                          <div className="flex-1">
                            <p className="font-medium">{crew.name}</p>
                            <p className="text-xs text-muted-foreground">{crew.memberIds.length} members</p>
                          </div>
                          {selectedCrewId === crew.id && (
                            <div className="w-5 h-5 rounded-full bg-primary flex items-center justify-center">
                              <span className="text-xs text-primary-foreground font-bold">&#10003;</span>
                            </div>
                          )}
                        </div>
                      </motion.button>
                    ))}
                  </div>
                </div>
              )}

              {/* Manual Group Size */}
              <div className="space-y-3">
                <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">
                  {userCrews.length > 0 ? 'Or set group size' : 'Group Size'}
                </h3>
                <div className="flex items-center gap-3">
                  {[1, 2, 3, 4, 5, 6, 7, 8].map(n => (
                    <motion.button
                      key={n}
                      whileTap={{ scale: 0.9 }}
                      onClick={() => { setGroupSize(n); setSelectedCrewId(null) }}
                      className={`w-10 h-10 rounded-full font-bold text-sm transition-colors ${
                        groupSize === n && !selectedCrewId
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-card border border-border text-foreground hover:border-primary/30'
                      }`}
                    >
                      {n}
                    </motion.button>
                  ))}
                </div>
              </div>

              <motion.button
                whileTap={{ scale: 0.97 }}
                onClick={() => setStep('vibe')}
                className="w-full py-3 rounded-xl bg-primary text-primary-foreground font-bold text-sm"
              >
                Next: Set the Vibe
              </motion.button>
            </motion.div>
          )}

          {step === 'vibe' && (
            <motion.div
              key="vibe"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="space-y-6"
            >
              <div>
                <h2 className="text-2xl font-bold mb-1">What's the Vibe?</h2>
                <p className="text-muted-foreground text-sm">Pick your mood for tonight</p>
              </div>

              {/* Vibe Pills */}
              <div className="space-y-3">
                <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Mood</h3>
                <div className="flex flex-wrap gap-2">
                  {PLANNER_VIBES.map(vibe => (
                    <motion.button
                      key={vibe.id}
                      whileTap={{ scale: 0.95 }}
                      onClick={() => handleVibeToggle(vibe.id)}
                      className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                        selectedVibes.includes(vibe.id)
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-card border border-border text-foreground hover:border-primary/30'
                      }`}
                    >
                      {vibe.emoji} {vibe.label}
                    </motion.button>
                  ))}
                </div>
              </div>

              <Separator />

              {/* Venue Types */}
              <div className="space-y-3">
                <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Venue Types</h3>
                <div className="flex flex-wrap gap-2">
                  {VENUE_TYPES.map(type => (
                    <motion.button
                      key={type.id}
                      whileTap={{ scale: 0.95 }}
                      onClick={() => handleVenueTypeToggle(type.id)}
                      className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                        selectedVenueTypes.includes(type.id)
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-card border border-border text-foreground hover:border-primary/30'
                      }`}
                    >
                      {type.label}
                    </motion.button>
                  ))}
                </div>
              </div>

              <motion.button
                whileTap={{ scale: 0.97 }}
                onClick={() => setStep('budget')}
                className="w-full py-3 rounded-xl bg-primary text-primary-foreground font-bold text-sm"
              >
                Next: Budget & Time
              </motion.button>
            </motion.div>
          )}

          {step === 'budget' && (
            <motion.div
              key="budget"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="space-y-6"
            >
              <div>
                <h2 className="text-2xl font-bold mb-1">Budget & Time</h2>
                <p className="text-muted-foreground text-sm">Set your spending and schedule</p>
              </div>

              {/* Budget Slider */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Budget per Person</h3>
                  <span className="text-xl font-bold text-primary">${budget}</span>
                </div>
                <Slider
                  value={[budget]}
                  onValueChange={([val]) => setBudget(val)}
                  min={50}
                  max={500}
                  step={10}
                  className="w-full"
                />
                <div className="flex justify-between text-xs text-muted-foreground">
                  <span>$50</span>
                  <span>$500</span>
                </div>
                <p className="text-sm text-muted-foreground">
                  Total for {groupSize} people: <span className="font-bold text-foreground">${budget * groupSize}</span>
                </p>
              </div>

              <Separator />

              {/* Time Selection */}
              <div className="space-y-4">
                <h3 className="font-semibold text-sm text-muted-foreground uppercase tracking-wide">Time Window</h3>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-sm text-muted-foreground flex items-center gap-1">
                      <Clock size={14} />
                      Start Time
                    </label>
                    <select
                      value={startHour}
                      onChange={e => setStartHour(Number(e.target.value))}
                      className="w-full bg-card border border-border rounded-lg px-3 py-2 text-sm"
                    >
                      {Array.from({ length: 12 }, (_, i) => i + 16).map(h => {
                        const displayH = h > 23 ? h - 24 : h
                        return (
                          <option key={h} value={displayH}>{formatHour(displayH)}</option>
                        )
                      })}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm text-muted-foreground flex items-center gap-1">
                      <Clock size={14} />
                      End Time
                    </label>
                    <select
                      value={endHour}
                      onChange={e => setEndHour(Number(e.target.value))}
                      className="w-full bg-card border border-border rounded-lg px-3 py-2 text-sm"
                    >
                      {[22, 23, 0, 1, 2, 3, 4].map(h => (
                        <option key={h} value={h}>{formatHour(h)}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              <motion.button
                whileTap={{ scale: 0.97 }}
                onClick={handleGenerate}
                className="w-full py-3 rounded-xl bg-primary text-primary-foreground font-bold text-sm flex items-center justify-center gap-2"
              >
                <Sparkle size={18} weight="fill" />
                Generate Night Plan
              </motion.button>
            </motion.div>
          )}

          {step === 'plan' && generatedPlan && (
            <motion.div
              key="plan"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="space-y-6"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-bold mb-1">Your Night Plan</h2>
                  <p className="text-muted-foreground text-sm">
                    {generatedPlan.stops.length} stops &middot; {groupSize} people &middot; ~${getTotalEstimatedSpend(generatedPlan)}/person
                  </p>
                </div>
                <div className="flex gap-2">
                  <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={handleShuffle}
                    className="p-2 rounded-lg bg-card border border-border hover:border-primary/30"
                    title="Shuffle plan"
                  >
                    <ArrowsClockwise size={20} />
                  </motion.button>
                  <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={handleSharePlan}
                    className="p-2 rounded-lg bg-card border border-border hover:border-primary/30"
                    title="Share plan"
                  >
                    <ShareNetwork size={20} />
                  </motion.button>
                </div>
              </div>

              {/* Timeline */}
              <div className="relative">
                {generatedPlan.stops.map((stop, i) => (
                  <div key={`${stop.venueId}-${i}`}>
                    {/* Transit indicator (between stops) */}
                    {i > 0 && (
                      <TransitIndicator stop={stop} />
                    )}
                    {/* Stop card */}
                    <StopCard
                      stop={stop}
                      index={i}
                      isLocked={lockedStops.has(i)}
                      onToggleLock={() => handleToggleLock(i)}
                      onVenueClick={() => {
                        const venue = venues.find(v => v.id === stop.venueId)
                        if (venue) onVenueClick(venue)
                      }}
                      formatTime={formatTime}
                    />
                  </div>
                ))}
              </div>

              {/* Total */}
              <div className="bg-card rounded-xl p-4 border border-border">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-muted-foreground">Total Estimated Cost</span>
                  <div className="text-right">
                    <p className="font-bold text-lg">${getTotalEstimatedSpend(generatedPlan) * groupSize}</p>
                    <p className="text-xs text-muted-foreground">${getTotalEstimatedSpend(generatedPlan)} per person</p>
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="space-y-3">
                <motion.button
                  whileTap={{ scale: 0.97 }}
                  onClick={handleActivatePlan}
                  className="w-full py-3 rounded-xl bg-primary text-primary-foreground font-bold text-sm flex items-center justify-center gap-2"
                >
                  <Sparkle size={18} weight="fill" />
                  Start This Night
                </motion.button>
                <motion.button
                  whileTap={{ scale: 0.97 }}
                  onClick={handleShuffle}
                  className="w-full py-3 rounded-xl bg-card border border-border text-foreground font-bold text-sm flex items-center justify-center gap-2"
                >
                  <ArrowsClockwise size={18} />
                  Shuffle Plan
                </motion.button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  )
}

function StopCard({
  stop,
  index,
  isLocked,
  onToggleLock,
  onVenueClick,
  formatTime,
}: {
  stop: PlanStop
  index: number
  isLocked: boolean
  onToggleLock: () => void
  onVenueClick: () => void
  formatTime: (iso: string) => string
}) {
  const purposeLabels: Record<string, string> = {
    dinner: 'Dinner',
    drinks: 'Drinks',
    dancing: 'Dancing',
    latenight: 'Late Night',
  }

  const purposeColors: Record<string, string> = {
    dinner: 'from-orange-500/20 to-amber-500/20 border-orange-500/20',
    drinks: 'from-blue-500/20 to-cyan-500/20 border-blue-500/20',
    dancing: 'from-purple-500/20 to-pink-500/20 border-purple-500/20',
    latenight: 'from-indigo-500/20 to-violet-500/20 border-indigo-500/20',
  }

  const energyConfig = ENERGY_CONFIG[stop.energyPrediction]

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.1 }}
      className="relative"
    >
      {/* Timeline dot */}
      <div className="flex gap-3">
        <div className="flex flex-col items-center">
          <div className="w-8 h-8 rounded-full bg-primary/20 border-2 border-primary flex items-center justify-center text-xs font-bold text-primary">
            {index + 1}
          </div>
          {/* Timeline line continues below via TransitIndicator */}
        </div>

        <div className={`flex-1 bg-gradient-to-br ${purposeColors[stop.purpose] ?? purposeColors.drinks} rounded-xl p-4 border mb-2`}>
          <div className="flex items-start justify-between mb-2">
            <div>
              <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                {purposeLabels[stop.purpose] ?? stop.purpose}
              </span>
              <button onClick={onVenueClick} className="block">
                <h3 className="font-bold text-base hover:text-primary transition-colors">{stop.venueName}</h3>
              </button>
            </div>
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={onToggleLock}
              className={`p-1.5 rounded-lg transition-colors ${
                isLocked ? 'bg-primary/20 text-primary' : 'text-muted-foreground hover:text-foreground'
              }`}
              title={isLocked ? 'Unlock this stop' : 'Lock this stop'}
            >
              <LockSimple size={16} weight={isLocked ? 'fill' : 'regular'} />
            </motion.button>
          </div>

          <div className="flex items-center gap-4 text-sm text-muted-foreground mb-2">
            <span className="flex items-center gap-1">
              <Clock size={14} />
              {formatTime(stop.arrivalTime)} - {formatTime(stop.departureTime)}
            </span>
            <span className="flex items-center gap-1">
              <CurrencyDollar size={14} />
              ~${stop.estimatedSpend}
            </span>
          </div>

          <div className="flex items-center gap-2">
            <div
              className="px-2 py-0.5 rounded-full text-xs font-medium"
              style={{
                backgroundColor: `${energyConfig.color}22`,
                color: energyConfig.color,
              }}
            >
              {energyConfig.emoji} {energyConfig.label}
            </div>
            {stop.venueCategory && (
              <span className="text-xs text-muted-foreground">
                {stop.venueCategory}
              </span>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  )
}

function TransitIndicator({ stop }: { stop: PlanStop }) {
  const isWalk = stop.transitMode === 'walk'

  return (
    <div className="flex gap-3 mb-2">
      <div className="flex flex-col items-center">
        <div className="w-px h-8 bg-border" />
      </div>
      <div className="flex items-center gap-2 text-xs text-muted-foreground py-1">
        {isWalk ? (
          <PersonSimpleWalk size={14} />
        ) : (
          <Car size={14} />
        )}
        <span>{stop.transitDuration} min {isWalk ? 'walk' : 'ride'}</span>
        {stop.transitDeepLink && !isWalk && (
          <a
            href={stop.transitDeepLink}
            target="_blank"
            rel="noopener noreferrer"
            className="text-primary font-medium hover:underline"
            onClick={e => e.stopPropagation()}
          >
            Open Uber
          </a>
        )}
      </div>
    </div>
  )
}

