export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, dispatch] = useReducer(toastReducer, [])
  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map())

  const dismiss = useCallback((id: string) => {
    const timer = timersRef.current.get(id)
    if (timer) {
      clearTimeout(timer)
      timersRef.current.delete(id)
    }
    dispatch({ type: 'DISMISS', id })
  }, [])

  const addToast = useCallback(
    (input: ToastInput): string => {
      const id = `toast-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
      const newToast: Toast = { ...input, id }

      dispatch({ type: 'ADD', toast: newToast })

      const duration = input.duration ?? DEFAULT_DURATION
      const timer = setTimeout(() => {
        timersRef.current.delete(id)
        dispatch({ type: 'DISMISS', id })
      }, duration)
      timersRef.current.set(id, timer)

      return id
    },
    [],
  )

  const contextValue = useMemo<ToastContextValue>(
    () => ({ toast: addToast, dismiss }),
    [addToast, dismiss],
  )

  const visibleToasts = toasts.slice(0, MAX_VISIBLE)

  return (
    <ToastContext.Provider value={contextValue}>
      {children}

      {/* Surge pulse keyframe — injected once */}
      <style>{`
        @keyframes surge-pulse {
          0%, 100% { box-shadow: 0 0 15px rgba(168,85,247,0.3); }
          50% { box-shadow: 0 0 30px rgba(168,85,247,0.55), 0 0 60px rgba(168,85,247,0.2); }
        }
      `}</style>

      {/* Toast viewport */}
      <div
        aria-label="Notifications"
        className="pointer-events-none fixed inset-x-0 top-0 z-50"
      >
        <div className="pointer-events-auto">
          <AnimatePresence mode="popLayout">
            {visibleToasts.map((t, i) => (
              <ToastItem key={t.id} toast={t} index={i} onDismiss={dismiss} />
            ))}
          </AnimatePresence>
        </div>
      </div>
    </ToastContext.Provider>
  )
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { cn } from '@/lib/utils'
import { MapPin, Lightning, Users, TrendUp } from '@phosphor-icons/react'
import { motion, AnimatePresence } from 'framer-motion'

interface VenueActivityStreamProps {
  venueId: string
  venueName: string
}

interface ActivityItem {
  id: string
  text: string
  timestamp: string
  type: 'checkin' | 'rating' | 'arrival' | 'energy'
  avatarColor: string
  avatarInitial: string
}

const FIRST_NAMES = [
  'Sarah', 'Mike', 'Emma', 'Jake', 'Olivia', 'Liam', 'Ava', 'Noah',
  'Mia', 'Alex', 'Chloe', 'Ryan', 'Zoe', 'Tyler', 'Luna', 'Kai',
]

const RATING_WORDS = ['Electric', 'Buzzing', 'Vibing', 'Chill', 'Fire']

const AVATAR_COLORS = [
  'bg-gradient-to-br from-violet-400 to-purple-600',
  'bg-gradient-to-br from-pink-400 to-rose-600',
  'bg-gradient-to-br from-blue-400 to-indigo-600',
  'bg-gradient-to-br from-emerald-400 to-teal-600',
  'bg-gradient-to-br from-amber-400 to-orange-600',
  'bg-gradient-to-br from-cyan-400 to-blue-600',
  'bg-gradient-to-br from-fuchsia-400 to-pink-600',
]

function getActivityIcon(type: ActivityItem['type']) {
  switch (type) {
    case 'checkin':
      return <MapPin size={12} weight="fill" className="text-green-400" />
    case 'rating':
      return <Lightning size={12} weight="fill" className="text-yellow-400" />
    case 'arrival':
      return <Users size={12} weight="fill" className="text-blue-400" />
    case 'energy':
      return <TrendUp size={12} weight="fill" className="text-orange-400" />
  }
}

function createSeededRandom(seed: string) {
  let s = 0
  for (let i = 0; i < seed.length; i++) {
    s = ((s << 5) - s + seed.charCodeAt(i)) | 0
  }
  return () => {
    s = (s * 16807 + 0) % 2147483647
    return (s & 0x7fffffff) / 2147483647
  }
}

function generateActivity(venueId: string, index: number): ActivityItem {
  const random = createSeededRandom(venueId + index.toString())
  const types: ActivityItem['type'][] = ['checkin', 'rating', 'arrival', 'energy']
  const type = types[Math.floor(random() * types.length)]
  const name = FIRST_NAMES[Math.floor(random() * FIRST_NAMES.length)]
  const color = AVATAR_COLORS[Math.floor(random() * AVATAR_COLORS.length)]

  const minutesAgo = Math.floor(random() * 10) + 1

  let text: string
  switch (type) {
    case 'checkin':
      text = `${name} checked in ${minutesAgo}m ago`
      break
    case 'rating':
      text = `${name} rated it ${RATING_WORDS[Math.floor(random() * RATING_WORDS.length)]} ${String.fromCodePoint(0x26A1)}`
      break
    case 'arrival':
      text = `${Math.floor(random() * 5) + 2} new people arrived`
      break
    case 'energy':
      text = 'Energy just went up!'
      break
  }

  return {
    id: `${venueId}-activity-${index}-${Date.now()}`,
    text,
    timestamp: `${minutesAgo}m`,
    type,
    avatarColor: color,
    avatarInitial: type === 'arrival' || type === 'energy' ? '' : name[0],
  }
}

export function VenueActivityStream({ venueId, venueName }: VenueActivityStreamProps) {
  const maxVisible = 4
  const activityCounter = useRef(0)

  const [activities, setActivities] = useState<ActivityItem[]>(() => {
    const initial: ActivityItem[] = []
    for (let i = 0; i < maxVisible; i++) {
      initial.push(generateActivity(venueId, activityCounter.current++))
    }
    return initial
  })

  const addActivity = useCallback(() => {
    const newItem = generateActivity(venueId, activityCounter.current++)
    setActivities((prev) => {
      const updated = [newItem, ...prev]
      return updated.slice(0, maxVisible)
    })
  }, [venueId])

  useEffect(() => {
    const interval = setInterval(addActivity, 8000)
    return () => clearInterval(interval)
  }, [addActivity])

  // Reset when venue changes
  useEffect(() => {
    activityCounter.current = 0
    const initial: ActivityItem[] = []
    for (let i = 0; i < maxVisible; i++) {
      initial.push(generateActivity(venueId, activityCounter.current++))
    }
    setActivities(initial)
  }, [venueId])

  return (
    <div className="space-y-1">
      <div className="flex items-center gap-2 mb-2">
        <motion.div
          className="w-1.5 h-1.5 rounded-full bg-green-400"
          animate={{ opacity: [1, 0.3, 1] }}
          transition={{ repeat: Infinity, duration: 1.5 }}
        />
        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
          Live Activity
        </span>
      </div>

      <div className="space-y-0.5 overflow-hidden">
        <AnimatePresence mode="popLayout" initial={false}>
          {activities.map((item, index) => (
            <motion.div
              key={item.id}
              layout
              initial={{ opacity: 0, x: 40, height: 0 }}
              animate={{ opacity: 1, x: 0, height: 'auto' }}
              exit={{ opacity: 0, x: -20, height: 0 }}
              transition={{
                layout: { type: 'spring', stiffness: 300, damping: 30 },
                opacity: { duration: 0.25 },
                x: { type: 'spring', stiffness: 300, damping: 30 },
                height: { duration: 0.2 },
                delay: index * 0.05,
              }}
              className="flex items-center gap-2.5 py-1.5 px-2 rounded-lg"
            >
              {/* Avatar / icon */}
              {item.avatarInitial ? (
                <div
                  className={cn(
                    'w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold text-white flex-shrink-0',
                    item.avatarColor
                  )}
                >
                  {item.avatarInitial}
                </div>
              ) : (
                <div className="w-6 h-6 rounded-full bg-muted flex items-center justify-center flex-shrink-0">
                  {getActivityIcon(item.type)}
                </div>
              )}

              {/* Text */}
              <span className="text-xs text-foreground/80 flex-1 truncate">
                {item.text}
              </span>

              {/* Timestamp + type icon */}
              <div className="flex items-center gap-1.5 flex-shrink-0">
                {getActivityIcon(item.type)}
                <span className="text-[10px] text-muted-foreground font-mono">
                  {item.timestamp}
                </span>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import {
  Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription
} from '@/components/ui/sheet'
import { Button } from '@/components/ui/button'
import { Card } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import {
  ArrowRight, Clock, Users, Ticket, MusicNotes, TShirt, MapPin, Trophy, Lightning
} from '@phosphor-icons/react'
import { motion } from 'framer-motion'
import { cn } from '@/lib/utils'
import { PulseScore } from '@/components/PulseScore'
import { formatDistance } from '@/lib/units'
import { calculateDistance, getEnergyLabel } from '@/lib/pulse-engine'
import type { Venue } from '@/lib/types'
import type { VenueLiveData } from '@/lib/live-intelligence'
import { getVenueLiveData } from '@/lib/live-intelligence'

interface VenueCompareSheetProps {
  open: boolean
  onClose: () => void
  venues: Venue[]
  compareVenueIds: string[]
  userLocation: { lat: number; lng: number } | null
  unitSystem: 'imperial' | 'metric'
  onVenueClick: (venue: Venue) => void
}

interface VenueCompareData {
  venue: Venue
  liveData: VenueLiveData
  distance: number | null
}

function MetricRow({
  label,
  icon,
  values,
  bestIndex,
  formatter,
}: {
  label: string
  icon: React.ReactNode
  values: (string | null)[]
  bestIndex: number | null
  formatter?: (v: string) => string
}) {
  return (
    <div className="space-y-1.5">
      <div className="flex items-center gap-2 text-xs text-muted-foreground">
        {icon}
        <span>{label}</span>
      </div>
      <div className={cn('grid gap-2', values.length === 2 ? 'grid-cols-2' : 'grid-cols-3')}>
        {values.map((value, idx) => (
          <div
            key={idx}
            className={cn(
              'text-center py-2 px-3 rounded-lg border text-sm font-bold',
              bestIndex === idx
                ? 'border-primary/30 bg-primary/5 text-primary'
                : 'border-border bg-secondary/30'
            )}
          >
            {value ?? '--'}
            {bestIndex === idx && (
              <Trophy size={12} weight="fill" className="inline ml-1 text-yellow-500" />
            )}
          </div>
        ))}
      </div>
    </div>
  )
}

export function VenueCompareSheet({
  open,
  onClose,
  venues,
  compareVenueIds,
  userLocation,
  unitSystem,
  onVenueClick,
}: VenueCompareSheetProps) {
  const [compareData, setCompareData] = useState<VenueCompareData[]>([])

  useEffect(() => {
    if (!open || compareVenueIds.length < 2) return

    const data: VenueCompareData[] = compareVenueIds
      .map(id => venues.find(v => v.id === id))
      .filter((v): v is Venue => v !== undefined)
      .slice(0, 3)
      .map(venue => ({
        venue,
        liveData: getVenueLiveData(venue.id),
        distance: userLocation
          ? calculateDistance(userLocation.lat, userLocation.lng, venue.location.lat, venue.location.lng)
          : null,
      }))

    setCompareData(data)
  }, [open, compareVenueIds, venues, userLocation])

  if (compareData.length < 2) return null

  // Determine "which is better right now" - simple scoring
  const scores = compareData.map((d, idx) => {
    let score = 0
    score += d.venue.pulseScore * 2 // energy matters most
    score -= (d.liveData.waitTime ?? 0) * 2 // less wait is better
    score -= (d.liveData.coverCharge ?? 0) // less cover is better
    if (d.distance !== null) score -= d.distance * 10 // closer is better
    return { idx, score }
  })
  const bestOverall = scores.sort((a, b) => b.score - a.score)[0].idx

  // Find best for individual metrics
  const bestPulse = compareData.reduce<number | null>((best, d, idx) =>
    best === null || d.venue.pulseScore > compareData[best].venue.pulseScore ? idx : best, null)
  const bestWait = compareData.reduce<number | null>((best, d, idx) => {
    if (d.liveData.waitTime === null) return best
    if (best === null) return idx
    return (d.liveData.waitTime ?? Infinity) < (compareData[best].liveData.waitTime ?? Infinity) ? idx : best
  }, null)
  const bestCover = compareData.reduce<number | null>((best, d, idx) => {
    const cover = d.liveData.coverCharge
    if (best === null) return idx
    const bestCoverVal = compareData[best].liveData.coverCharge
    if (cover === null) return idx // free is best
    if (bestCoverVal === null) return best
    return cover < bestCoverVal ? idx : best
  }, null)
  const bestDistance = compareData.reduce<number | null>((best, d, idx) => {
    if (d.distance === null) return best
    if (best === null) return idx
    return (d.distance ?? Infinity) < (compareData[best].distance ?? Infinity) ? idx : best
  }, null)

  return (
    <Sheet open={open} onOpenChange={onClose}>
      <SheetContent side="bottom" className="rounded-t-3xl border-t-accent/20 bg-card max-h-[90vh] overflow-y-auto">
        <SheetHeader className="pb-2">
          <div className="mx-auto w-12 h-1.5 rounded-full bg-muted/30 mb-2" />
          <SheetTitle className="text-xl font-bold">Compare Venues</SheetTitle>
          <SheetDescription className="text-sm">Side-by-side live metrics</SheetDescription>
        </SheetHeader>

        {/* Venue Headers */}
        <div className={cn('grid gap-2 mb-4', compareData.length === 2 ? 'grid-cols-2' : 'grid-cols-3')}>
          {compareData.map((d, idx) => (
            <motion.div
              key={d.venue.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.1 }}
            >
              <Card
                className={cn(
                  'p-3 text-center cursor-pointer hover:border-primary/30 transition-colors',
                  bestOverall === idx && 'border-primary/30 bg-primary/5'
                )}
                onClick={() => { onClose(); onVenueClick(d.venue) }}
              >
                <p className="text-sm font-bold truncate">{d.venue.name}</p>
                <div className="flex items-center justify-center gap-1 mt-1">
                  <PulseScore score={d.venue.pulseScore} size="sm" showLabel={false} />
                  {bestOverall === idx && (
                    <Badge className="bg-primary/10 text-primary text-[10px]">Best pick</Badge>
                  )}
                </div>
                {d.venue.category && (
                  <p className="text-[10px] text-muted-foreground uppercase font-mono mt-1">
                    {d.venue.category}
                  </p>
                )}
              </Card>
            </motion.div>
          ))}
        </div>

        <Separator className="mb-4" />

        {/* Metrics Comparison */}
        <div className="space-y-4 pb-6">
          {/* Energy */}
          <MetricRow
            label="Energy"
            icon={<Lightning size={14} weight="fill" className="text-yellow-500" />}
            values={compareData.map(d => getEnergyLabel(d.venue.pulseScore))}
            bestIndex={bestPulse}
          />

          {/* Wait Time */}
          <MetricRow
            label="Wait Time"
            icon={<Clock size={14} weight="fill" className="text-orange-400" />}
            values={compareData.map(d =>
              d.liveData.waitTime !== null
                ? d.liveData.waitTime === 0 ? 'No wait' : `~${d.liveData.waitTime} min`
                : null
            )}
            bestIndex={bestWait}
          />

          {/* Cover */}
          <MetricRow
            label="Cover Charge"
            icon={<Ticket size={14} weight="fill" className="text-green-400" />}
            values={compareData.map(d =>
              d.liveData.coverCharge !== null
                ? `$${d.liveData.coverCharge}`
                : d.liveData.coverChargeNote || 'Free'
            )}
            bestIndex={bestCover}
          />

          {/* Crowd */}
          <MetricRow
            label="Crowd Level"
            icon={<Users size={14} weight="fill" className="text-blue-400" />}
            values={compareData.map(d =>
              d.liveData.crowdLevel > 0 ? `${d.liveData.crowdLevel}%` : null
            )}
            bestIndex={null} // crowd preference is subjective
          />

          {/* Music */}
          <MetricRow
            label="Music"
            icon={<MusicNotes size={14} weight="fill" className="text-purple-400" />}
            values={compareData.map(d =>
              d.liveData.nowPlaying
                ? `${d.liveData.nowPlaying.track}`
                : d.liveData.musicGenre || null
            )}
            bestIndex={null}
          />

          {/* Dress Code */}
          <MetricRow
            label="Dress Code"
            icon={<TShirt size={14} weight="fill" className="text-pink-400" />}
            values={compareData.map(d =>
              d.liveData.dressCode
                ? d.liveData.dressCode.replace('-', ' ').replace(/\b\w/g, c => c.toUpperCase())
                : null
            )}
            bestIndex={null}
          />

          {/* Distance */}
          {userLocation && (
            <MetricRow
              label="Distance"
              icon={<MapPin size={14} weight="fill" className="text-accent" />}
              values={compareData.map(d =>
                d.distance !== null ? formatDistance(d.distance, unitSystem) : null
              )}
              bestIndex={bestDistance}
            />
          )}
        </div>

        {/* Quick navigate buttons */}
        <div className={cn('grid gap-2 pb-4', compareData.length === 2 ? 'grid-cols-2' : 'grid-cols-3')}>
          {compareData.map(d => (
            <Button
              key={d.venue.id}
              variant="outline"
              size="sm"
              onClick={() => { onClose(); onVenueClick(d.venue) }}
            >
              <ArrowRight size={14} className="mr-1" />
              Go to {d.venue.name.split(' ')[0]}
            </Button>
          ))}
        </div>
      </SheetContent>
    </Sheet>
  )
}

import { useMemo, useId } from 'react'
import { cn } from '@/lib/utils'
import { motion } from 'framer-motion'

interface VenueEnergyTimelineProps {
  venueId: string
  currentScore: number
}

function getEnergyColor(score: number): { line: string; fill: string; glow: string } {
  if (score >= 80) return { line: '#ef4444', fill: '#ef4444', glow: 'rgba(239,68,68,0.3)' }
  if (score >= 60) return { line: '#f97316', fill: '#f97316', glow: 'rgba(249,115,22,0.3)' }
  if (score >= 40) return { line: '#eab308', fill: '#eab308', glow: 'rgba(234,179,8,0.3)' }
  if (score >= 20) return { line: '#22c55e', fill: '#22c55e', glow: 'rgba(34,197,94,0.3)' }
  return { line: '#3b82f6', fill: '#3b82f6', glow: 'rgba(59,130,246,0.3)' }
}

function generateHistoricalData(venueId: string, currentScore: number): number[] {
  // Seeded random based on venueId for consistency
  let seed = 0
  for (let i = 0; i < venueId.length; i++) {
    seed = ((seed << 5) - seed + venueId.charCodeAt(i)) | 0
  }
  const seededRandom = () => {
    seed = (seed * 16807 + 0) % 2147483647
    return (seed & 0x7fffffff) / 2147483647
  }

  const points = 12
  const data: number[] = []

  // Start low, build up to current score to simulate buildup
  const baseStart = Math.max(5, currentScore * 0.15)

  for (let i = 0; i < points; i++) {
    const progress = i / (points - 1)
    // Exponential buildup curve with random noise
    const base = baseStart + (currentScore - baseStart) * Math.pow(progress, 1.5)
    const noise = (seededRandom() - 0.5) * currentScore * 0.2
    data.push(Math.max(0, Math.min(100, Math.round(base + noise))))
  }

  // Ensure last point is exactly the current score
  data[data.length - 1] = currentScore

  return data
}

function buildSmoothPath(
  data: number[],
  width: number,
  height: number,
  padding: { top: number; bottom: number; left: number; right: number }
): string {
  const chartW = width - padding.left - padding.right
  const chartH = height - padding.top - padding.bottom
  const maxVal = 100
  const minVal = 0

  const points = data.map((val, i) => ({
    x: padding.left + (i / (data.length - 1)) * chartW,
    y: padding.top + chartH - ((val - minVal) / (maxVal - minVal)) * chartH,
  }))

  if (points.length < 2) return ''

  let d = `M ${points[0].x},${points[0].y}`

  for (let i = 0; i < points.length - 1; i++) {
    const p0 = points[Math.max(0, i - 1)]
    const p1 = points[i]
    const p2 = points[i + 1]
    const p3 = points[Math.min(points.length - 1, i + 2)]

    const tension = 0.3
    const cp1x = p1.x + (p2.x - p0.x) * tension
    const cp1y = p1.y + (p2.y - p0.y) * tension
    const cp2x = p2.x - (p3.x - p1.x) * tension
    const cp2y = p2.y - (p3.y - p1.y) * tension

    d += ` C ${cp1x},${cp1y} ${cp2x},${cp2y} ${p2.x},${p2.y}`
  }

  return d
}

export function VenueEnergyTimeline({ venueId, currentScore }: VenueEnergyTimelineProps) {
  const uniqueId = useId()
  const gradientId = `energy-gradient-${uniqueId}`
  const glowFilterId = `glow-${uniqueId}`

  const data = useMemo(() => generateHistoricalData(venueId, currentScore), [venueId, currentScore])
  const colors = getEnergyColor(currentScore)

  const width = 360
  const height = 80
  const padding = { top: 8, bottom: 20, left: 30, right: 10 }

  const linePath = useMemo(() => buildSmoothPath(data, width, height, padding), [data])

  // Build fill path (line + close at bottom)
  const fillPath = useMemo(() => {
    if (!linePath) return ''
    const chartBottom = height - padding.bottom
    const firstX = padding.left
    const lastX = width - padding.right
    return `${linePath} L ${lastX},${chartBottom} L ${firstX},${chartBottom} Z`
  }, [linePath])

  // Find peak point
  const peakIndex = useMemo(() => {
    let maxI = 0
    for (let i = 1; i < data.length; i++) {
      if (data[i] > data[maxI]) maxI = i
    }
    return maxI
  }, [data])

  const chartW = width - padding.left - padding.right
  const chartH = height - padding.top - padding.bottom

  const getX = (i: number) => padding.left + (i / (data.length - 1)) * chartW
  const getY = (val: number) => padding.top + chartH - (val / 100) * chartH

  const currentX = getX(data.length - 1)
  const currentY = getY(currentScore)
  const peakX = getX(peakIndex)
  const peakY = getY(data[peakIndex])

  // Calculate approximate path length for animation
  const pathLength = useMemo(() => {
    let len = 0
    for (let i = 1; i < data.length; i++) {
      const dx = getX(i) - getX(i - 1)
      const dy = getY(data[i]) - getY(data[i - 1])
      len += Math.sqrt(dx * dx + dy * dy)
    }
    return Math.ceil(len)
  }, [data])

  const timeLabels = [
    { label: '6h ago', x: padding.left },
    { label: '3h ago', x: padding.left + chartW / 2 },
    { label: 'Now', x: width - padding.right },
  ]

  return (
    <div className="w-full">
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="w-full"
        style={{ height: 80 }}
        preserveAspectRatio="none"
      >
        <defs>
          <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={colors.fill} stopOpacity={0.3} />
            <stop offset="100%" stopColor={colors.fill} stopOpacity={0.02} />
          </linearGradient>
          <filter id={glowFilterId}>
            <feGaussianBlur stdDeviation="2" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>
        </defs>

        {/* Fill under curve */}
        <motion.path
          d={fillPath}
          fill={`url(#${gradientId})`}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5, duration: 0.6 }}
        />

        {/* Animated line */}
        <motion.path
          d={linePath}
          fill="none"
          stroke={colors.line}
          strokeWidth={2.5}
          strokeLinecap="round"
          strokeLinejoin="round"
          filter={`url(#${glowFilterId})`}
          initial={{ strokeDasharray: pathLength, strokeDashoffset: pathLength }}
          animate={{ strokeDashoffset: 0 }}
          transition={{ duration: 1.2, ease: 'easeOut' }}
        />

        {/* Peak label */}
        {peakIndex !== data.length - 1 && (
          <motion.g
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1.0, duration: 0.4 }}
          >
            <text
              x={peakX}
              y={peakY - 8}
              textAnchor="middle"
              fill={colors.line}
              fontSize={8}
              fontWeight="600"
              fontFamily="monospace"
            >
              Peak
            </text>
            <circle cx={peakX} cy={peakY} r={2.5} fill={colors.line} opacity={0.7} />
          </motion.g>
        )}

        {/* Current point - pulsing */}
        <motion.circle
          cx={currentX}
          cy={currentY}
          r={4}
          fill={colors.line}
          initial={{ opacity: 0, scale: 0 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 1.2, type: 'spring', stiffness: 200 }}
        />
        <motion.circle
          cx={currentX}
          cy={currentY}
          r={4}
          fill="none"
          stroke={colors.line}
          strokeWidth={1.5}
          initial={{ opacity: 0 }}
          animate={{
            opacity: [0.6, 0, 0.6],
            r: [4, 10, 4],
          }}
          transition={{
            delay: 1.4,
            repeat: Infinity,
            duration: 2,
            ease: 'easeInOut',
          }}
        />

        {/* Time labels */}
        {timeLabels.map(({ label, x }) => (
          <text
            key={label}
            x={x}
            y={height - 4}
            textAnchor={label === 'Now' ? 'end' : label === '6h ago' ? 'start' : 'middle'}
            fill="currentColor"
            className="text-muted-foreground"
            fontSize={8}
            fontFamily="monospace"
            opacity={0.5}
          >
            {label}
          </text>
        ))}
      </svg>
    </div>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { Venue } from '@/lib/types'
import { cn } from '@/lib/utils'
import { ArrowLeft } from '@phosphor-icons/react'
import { motion, useMotionValue, useTransform, animate, AnimatePresence } from 'framer-motion'

interface VenueHeroCarouselProps {
  venue: Venue
  pulseScore: number
  onBack: () => void
}

function getCategoryGradients(category?: string): string[] {
  const cat = (category || '').toLowerCase()

  if (cat.includes('bar') || cat.includes('pub') || cat.includes('lounge')) {
    return [
      'linear-gradient(135deg, #b44d12 0%, #dc6b20 30%, #f59e0b 60%, #92400e 100%)',
      'linear-gradient(135deg, #dc6b20 0%, #f97316 30%, #fbbf24 60%, #b45309 100%)',
      'linear-gradient(135deg, #92400e 0%, #b44d12 30%, #dc6b20 60%, #f59e0b 100%)',
      'linear-gradient(135deg, #f59e0b 0%, #dc6b20 40%, #92400e 80%, #b44d12 100%)',
    ]
  }

  if (cat.includes('club') || cat.includes('nightclub') || cat.includes('dance')) {
    return [
      'linear-gradient(135deg, #7c3aed 0%, #a855f7 30%, #ec4899 60%, #6366f1 100%)',
      'linear-gradient(135deg, #ec4899 0%, #f43f5e 30%, #a855f7 60%, #7c3aed 100%)',
      'linear-gradient(135deg, #6366f1 0%, #8b5cf6 30%, #d946ef 60%, #ec4899 100%)',
      'linear-gradient(135deg, #d946ef 0%, #a855f7 40%, #6366f1 80%, #ec4899 100%)',
    ]
  }

  if (cat.includes('restaurant') || cat.includes('dining') || cat.includes('bistro')) {
    return [
      'linear-gradient(135deg, #78350f 0%, #a16207 30%, #65a30d 60%, #4d7c0f 100%)',
      'linear-gradient(135deg, #a16207 0%, #ca8a04 30%, #84cc16 60%, #65a30d 100%)',
      'linear-gradient(135deg, #4d7c0f 0%, #65a30d 30%, #a16207 60%, #78350f 100%)',
      'linear-gradient(135deg, #65a30d 0%, #a16207 40%, #78350f 80%, #ca8a04 100%)',
    ]
  }

  if (cat.includes('cafe') || cat.includes('coffee')) {
    return [
      'linear-gradient(135deg, #78350f 0%, #92400e 30%, #d4a574 60%, #a16207 100%)',
      'linear-gradient(135deg, #92400e 0%, #b45309 30%, #e8c9a0 60%, #78350f 100%)',
      'linear-gradient(135deg, #a16207 0%, #d4a574 30%, #92400e 60%, #78350f 100%)',
    ]
  }

  // Default / generic
  return [
    'linear-gradient(135deg, #1e3a5f 0%, #3b82f6 30%, #6366f1 60%, #1e40af 100%)',
    'linear-gradient(135deg, #3b82f6 0%, #6366f1 30%, #8b5cf6 60%, #1e3a5f 100%)',
    'linear-gradient(135deg, #1e40af 0%, #3b82f6 30%, #60a5fa 60%, #6366f1 100%)',
    'linear-gradient(135deg, #6366f1 0%, #3b82f6 40%, #1e3a5f 80%, #1e40af 100%)',
  ]
}

function getScoreColor(score: number): string {
  if (score >= 80) return 'text-red-400'
  if (score >= 60) return 'text-orange-400'
  if (score >= 40) return 'text-yellow-400'
  if (score >= 20) return 'text-green-400'
  return 'text-blue-400'
}

function getScoreLabel(score: number): string {
  if (score >= 80) return 'Electric'
  if (score >= 60) return 'Buzzing'
  if (score >= 40) return 'Lively'
  if (score >= 20) return 'Chill'
  return 'Quiet'
}

export function VenueHeroCarousel({ venue, pulseScore, onBack }: VenueHeroCarouselProps) {
  const gradients = getCategoryGradients(venue.category)
  const [currentIndex, setCurrentIndex] = useState(0)
  const [isTouching, setIsTouching] = useState(false)
  const autoPlayRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const containerRef = useRef<HTMLDivElement>(null)

  const dragX = useMotionValue(0)
  const parallaxX = useTransform(dragX, [-300, 0, 300], [30, 0, -30])

  const startAutoPlay = useCallback(() => {
    if (autoPlayRef.current) clearInterval(autoPlayRef.current)
    autoPlayRef.current = setInterval(() => {
      if (!isTouching) {
        setCurrentIndex((prev) => (prev + 1) % gradients.length)
      }
    }, 5000)
  }, [isTouching, gradients.length])

  useEffect(() => {
    startAutoPlay()
    return () => {
      if (autoPlayRef.current) clearInterval(autoPlayRef.current)
    }
  }, [startAutoPlay])

  const handleDragEnd = (_: unknown, info: { offset: { x: number }; velocity: { x: number } }) => {
    const threshold = 50
    const velocity = info.velocity.x

    if (info.offset.x < -threshold || velocity < -500) {
      setCurrentIndex((prev) => Math.min(prev + 1, gradients.length - 1))
    } else if (info.offset.x > threshold || velocity > 500) {
      setCurrentIndex((prev) => Math.max(prev - 1, 0))
    }
    startAutoPlay()
  }

  return (
    <div
      ref={containerRef}
      className="relative h-[320px] overflow-hidden rounded-b-3xl"
    >
      {/* Parallax background layer */}
      <motion.div
        className="absolute inset-0 scale-110"
        style={{ x: parallaxX }}
      >
        <AnimatePresence mode="popLayout">
          <motion.div
            key={currentIndex}
            className="absolute inset-0"
            style={{ background: gradients[currentIndex] }}
            initial={{ opacity: 0, scale: 1.1 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            transition={{ duration: 0.5, ease: 'easeInOut' }}
          />
        </AnimatePresence>
      </motion.div>

      {/* Decorative elements for visual interest */}
      <motion.div
        className="absolute inset-0 pointer-events-none"
        style={{ x: parallaxX }}
      >
        <div className="absolute top-8 right-8 w-32 h-32 rounded-full bg-white/5 blur-xl" />
        <div className="absolute bottom-16 left-12 w-24 h-24 rounded-full bg-white/8 blur-lg" />
        <div className="absolute top-20 left-1/3 w-16 h-16 rounded-full bg-white/5 blur-md" />
      </motion.div>

      {/* Swipe gesture layer */}
      <motion.div
        className="absolute inset-0 z-10 cursor-grab active:cursor-grabbing"
        drag="x"
        dragConstraints={{ left: 0, right: 0 }}
        dragElastic={0.2}
        onDragStart={() => setIsTouching(true)}
        onDragEnd={(e, info) => {
          setIsTouching(false)
          handleDragEnd(e, info)
        }}
        onTouchStart={() => {
          setIsTouching(true)
          if (autoPlayRef.current) clearInterval(autoPlayRef.current)
        }}
        onTouchEnd={() => {
          setIsTouching(false)
          startAutoPlay()
        }}
        style={{ x: dragX }}
      />

      {/* Gradient overlay for text readability */}
      <div className="absolute inset-0 z-20 pointer-events-none bg-gradient-to-t from-background via-background/40 to-transparent" />

      {/* Back button */}
      <button
        onClick={onBack}
        className="absolute top-4 left-4 z-30 p-2.5 rounded-full bg-black/20 backdrop-blur-md border border-white/10 hover:bg-black/30 transition-colors"
      >
        <ArrowLeft size={22} weight="bold" className="text-white" />
      </button>

      {/* Content overlay */}
      <div className="absolute bottom-0 left-0 right-0 z-20 p-5 pointer-events-none">
        {/* Pulse score badge */}
        <motion.div
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.2, type: 'spring', stiffness: 200 }}
          className="mb-3"
        >
          <div className={cn(
            'inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-black/30 backdrop-blur-sm border border-white/10',
            getScoreColor(pulseScore)
          )}>
            <motion.div
              className="w-2 h-2 rounded-full bg-current"
              animate={{ scale: [1, 1.3, 1] }}
              transition={{ repeat: Infinity, duration: 2 }}
            />
            <span className="text-sm font-bold">{pulseScore}</span>
            <span className="text-xs opacity-80">{getScoreLabel(pulseScore)}</span>
          </div>
        </motion.div>

        {/* Venue name */}
        <motion.h1
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1, duration: 0.4 }}
          className="text-3xl font-bold text-white mb-1.5 drop-shadow-lg"
        >
          {venue.name}
        </motion.h1>

        {/* Category badge */}
        {venue.category && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.15, duration: 0.4 }}
          >
            <span className="inline-block px-2.5 py-1 rounded-md bg-white/15 backdrop-blur-sm text-xs font-mono uppercase tracking-wider text-white/90">
              {venue.category}
            </span>
          </motion.div>
        )}

        {/* Dot indicators */}
        <div className="flex items-center gap-2 mt-4">
          {gradients.map((_, index) => (
            <button
              key={index}
              className="pointer-events-auto relative"
              onClick={() => {
                setCurrentIndex(index)
                startAutoPlay()
              }}
            >
              <div
                className={cn(
                  'h-1.5 rounded-full transition-all duration-300',
                  index === currentIndex
                    ? 'w-6 bg-white'
                    : 'w-1.5 bg-white/40'
                )}
              />
              {index === currentIndex && (
                <motion.div
                  layoutId="activeDot"
                  className="absolute inset-0 h-1.5 w-6 rounded-full bg-white"
                  transition={{ type: 'spring', stiffness: 300, damping: 30 }}
                />
              )}
            </button>
          ))}
        </div>
      </div>
    </div>
  )
}

