      'promoted_listing',
      100,
      now.toISOString(),
      new Date(now.getTime() + 14 * 86400000).toISOString()
    )
    setCampaigns(prev => [campaign, ...prev])
    toast.success('Campaign created')
  }

  const handleGenerateSocialPost = (type: 'highlight' | 'event' | 'milestone') => {
